# Sprint 6E: Thread-safe bounded queue for target queue (rule 19-22)
# Non-blocking FIFO with bounded maxsize and drop counting
import collections
import threading


class ThreadSafeBoundedQueue:
    __slots__ = ("_deque", "_lock", "maxsize", "_enqueued_total", "_drop_count")

    def __init__(self, maxsize: int = 10000):
        self.maxsize = maxsize
        self._deque = collections.deque(maxlen=maxsize)
        self._lock = threading.Lock()
        self._enqueued_total = 0
        self._drop_count = 0

    def put(self, item) -> bool:
        with self._lock:
            was_full = len(self._deque) >= self.maxsize
            if was_full:
                self._drop_count += 1
            self._deque.append(item)
            self._enqueued_total += 1
            return not was_full

    def get(self):
        with self._lock:
            return self._deque.popleft() if self._deque else None

    def __len__(self):
        with self._lock:
            return len(self._deque)

    @property
    def drop_count(self) -> int:
        with self._lock:
            return self._drop_count


# Sprint 7A: TokenBucket for async-native rate limiting
class TokenBucket:
    """Async-native token bucket using asyncio.Lock + asyncio.sleep (never blocks event loop)."""
    __slots__ = ("_tokens", "_last_refill", "_rate", "_burst", "_lock")

    def __init__(self, rate: float = 1.0, burst: float = 3.0):
        self._tokens = burst
        self._last_refill = time.monotonic()
        self._rate = rate  # tokens per second
        self._burst = burst
        self._lock: Optional[asyncio.Lock] = None

    def _ensure_lock(self):
        if self._lock is None:
            self._lock = asyncio.Lock()

    async def acquire(self, tokens: float = 1.0) -> bool:
        """Acquire tokens, waiting if necessary. Never blocks event loop."""
        self._ensure_lock()
        async with self._lock:
            self._refill()
            if self._tokens >= tokens:
                self._tokens -= tokens
                return True
            # Calculate wait time
            needed = tokens - self._tokens
            wait_time = needed / self._rate
            await asyncio.sleep(wait_time)
            self._refill()
            if self._tokens >= tokens:
                self._tokens -= tokens
                return True
            return False

    def _refill(self):
        now = time.monotonic()
        elapsed = now - self._last_refill
        self._tokens = min(self._burst, self._tokens + elapsed * self._rate)
        self._last_refill = now

    async def try_acquire(self, tokens: float = 1.0) -> bool:
        """Try to acquire tokens without waiting."""
        self._ensure_lock()
        async with self._lock:
            self._refill()
            if self._tokens >= tokens:
                self._tokens -= tokens
                return True
            return False


# Sprint 6E: Welford stats for running mean/stddev + percentile
from collections import deque


class WelfordStats:
    __slots__ = ("n", "_mean", "_M2", "_window")

    def __init__(self, window: int = 1000):
        self.n = 0
        self._mean = 0.0
        self._M2 = 0.0
        self._window = deque(maxlen=window)

    def update(self, x: float) -> None:
        self.n += 1
        d = x - self._mean
        self._mean += d / self.n
        self._M2 += d * (x - self._mean)
        self._window.append(x)

    @property
    def mean(self) -> float:
        return self._mean

    @property
    def stddev(self) -> float:
        return (self._M2 / max(1, self.n - 1)) ** 0.5

    def percentile(self, p: float) -> float:
        if len(self._window) < 10:
            return float("nan")
        s = sorted(self._window)
        return s[int(len(s) * p)]


# Sprint 5M: Reservoir sampler for latency percentiles
class ReservoirSampler:
    """Bounded reservoir sampler for latency percentiles without Welford approximation."""
    __slots__ = ("_k", "_reservoir", "_n")

    def __init__(self, k: int = 128):
        self._k = k
        self._reservoir: List[float] = []
        self._n = 0

    def update(self, x: float) -> None:
        self._n += 1
        if len(self._reservoir) < self._k:
            self._reservoir.append(x)
        else:
            import random
            j = random.randint(0, self._n - 1)
            if j < self._k:
                self._reservoir[j] = x

    def percentile(self, p: float) -> float:
        if not self._reservoir:
            return 0.0
        s = sorted(self._reservoir)
        idx = min(int((p / 100.0) * len(s)), len(s) - 1)
        return s[idx]

    def clear(self) -> None:
        self._reservoir = []
        self._n = 0


# Sprint 5M: Safe wrapper for shard packet loading with asyncio.to_thread
async def _load_shard_packet_safe(packet_file: "Path") -> Tuple[Optional[Dict], Optional[str], float]:
    """Safe wrapper for shard packet loading. Returns (data, error, latency_ms)."""
    start = time.perf_counter()
    try:
        def _sync_load():
            with open(packet_file, 'r') as f:
                return json.load(f)
        data = await asyncio.to_thread(_sync_load)
        latency_ms = (time.perf_counter() - start) * 1000
        return data, None, latency_ms
    except FileNotFoundError as e:
        latency_ms = (time.perf_counter() - start) * 1000
        return None, f"FileNotFound: {packet_file}", latency_ms
    except Exception as e:
        latency_ms = (time.perf_counter() - start) * 1000
        return None, f"{type(e).__name__}: {e}", latency_ms

