# Sprint 82Q Phase 6: Exception-to-ActionResultType mapping
# =============================================================================
# Maps exceptions to typed result states for truthful benchmark classification

# HTTP status codes that indicate upstream API errors
_UPSTREAM_API_ERROR_CODES = {429, 403, 451, 502, 503, 504, 529}


def _map_exception_to_result_type(
    exception: Optional[Exception],
    http_status: Optional[int] = None,
    is_mock_derived: bool = False,
) -> str:
    """
    Map exception/HTTP status to typed ActionResultType.

    This enables truthful benchmark classification:
    - NETWORK_UNAVAILABLE: network unreachable, DNS, connection refused
    - UPSTREAM_API_ERROR: HTTP 429/403/451/502/503/504/529
    - TIMEOUT: action timed out
    - EXCEPTION: unhandled exception (possibly code bug)
    - MOCK_FALLBACK_USED: fixture/mock data was used
    - SUCCESS: action completed with valid results
    - EMPTY: action completed but no results
    """
    # Mock/fixture derived takes precedence
    if is_mock_derived:
        return "MOCK_FALLBACK_USED"

    # HTTP status takes precedence over exception
    if http_status is not None:
        if http_status in _UPSTREAM_API_ERROR_CODES:
            return "UPSTREAM_API_ERROR"
        # Other HTTP errors might be client errors (4xx except 429/403/451)
        if 400 <= http_status < 500 and http_status not in {429, 403, 451}:
            return "EXCEPTION"  # Client errors are code bugs
        if http_status >= 500:
            return "UPSTREAM_API_ERROR"

    if exception is None:
        return "EMPTY"

    # Exception type mapping
    exc_type = type(exception).__name__
    exc_msg = str(exception).lower()

    # Network unavailable: socket.gaierror, ConnectionRefusedError, ConnectionResetError
    if isinstance(exception, socket.gaierror):
        return "NETWORK_UNAVAILABLE"
    if isinstance(exception, ConnectionRefusedError):
        return "NETWORK_UNAVAILABLE"
    if isinstance(exception, ConnectionResetError):
        return "NETWORK_UNAVAILABLE"

    # Timeout: asyncio.TimeoutError, asyncio.CancelledError (if timeout related)
    if isinstance(exception, asyncio.TimeoutError):
        return "TIMEOUT"
    if "timeout" in exc_msg or "timed out" in exc_msg:
        return "TIMEOUT"

    # OfflineModeError is explicit offline mode
    from .types import OfflineModeError
    if isinstance(exception, OfflineModeError):
        return "NETWORK_UNAVAILABLE"

    # aiohttp client errors
    if "clientconnectorerror" in exc_type.lower() or "connectorerror" in exc_type.lower():
        return "NETWORK_UNAVAILABLE"

    # Default to EXCEPTION (could be code bug)
    return "EXCEPTION"

