def _l1_prefetch_echo(url: str, title_snippet: str, seen_hashes: set[int]) -> bool:
    """
    Sprint 82E: Levná L1 pre-fetch echo suppression pomocí xxhash.

    Používá xxhash (ne SimHash) pro rychlou detekci přesných duplikátů.
    SimHash/content near-dup patří do post-fetch content dedup, ne sem.
    """
    if not XXHASH_AVAILABLE:
        # Fallback: return False (no echo detected)
        return False

    # Create fingerprint from URL + short title/snippet
    key = url.encode() + b"\x00" + title_snippet[:80].encode()
    h = xxhash.xxh64_intdigest(key)

    if h in seen_hashes:
        return True  # Echo detected

    # Add to seen hashes (bounded)
    if len(seen_hashes) < _SEEN_HASHES_MAX:
        seen_hashes.add(h)
    return False


