# Sprint 72: Dynamic Metal limit with sysctl fallback
def _get_dynamic_metal_limit() -> int:
    """Získej doporučený Metal limit od OS (macOS 15+)."""
    try:
        import ctypes
        rec_bytes = ctypes.c_size_t()
        size = ctypes.c_size_t()
        ret = ctypes.cdll.LoadLibrary(None).sysctlbyname(
            b"kern.memorystatus_metal_recommended_memory",
            ctypes.byref(rec_bytes),
            ctypes.byref(size),
            None, 0
        )
        if ret == 0:
            return min(rec_bytes.value, 5 * 1024**3)
    except Exception:
        pass

    # Fallback pro starší macOS nebo selhání sysctl
    try:
        import psutil
        total = psutil.virtual_memory().total
        return min(int(total * 0.6), 5 * 1024**3)  # 60% RAM, max 5GB
    except Exception:
        return 4 * 1024**3  # safe default

# Sprint 62/71: MLX memory limit (best-effort), prefer mx.set_* over mx.metal.set_*
if sys.platform == "darwin":
    try:
        import mlx.core as mx  # lokální import – OK
        metal_limit = _get_dynamic_metal_limit()

        # Verze API – zkusit moderní, pak metal, jinak přeskočit
        if hasattr(mx, 'set_memory_limit'):
            mx.set_memory_limit(metal_limit)
        elif hasattr(mx.metal, 'set_memory_limit'):
            mx.metal.set_memory_limit(metal_limit)

        logger.info(f"[Metal] Heap capped at {metal_limit/1024**3:.1f}GB")

        # Cache limit pro kompilované funkce (ne KV cache)
        if hasattr(mx, 'set_cache_limit'):
            mx.set_cache_limit(512 * 1024 * 1024)
        elif hasattr(mx.metal, 'set_cache_limit'):
            mx.metal.set_cache_limit(512 * 1024 * 1024)

        logger.debug("[Metal] Cache limit 512MB")
    except Exception as e:
        logger.warning(f"[Metal] Failed to set limits: {e}")


# =============================================================================
# BUDGET MANAGER - Runtime budget enforcement
# =============================================================================

class BudgetManager:
    """Runtime budget manager for autonomous execution.

    Tracks and enforces budget limits for:
    - RAM usage
    - Execution time
    - Network calls
    - Snapshot writes

    Implements fallback strategies when budgets are exceeded.
    """

    def __init__(
        self,
        max_ram_mb: int = 2048,
        max_time_s: int = 300,
        max_network_calls: int = 50,
        max_snapshot_writes: int = 20
    ):
        self.max_ram_mb = max_ram_mb
        self.max_time_s = max_time_s
        self.max_network_calls = max_network_calls
        self.max_snapshot_writes = max_snapshot_writes

        # Current usage
        self._used_ram_mb = 0
        self._used_time_s = 0.0
        self._network_calls = 0
        self._snapshot_writes = 0

        # Start time
        self._start_time = time.time()

        # Stagnation tracking
        self._consecutive_novelty_failures = 0

    def reset(self) -> None:
        """Reset all budget counters."""
        self._used_ram_mb = 0
        self._used_time_s = 0.0
        self._network_calls = 0
        self._snapshot_writes = 0
        self._start_time = time.time()
        self._consecutive_novelty_failures = 0

    def check_network_allowed(self) -> Tuple[bool, str]:
        """Check if network call is allowed, with fallback reason."""
        if self._network_calls >= self.max_network_calls:
            return False, f"network_budget_exceeded({self._network_calls}/{self.max_network_calls})"
        return True, ""

    def check_snapshot_allowed(self) -> Tuple[bool, str]:
        """Check if snapshot write is allowed."""
        if self._snapshot_writes >= self.max_snapshot_writes:
            return False, f"snapshot_budget_exceeded({self._snapshot_writes}/{self.max_snapshot_writes})"
        return True, ""

    def check_ram_allowed(self, needed_mb: int) -> Tuple[bool, str]:
        """Check if RAM allocation is allowed."""
        if self._used_ram_mb + needed_mb > self.max_ram_mb:
            return False, f"ram_budget_exceeded({self._used_ram_mb + needed_mb}/{self.max_ram_mb})"
        return True, ""

    def check_time_allowed(self) -> Tuple[bool, str]:
        """Check if time budget allows continuation."""
        elapsed = time.time() - self._start_time
        if elapsed >= self.max_time_s:
            return False, f"time_budget_exceeded({elapsed:.0f}s/{self.max_time_s}s)"
        return True, ""

    def record_network_call(self) -> None:
        """Record a network call."""
        self._network_calls += 1

    def record_snapshot_write(self) -> None:
        """Record a snapshot write."""
        self._snapshot_writes += 1

    def record_ram_usage(self, mb: int) -> None:
        """Record RAM usage."""
        self._used_ram_mb += mb

    def record_novelty_failure(self) -> None:
        """Record a novelty stagnation event."""
        self._consecutive_novelty_failures += 1

    def should_force_synthesis(self, min_failures: int = 3) -> bool:
        """Check if should force synthesis due to stagnation + low budget."""
        elapsed = time.time() - self._start_time
        time_remaining = self.max_time_s - elapsed

        # Force synthesis if: stagnation + low time remaining
        if self._consecutive_novelty_failures >= min_failures:
            if time_remaining < 30:  # Less than 30s left
                return True
        return False

    def get_fallback_action(self, requested_action: str) -> str:
        """Get fallback action when budget exceeded."""
        fallback_map = {
            'api_fetch': 'skip',
            'full_snapshot': 'preview_only',
            'deep_probe': 'limited_seeds',
            'investigation': 'skip',
            'ner_extraction': 'strict_mode',
            'online_fetch': 'offline_replay'
        }
        return fallback_map.get(requested_action, 'skip')

    def get_status(self) -> Dict[str, Any]:
        """Get current budget status."""
        elapsed = time.time() - self._start_time
        return {
            'ram_mb': f"{self._used_ram_mb}/{self.max_ram_mb}",
            'time_s': f"{elapsed:.0f}/{self.max_time_s}",
            'network_calls': f"{self._network_calls}/{self.max_network_calls}",
            'snapshot_writes': f"{self._snapshot_writes}/{self.max_snapshot_writes}",
            'stagnation_count': self._consecutive_novelty_failures
        }


