_TRACKING_PARAMS = {
    'utm_source', 'utm_medium', 'utm_campaign', 'utm_term', 'utm_content',
    'utm_id', 'utm_source_platform', 'utm_creative_format', 'utm_marketing_tactic',
    'gclid', 'gclsrc', 'dclid', 'wbraid', 'gbraid', 'gad_source',
    'fbclid', 'fb_source', 'fb_action_ids', 'fb_action_types',
    'mc_cid', 'mc_eid', 'mc_tid', 'mc_mid', 'mc_suid',
    'ref', 'source', 'referrer', 'referer', 'via',
    'pk_campaign', 'pk_kwd', 'pk_keyword', 'pk_source', 'pk_medium',
    'piwik_campaign', 'piwik_kwd', 'mtm_campaign', 'mtm_keyword', 'mtm_source', 'mtm_medium',
    'ttclid', 'twclid', 'li_fat_id', 'igshid',
    'zanpid', 'kochava_click_id', 'appsflyer_id', 'adjust_tracking_id',
    'mkt_tok', 'elqTrackId', 'hsCtaTracking', 'irclickid',
    'yclid', 'ysclid', 's_kwcid', 'wickedid', 'cjevent', 'ranMID', 'ranEAID', 'ranSiteID',
    'cvid', 'msclkid', 'epik', 'srsltid', 'si', 'trk_contact', 'trk_msg', 'trk_module', 'trk_sid'
}


def normalize_url(url: str) -> str:
    """
    Normalize URL for deduplication.

    Rules:
    - Lowercase hostname
    - Remove fragment (#...)
    - Remove common tracking query parameters
    - Stable ordering of query params (sorted)
    - Normalize trailing slash
    - Safely handle None/invalid URL (return original)

    Args:
        url: URL to normalize

    Returns:
        Normalized URL string
    """
    if not url or not isinstance(url, str):
        return url or ""

    try:
        # Parse URL
        parsed = urlparse(url)

        # Lowercase hostname
        netloc = parsed.netloc.lower()

        # Remove www. prefix for consistency (optional but helps dedup)
        if netloc.startswith('www.'):
            netloc = netloc[4:]

        # Normalize path (remove trailing slash except for root)
        path = parsed.path
        if path and path != '/' and path.endswith('/'):
            path = path[:-1]

        # Parse and clean query parameters
        query_params = parse_qs(parsed.query, keep_blank_values=False)

        # Remove tracking parameters
        clean_params = {
            k: v for k, v in query_params.items()
            if k.lower() not in _TRACKING_PARAMS
        }

        # Sort parameters for stable ordering
        sorted_params = sorted(clean_params.items())

        # Rebuild query string
        query = urlencode(sorted_params, doseq=True) if sorted_params else ""

        # Rebuild URL without fragment
        normalized = urlunparse((
            parsed.scheme.lower(),
            netloc,
            path,
            parsed.params,
            query,
            ''  # Remove fragment
        ))

        return normalized

    except Exception:
        # On any error, return original URL
        return url


