# INTERNAL COORDINATOR CLASSES - Forward declarations
# =============================================================================

# These will be defined after FullyAutonomousOrchestrator
# to avoid forward reference issues


# =============================================================================
# MAIN AUTONOMOUS ORCHESTRATOR - FACADE
# =============================================================================

class FullyAutonomousOrchestrator:
    """
    Plně autonomní orchestrátor v6.1 - REFACTORED WITH INTERNAL COORDINATORS

    Tato třída je fasáda která deleguje všechny operace na interní koordinátory:
    - _state_mgr: _StateManager - state machine
    - _tool_mgr: _ToolRegistryManager - tool registry
    - _research_mgr: _ResearchManager - research execution
    - _synthesis_mgr: _SynthesisManager - report synthesis
    - _memory_mgr: _MemoryManager - memory/cache
    - _security_mgr: _SecurityManager - security/privacy
    - _brain_mgr: _BrainManager - AI brains

    Použití:
        >>> orchestrator = FullyAutonomousOrchestrator()
        >>> await orchestrator.initialize()
        >>> result = await orchestrator.research(
        ...     query="quantum cryptography breakthroughs 2024",
        ...     depth=DiscoveryDepth.EXHAUSTIVE
        ... )
    """

    def __init__(self, config: Optional[UniversalConfig] = None):
        self.config = config or UniversalConfig.for_mode(ResearchMode.AUTONOMOUS)

        # Sprint 72: Thermal monitoring state - initialize early
        self._bg_tasks: set = set()
        self._thermal_monitor_started = False

        # Sprint 1A: Lifecycle manager (fail-open, no heavy imports on boot path)
        self._lifecycle: SprintLifecycleManager = SprintLifecycleManager.get_instance()
        self._lifecycle_windup_active: bool = False  # Wind-up signal flag
