    def _is_js_gated(self, preview: str) -> bool:
        """Synchronní kontrola, zda stránka vyžaduje JS rendering."""
        if not preview:
            return False
        try:
            from hledac.universal.tools.content_miner import is_js_gated_page
            return is_js_gated_page(preview)
        except Exception:
            return False

    def _current_url(self) -> str:
        """Vrátí poslední zpracovanou URL."""
        return self._last_url

    def _pick_url_for_archive(self) -> Optional[str]:
        """Vybere URL z sources heap pro archivaci."""
        if not hasattr(self, '_sources_heap') or not self._sources_heap:
            return None
        try:
            import heapq
            top_entries = heapq.nsmallest(10, self._sources_heap)
            for entry in top_entries:
                if len(entry) >= 3:
                    src = entry[2]
                    url = getattr(src, 'url', None)
                    if url:
                        return url
        except Exception:
            pass
        return None

    def _compute_novelty_score(self) -> float:
        """Vypočítá novelty score jako poměr nových findings."""
        # Sprint 82Q FIX: Read from _research_mgr._findings_heap, not self._findings_heap
        findings_heap = []
        if hasattr(self, '_research_mgr') and self._research_mgr:
            findings_heap = getattr(self._research_mgr, '_findings_heap', [])
        total = len(findings_heap)
        if total == 0:
            return 0.0
        return self._last_iteration_new_findings / total

    # =============================================================================
    # Sprint 82Q Phase 2: Iteration Trace Methods
    # =============================================================================

    def _flush_iteration_trace(self) -> None:
        """
        Flush trace buffer to disk (off-hot-path).
        Called at research completion or periodically.
        """
        if not self._iteration_trace_buffer:
            return

        try:
            # Get output directory
            output_dir = Path.home() / '.hledac' / 'traces'
            output_dir.mkdir(parents=True, exist_ok=True)

            # Create snapshot (atomically swap buffer)
            snapshot = list(self._iteration_trace_buffer)
            self._iteration_trace_buffer.clear()

            if not snapshot:
                return

            # Write as JSONL
            timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")
            trace_file = output_dir / f"trace_{self._run_id}_{timestamp}.jsonl"

            # Use msgspec or fallback to json
            if MSGSPEC_AVAILABLE:
                for entry in snapshot:
                    line = msgspec.json.encode(entry)
                    trace_file.write_bytes(line + b'\n')
            else:
                with open(trace_file, 'w') as f:
                    for entry in snapshot:
                        f.write(json.dumps(entry) + '\n')

            logger.info(f"[TRACE] Flushed {len(snapshot)} entries to {trace_file}")

        except Exception as e:
            logger.warning(f"[TRACE] Flush failed: {e}")

    def _register_trace_atexit(self) -> None:
        """Register atexit handler for crash-safe trace flush."""
        try:
            atexit.register(self._flush_iteration_trace)
        except Exception:
            pass  # Best-effort

    def _capture_iteration_trace(
        self,
        iteration: int,
        state: 'WorkflowState',
        chosen_action: str,
        chosen_score: float,
        all_scores: Dict[str, float],
        zero_score_reasons: Dict[str, str],
        action_result_type: str,
        new_findings: int,
        new_sources: int,
        new_candidates: int,
        new_families: int,
        action_duration_ms: float,
        action_timeout: bool,
    ) -> IterationTrace:
        """
        Capture per-iteration trace data.

        Returns the IterationTrace object (also appends to buffer).
        """
        # Compute query hash
        query_hash = hashlib.md5(state.query.encode()).hexdigest()[:8]
        query_changed = query_hash != self._iteration_trace_last_query_hash

        # Compute consecutive tracking
        if chosen_action == self._iteration_trace_last_action:
            self._iteration_trace_consecutive_same_action += 1
        else:
            self._iteration_trace_consecutive_same_action = 0

        if action_result_type in ("EMPTY_RESULT", "ALL_ECHO_BLOCKED"):
            self._iteration_trace_consecutive_empty_actions += 1
        else:
            self._iteration_trace_consecutive_empty_actions = 0

        # Compute cumulative
        cumulative_findings = self._iteration_trace_last_cumulative_findings + new_findings
        cumulative_sources = self._iteration_trace_last_cumulative_sources + new_sources

        # Get RSS
        rss_bytes = 0
        try:
            import psutil
            rss_bytes = psutil.Process().memory_info().rss
        except Exception:
            pass

        # Get thermal level
        thermal_level = 0
        if hasattr(self, '_memory_mgr') and self._memory_mgr:
            try:
                thermal = self._memory_mgr.get_thermal_state()
                thermal_level = thermal.value if hasattr(thermal, 'value') else 0
            except Exception:
                pass

        # Get phase
        phase = "DISCOVERY"
        if hasattr(self, '_phase_controller'):
            try:
                phase = self._phase_controller.current_phase.name
            except Exception:
                pass

        # Get novelty
        recent_novelty = self._compute_novelty_score()

        # Get backlog and frontier size
        backlog_size = len(getattr(self, '_hold_backlog', []) or [])
        frontier_size = 0
        if hasattr(self, '_fetch_coordinator') and self._fetch_coordinator:
            try:
                frontier_size = len(getattr(self._fetch_coordinator, '_frontier', []) or [])
            except Exception:
                pass

        # Create trace entry
        trace = IterationTrace(
            iteration=iteration,
            query_hash=query_hash,
            query_changed=query_changed,
            chosen_action=chosen_action,
            chosen_score=chosen_score,
            all_scores=all_scores,
            zero_score_reason_code_by_action=zero_score_reasons,
            action_result_type=action_result_type,
            new_findings=new_findings,
            new_sources=new_sources,
            new_candidates=new_candidates,
            new_families=new_families,
            stagnation=self._stagnation_counter > 3 if hasattr(self, '_stagnation_counter') else False,
            recent_novelty=recent_novelty,
            phase=phase,
            iteration_start_ts=time.time() - (action_duration_ms / 1000.0),
            iteration_end_ts=time.time(),
            iteration_duration_ms=action_duration_ms,
            action_timeout=action_timeout,
            action_duration_ms=action_duration_ms,
            rss_bytes=rss_bytes,
            metal_peak_since_last_mb=0.0,  # Would need Metal API integration
            metal_cumulative_peak_mb=0.0,
            total_uma_mb=rss_bytes / (1024 * 1024),
            thermal_level=thermal_level,
            l1_echo_rejects_delta=self._l1_echo_rejects_count,
            l1_echo_admits_delta=self._l1_echo_admits_count,
            echo_reject_reason_code="UNKNOWN",  # Would need echo gate integration
            l1_reject_url_sample=self._l1_echo_reject_samples[-5:] if self._l1_echo_reject_samples else [],
            source_family_reject_sample=self._l1_echo_family_samples[-5:] if self._l1_echo_family_samples else [],
            dead_link_detected=False,  # Would need link checker integration
            rescue_attempted=False,
            consecutive_same_action=self._iteration_trace_consecutive_same_action,
            consecutive_empty_actions=self._iteration_trace_consecutive_empty_actions,
            candidates_in_backlog=backlog_size,
            frontier_size=frontier_size,
            iteration_cumulative_findings=cumulative_findings,
            iteration_cumulative_sources=cumulative_sources,
            # Sprint 3C: Pressure snapshot
            io_only_mode=self._is_io_only_mode() if hasattr(self, '_is_io_only_mode') else False,
            adaptive_concurrency_cap=self._get_adaptive_concurrency_cap() if hasattr(self, '_get_adaptive_concurrency_cap') else 4,
            thermal_is_critical=False,
            uma_is_critical=False,
            windup_active=self._lifecycle_windup_active if hasattr(self, '_lifecycle_windup_active') else False,
            remaining_seconds=self._lifecycle.remaining_time if hasattr(self, '_lifecycle') and self._lifecycle else 0.0,
        )

        # Append to buffer (bounded)
        self._iteration_trace_buffer.append(trace)

        # Update last values
        self._iteration_trace_last_query_hash = query_hash
        self._iteration_trace_last_action = chosen_action
        self._iteration_trace_last_cumulative_findings = cumulative_findings
        self._iteration_trace_last_cumulative_sources = cumulative_sources

        return trace

    def _compute_capability_reachability_report(self) -> Dict[str, Any]:
        """
        Compute capability reachability report from trace data.

        Analyzes which actions are:
        - economics-dead (never selected due to cost)
        - reachability-dead (blocked by phase/preconditions)
        - echo-blocked
        - duplicate-only
        - suffering from candidate starvation
        """
        if not self._iteration_trace_buffer:
            return {"error": "No trace data"}

        # Aggregate from trace buffer
        action_selection_count: Dict[str, int] = defaultdict(int)
        action_execution_count: Dict[str, int] = defaultdict(int)
        action_findings: Dict[str, int] = defaultdict(int)
        action_sources: Dict[str, int] = defaultdict(int)
        zero_score_reasons: Dict[str, Dict[str, int]] = defaultdict(lambda: defaultdict(int))
        result_types: Dict[str, int] = defaultdict(int)
        consecutive_streaks: List[int] = []

        prev_action = None
        for trace in self._iteration_trace_buffer:
            action_selection_count[trace.chosen_action] += 1

            if trace.action_result_type != "NOT_SELECTED":
                action_execution_count[trace.chosen_action] += 1

            action_findings[trace.chosen_action] += trace.new_findings
            action_sources[trace.chosen_action] += trace.new_sources

            result_types[trace.action_result_type] += 1

            for action, reason in trace.zero_score_reason_code_by_action.items():
                zero_score_reasons[action][reason] += 1

            if trace.consecutive_same_action > 0:
                consecutive_streaks.append(trace.consecutive_same_action)

        return {
            "action_selection_count": dict(action_selection_count),
            "action_execution_count": dict(action_execution_count),
            "action_findings": dict(action_findings),
            "action_sources": dict(action_sources),
            "zero_score_reasons": {k: dict(v) for k, v in zero_score_reasons.items()},
            "result_types": dict(result_types),
            "consecutive_streaks_max": max(consecutive_streaks) if consecutive_streaks else 0,
            "total_iterations": len(self._iteration_trace_buffer),
        }

    def _termination_reason(self) -> Optional[str]:
        """Vrátí důvod ukončení nebo None pokud nemá končit."""
        # Budget termination
        budget_ok, _ = self._budget_manager.check_time_allowed()
        if not budget_ok:
            return "budget_exhausted"

        # High confidence termination
        if self._main_hypothesis is not None:
            confidence = getattr(self._main_hypothesis, 'confidence', 0.0)
            if confidence > 0.9:
                return f"high_confidence_{confidence:.2f}"

        # Sprint 82Q: Bounded escape hatch for premature stagnation
        # If stagnating but backlog has candidates, allow continuation with limited retries
        if self._stagnation_counter > 5:
            # Check if there are backlog candidates that could be promoted
            backlog_count = len(getattr(self, '_hold_backlog', []) or [])
            # Allow up to 3 additional "escape" iterations if backlog has candidates
            escape_remaining = getattr(self, '_stagnation_escape_remaining', 3)
            if backlog_count > 0 and escape_remaining > 0:
                self._stagnation_escape_remaining = escape_remaining - 1
                logger.info(f"[SPRINT82Q] Escape hatch: {escape_remaining} remaining, backlog={backlog_count}")
                return None  # Don't terminate yet
            return f"stagnation_{self._stagnation_counter}"

        # Max iterations termination
        if self._iter_count >= self._max_iters:
            return f"max_iterations_{self._iter_count}"

        # Contradiction queue cycling
        if len(self._contradiction_queue) > 15:
            return "contradiction_cycle"

        return None

    def _should_terminate(self) -> bool:
        """Určí, zda má být autonomní smyčka ukončena."""
        return self._termination_reason() is not None

    async def _investigate_contradiction(self, claim_id: str) -> ActionResult:
        """Provede investigaci konkrétní kontradikce."""
        # Najdi claim v queue
        claim_text = None
        for i, item in enumerate(self._contradiction_queue):
            if item.get('claim_id') == claim_id:
                claim_text = item.get('text', claim_id)
                # Odeber z fronty
                try:
                    del self._contradiction_queue[i]
                except Exception:
                    pass
                break

        if not claim_text:
            return ActionResult(success=False, error=f"Claim {claim_id} not found")

        # Získej hypothesis engine
        engine = await self._get_hypothesis_engine()
        if not engine:
            return ActionResult(success=False, error="HypothesisEngine not available")

        try:
            report = await engine.verify_claim(claim_text)
            # Bezpečné čtení atributů
            contradictions = getattr(report, 'contradictions_found', [])
            devil_score = getattr(report, 'devil_advocate_score', 0.0)
            overall_confidence = getattr(report, 'overall_confidence', 0.5)
            return ActionResult(
                success=True,
                contradictions=contradictions,
                metadata={
                    'devil_score': devil_score,
                    'overall_confidence': overall_confidence,
                    'claim_id': claim_id
                }
            )
        except Exception as e:
            return ActionResult(success=False, error=str(e))

    def _check_memory_pressure(self) -> None:
        """Synchronní kontrola paměti a evikce MLX cache."""
        import gc
        try:
            import psutil
            proc = psutil.Process()
            rss = proc.memory_info().rss / 1e9  # v GB
            if rss > 4.0:
                logger.warning(f"RSS {rss:.2f} GB – evicting MLX cache")
                from hledac.universal.utils.mlx_cache import evict_all
                evict_all()
                gc.collect()
                if hasattr(self, '_evidence_log') and self._evidence_log:
                    self._evidence_log.create_event("memory_pressure", {"rss_gb": rss, "action": "evict"})
        except ImportError:
            pass  # psutil není dostupné
        except Exception as e:
            logger.warning(f"Memory check failed: {e}")

    # =========================================================================
    # Sprint 68: Registrace akcí (KROK 4)
    # =========================================================================

    def _register_action(self, name: str, handler: Any, scorer: Any) -> None:
        """Registruje akci do instančního registru."""
        self._action_registry[name] = (handler, scorer)

    async def _get_render_coordinator(self):
        """Lazy získání render coordinator."""
        if self._render_coordinator is None:
            try:
                from hledac.universal.coordinators.render_coordinator import RenderCoordinator
                self._render_coordinator = RenderCoordinator()
            except Exception as e:
                logger.warning(f"RenderCoordinator init failed: {e}")
                return None
        return self._render_coordinator

    async def _initialize_actions(self) -> None:
        """Inicializuje instanční registry akcí."""
        from hledac.universal.utils import ActionResult

        # ---- surface_search ----
        async def surface_search_handler(query: str) -> ActionResult:
            # Sprint 7D: Offline fast-fail guard
            if _HLEDAC_OFFLINE and getattr(self, '_data_mode', None) != "OFFLINE_REPLAY":
                return ActionResult(success=False, error="HLEDAC_OFFLINE=1: surface_search unavailable")
            if not self._research_mgr:
                return ActionResult(success=False, error="ResearchMgr not initialized")
            try:
                res = await self._research_mgr.execute_surface_search(query)
                return ActionResult(
                    success=True,
                    findings=res.get('findings', []),
                    sources=res.get('sources', []),
                    metadata={'action': 'surface_search'}
                )
            except Exception as e:
                return ActionResult(success=False, error=str(e))

        def surface_search_scorer(state: Dict[str, Any]) -> Tuple[float, Dict[str, Any]]:
            score = 0.5
            if state.get('recent_novelty', 0) < 0.2:
                score += 0.2

            # Sprint 3A: Freshness bonus - prefer newer sources
            sources = state.get('sources', [])
            if sources:
                try:
                    import time
                    now = time.time()
                    ages = []
                    for src in sources:
                        # Try to get age_days from metadata
                        meta = getattr(src, 'metadata', {}) or {}
                        age_days = meta.get('age_days')
                        if age_days is None:
                            # Fallback: estimate from fetched_at
                            fetched_at = meta.get('fetched_at', 0)
                            if fetched_at > 0:
                                age_days = (now - fetched_at) / 86400
                        if age_days is not None:
                            ages.append(age_days)

                    if ages:
                        avg_age = sum(ages) / len(ages)
                        # Freshness bonus: newer = higher bonus (max 0.15)
                        # decay formula: bonus = 0.15 * exp(-age_days / 365)
                        import math
                        freshness_bonus = 0.15 * math.exp(-avg_age / 365)
                        score += freshness_bonus
                except Exception:
                    pass  # Silently ignore freshness calculation errors

            # Sprint 86F: Track score history for post-mortem percentiles
            if not hasattr(self, '_score_history'):
                self._score_history = {}
            if 'surface_search' not in self._score_history:
                self._score_history['surface_search'] = deque(maxlen=200)
            self._score_history['surface_search'].append(score)
            return (score, {"query": state['query']})

        self._register_action('surface_search', surface_search_handler, surface_search_scorer)

        # ---- archive_fetch ----
        async def archive_fetch_handler(url: str) -> ActionResult:
            # Sprint 7D: Offline fast-fail guard
            if _HLEDAC_OFFLINE and getattr(self, '_data_mode', None) != "OFFLINE_REPLAY":
                return ActionResult(success=False, error="HLEDAC_OFFLINE=1: archive_fetch unavailable")
            try:
                # Initialize archive coordinator if needed
                if self._archive_coordinator is None:
                    self._archive_coordinator = ArchiveCoordinator()
                ac = self._archive_coordinator
                result = await ac.fetch(url)
                if result and result.get('content'):
                    # Use content_miner for extraction
                    try:
                        from hledac.universal.tools.content_miner import ContentMiner
                        miner = ContentMiner()
                        mined = await miner.mine(result['content'], url)
                        return ActionResult(
                            success=True,
                            findings=[mined],
                            metadata={'url': url, 'preview': mined.content[:500] if hasattr(mined, 'content') else '', 'archive': True}
                        )
                    except Exception as e:
                        logger.warning(f"Content mining failed: {e}")
                        return ActionResult(success=True, findings=[result['content']], metadata={'url': url, 'archive': True})
                return ActionResult(success=False, metadata={'url': url})
            except Exception as e:
                return ActionResult(success=False, error=str(e))

        def archive_fetch_scorer(state: Dict[str, Any]) -> Tuple[float, Dict[str, Any]]:
            if state.get('archive_available') and state.get('recent_novelty', 1) < 0.3:
                url = self._pick_url_for_archive()
                if url:
                    return (0.8, {"url": url})
            return (0.0, {})

        self._register_action('archive_fetch', archive_fetch_handler, archive_fetch_scorer)

        # ---- render_page ----
        async def render_page_handler(url: str, mode: str = 'text') -> ActionResult:
            # Sprint 7D: Offline fast-fail guard
            if _HLEDAC_OFFLINE and getattr(self, '_data_mode', None) != "OFFLINE_REPLAY":
                return ActionResult(success=False, error="HLEDAC_OFFLINE=1: render_page unavailable")
            try:
                rc = await self._get_render_coordinator()
                if not rc:
                    return ActionResult(success=False, error="RenderCoordinator not available")
                res = await rc.render(url, mode=mode)
                if res and getattr(res, 'status', None) == 'ok':
                    # Use content_miner for extraction
                    try:
                        from hledac.universal.tools.content_miner import ContentMiner
                        if hasattr(res, 'html'):
                            miner = ContentMiner()
                            mined = await miner.mine(res.html, url)
                            return ActionResult(
                                success=True,
                                findings=[mined],
                                metadata={'url': url, 'preview': mined.content[:500] if hasattr(mined, 'content') else ''}
                            )
                    except Exception as e:
                        logger.warning(f"Content mining failed: {e}")
                return ActionResult(success=False, metadata={'url': url, 'status': getattr(res, 'status', 'unknown') if res else 'no_result'})
            except Exception as e:
                return ActionResult(success=False, error=str(e))

        def render_page_scorer(state: Dict[str, Any]) -> Tuple[float, Dict[str, Any]]:
            if state.get('browser_available') and state.get('js_gated'):
                url = self._current_url()
                if url:
                    return (0.9, {"url": url})
            return (0.0, {})

        self._register_action('render_page', render_page_handler, render_page_scorer)

        # ---- investigate_contradiction ----
        async def investigate_handler(claim_id: str) -> ActionResult:
            return await self._investigate_contradiction(claim_id)

        def investigate_scorer(state: Dict[str, Any]) -> Tuple[float, Dict[str, Any]]:
            if state.get('contradictions', 0) > 0 and self._contradiction_queue:
                first = self._contradiction_queue[0]
                claim_id = first.get('claim_id', '')
                if claim_id:
                    return (1.0, {"claim_id": claim_id})
            return (0.0, {})

        self._register_action('investigate_contradiction', investigate_handler, investigate_scorer)

        # Sprint 69D: build_structure_map action
        async def build_structure_map_handler() -> ActionResult:
            """Handler for build_structure_map action."""
            try:
                # Check if should run
                snap = await self._structure_map_scalar_snapshot()
                now = time.monotonic()
                if not self._structure_map_should_run(now, snap):
                    return ActionResult(
                        success=False,
                        error="structure_map scheduling gate closed",
                        findings=[],
                        metadata={"skipped": True}
                    )

                # Execute build
                result = await self._build_structure_map_async(
                    limits=self._HIGH_PRIORITY_STRUCTURE_MAP_LIMITS
                )
                fingerprint = result.get("fingerprint", "")
                return ActionResult(
                    success=True,
                    findings=[],
                    metadata={
                        "structure_map_fingerprint": fingerprint,
                        "files_count": len(result.get("files", [])),
                        "edges_count": len(result.get("edges", [])),
                    }
                )
            except Exception as e:
                return ActionResult(
                    success=False,
                    error=str(e),
                    findings=[],
                    metadata={"structure_map_error": True}
                )

        def build_structure_map_scorer(state: Dict[str, Any]) -> Tuple[float, Dict[str, Any]]:
            """Scorer for build_structure_map action - NON-BLOCKING.

            Reads gating values from state dict (pre-computed in _analyze_state).
            No async calls, no thread pools, no blocking operations.
            """
            # Sprint 69E: Read pre-computed gating from state (non-blocking)
            if not state.get("structure_map_can_run", False):
                return (-1e9, {})

            # Base score if can run
            score = 0.35

            # Bonus for upcoming synthesis (pre-computed in _analyze_state)
            if state.get("structure_map_upcoming_synthesis"):
                score += 0.10

            return (score, {})

        self._register_action('build_structure_map', build_structure_map_handler, build_structure_map_scorer)

