        async def _handle_crawl_onion(self, **kwargs) -> ActionResult:
            """Handler for dark web onion crawl action."""
            # Sprint 7E: Offline fast-fail guard
            if _HLEDAC_OFFLINE and getattr(self, '_data_mode', None) != "OFFLINE_REPLAY":
                return ActionResult(success=False, error="HLEDAC_OFFLINE=1: crawl_onion unavailable")
            onion_address = kwargs.get('onion_address', kwargs.get('onion_target', ''))
            try:
                # Sprint 5D: Autonomous transport selection
                transport = self._select_transport_for_target(onion_address)

                # Track transport selection
                if hasattr(self, '_transport_selected_count'):
                    self._transport_selected_count[transport] = self._transport_selected_count.get(transport, 0) + 1

                if transport == 'unavailable':
                    return ActionResult(success=False, error="Transport unavailable", findings=[], metadata={'transport': 'unavailable'})

                if transport == 'default':
                    return ActionResult(success=False, error="Non-onion target", findings=[], metadata={'transport': 'default'})

                # Use tor_manager if selected and available
                await self._ensure_tor_manager()
                if not self._tor_manager:
                    if hasattr(self, '_transport_unavailable_count'):
                        self._transport_unavailable_count = getattr(self, '_transport_unavailable_count', 0) + 1
                    return ActionResult(success=False, error="Tor not available", findings=[], metadata={'transport': 'tor_unavailable'})

                # Execute with tor_manager
                from hledac.universal.intelligence.stealth_crawler import StealthCrawler
                crawler = StealthCrawler()
                findings = []
                async for content in crawler.crawl_onion(onion_address, depth=2):
                    findings.append(content)
                    if hasattr(self, '_graph_rag') and self._graph_rag:
                        await self._graph_rag.add_node(content.url, 'onion_content', onion_address)

                # Update EMA on success
                self._update_transport_ema('tor', success=len(findings) > 0)
                return ActionResult(success=True, findings=findings, metadata={'findings_count': len(findings), 'transport': 'tor'})
            except Exception as e:
                self._update_transport_ema('tor', success=False)
                return ActionResult(success=False, error=str(e), findings=[], metadata={'onion_error': True})

        def _onion_scorer(state: Dict[str, Any]) -> Tuple[float, Dict[str, Any]]:
            if state.get('has_onion_targets'):
                return (0.8, {"onion_address": state['onion_target']})
            return (0.0, {})
        self._register_action('crawl_onion', _handle_crawl_onion, _onion_scorer)

        async def _handle_path_discovery(self, **kwargs) -> ActionResult:
            """Handler for path discovery action."""
            base_url = kwargs.get('base_url', '')
            known_paths = kwargs.get('known_paths', [])
            try:
                from hledac.universal.intelligence.path_discovery import ShadowWalkerAlgorithm
                pathfinder = ShadowWalkerAlgorithm()
                predictions = pathfinder.predict_next_paths(base_url, known_paths, max_predictions=10)
                # Sprint 2A: Windup check — skip new frontier work during wind-down
                if self._lifecycle_windup_active:
                    return ActionResult(success=True, findings=[],
                        metadata={'predictions': len(predictions), 'windup_skip': True})
                if hasattr(self, '_url_frontier') and self._url_frontier:
                    for url, conf in predictions:
                        self._url_frontier.push(url, novelty_score=conf)
                return ActionResult(success=True, findings=[], metadata={'predictions': len(predictions)})
            except Exception as e:
                return ActionResult(success=False, error=str(e), findings=[], metadata={'path_discovery_error': True})

        def _path_discovery_scorer(state: Dict[str, Any]) -> Tuple[float, Dict[str, Any]]:
            if state.get('has_known_paths'):
                return (0.4, {"base_url": state['base_url'], "known_paths": state['known_paths']})
            return (0.0, {})
        self._register_action('generate_paths', _handle_path_discovery, _path_discovery_scorer)

