        async def ct_discovery_handler(**kwargs) -> ActionResult:
            # Sprint 7D: Offline fast-fail guard
            if _HLEDAC_OFFLINE and getattr(self, '_data_mode', None) != "OFFLINE_REPLAY":
                return ActionResult(success=False, error="HLEDAC_OFFLINE=1: ct_discovery unavailable")
            """Handler for CT discovery action."""
            domain = kwargs.get('domain', kwargs.get('new_domain', ''))
            try:
                # Check budget
                if self._phase_controller.current_phase.value >= 3:
                    return ActionResult(success=False, error="Phase 3+: no new CT", findings=[])

                stealth = getattr(self, '_stealth', None)
                if not stealth:
                    return ActionResult(success=False, error="No stealth", findings=[])

                subdomains = await _ct_quick_discover(domain, stealth)

                # Update metrics
                if self._metrics_registry:
                    if subdomains:
                        self._metrics_registry.inc("ct_discovery_hits", len(subdomains))
                    else:
                        self._metrics_registry.inc("ct_discovery_failures", 1)

                return ActionResult(
                    success=True,
                    findings=[],
                    metadata={'subdomains': subdomains, 'count': len(subdomains)}
                )
            except Exception as e:
                if self._metrics_registry:
                    self._metrics_registry.inc("ct_discovery_failures", 1)
                return ActionResult(success=False, error=str(e), findings=[])

        def ct_discovery_scorer(state: Dict[str, Any]) -> Tuple[float, Dict[str, Any]]:
            if state.get('new_domain_detected') and state.get('phase', 0) < 3:
                score = 0.7
                # Sprint 86F: Track score history
                if not hasattr(self, '_score_history'):
                    self._score_history = {}
                if 'ct_discovery' not in self._score_history:
                    self._score_history['ct_discovery'] = deque(maxlen=200)
                self._score_history['ct_discovery'].append(score)
                return (score, {"domain": state.get('new_domain', '')})
            return (0.0, {})

