        async def wayback_rescue_handler(**kwargs) -> ActionResult:
            # Sprint 7D: Offline fast-fail guard
            if _HLEDAC_OFFLINE and getattr(self, '_data_mode', None) != "OFFLINE_REPLAY":
                return ActionResult(success=False, error="HLEDAC_OFFLINE=1: wayback_rescue unavailable")
            """Handler for Wayback rescue action."""
            url = kwargs.get('url', kwargs.get('dead_url', ''))
            try:
                stealth = getattr(self, '_stealth', None)
                if not stealth:
                    return ActionResult(success=False, error="No stealth", findings=[])

                # Quick check first
                wayback_meta = await _wayback_quick_check(url, stealth)

                if wayback_meta and wayback_meta.get('available'):
                    if self._metrics_registry:
                        self._metrics_registry.inc("wayback_quick_hits", 1)
                    return ActionResult(
                        success=True,
                        findings=[],
                        metadata={'rescued_url': wayback_meta.get('url'), 'timestamp': wayback_meta.get('timestamp'), 'method': 'wayback_quick'}
                    )

                # CDX fallback
                parsed = urlparse(url)
                cdx_results = await _wayback_cdx_stream(parsed.netloc, stealth, max_lines=10)

                if cdx_results:
                    if self._metrics_registry:
                        self._metrics_registry.inc("wayback_cdx_hits", 1)
                    first = cdx_results[0]
                    return ActionResult(
                        success=True,
                        findings=[],
                        metadata={'rescued_url': first.get('wayback_url'), 'timestamp': first.get('timestamp'), 'method': 'wayback_cdx'}
                    )

                return ActionResult(success=False, error="No archive found", findings=[])
            except Exception as e:
                return ActionResult(success=False, error=str(e), findings=[])

