        # ---- necromancer_rescue ----
        async def necromancer_handler(**kwargs) -> ActionResult:
            # Sprint 7D: Offline fast-fail guard
            if _HLEDAC_OFFLINE and getattr(self, '_data_mode', None) != "OFFLINE_REPLAY":
                return ActionResult(success=False, error="HLEDAC_OFFLINE=1: necromancer unavailable")
            """Handler for full Necromancer rescue chain."""
            url = kwargs.get('url', kwargs.get('dead_url', ''))
            try:
                if self._necromancer_budget_used >= _NECROMANCER_BUDGET_PER_SPRINT:
                    return ActionResult(success=False, error="Budget exhausted", findings=[])

                stealth = getattr(self, '_stealth', None)
                if not stealth:
                    return ActionResult(success=False, error="No stealth", findings=[])

                budget_remaining = _NECROMANCER_BUDGET_PER_SPRINT - self._necromancer_budget_used
                result = await _necromancer_rescue_chain(url, stealth, budget_remaining=budget_remaining)

                if result and result.get('rescued'):
                    self._necromancer_budget_used += 1
                    if self._metrics_registry:
                        self._metrics_registry.inc("necromancer_rescues", 1)
                    return ActionResult(
                        success=True,
                        findings=[],
                        metadata=result
                    )
                else:
                    if self._metrics_registry:
                        self._metrics_registry.inc("necromancer_failures", 1)
                    return ActionResult(success=False, error=result.get('reason', 'failed'), findings=[])

            except Exception as e:
                if self._metrics_registry:
                    self._metrics_registry.inc("necromancer_failures", 1)
                return ActionResult(success=False, error=str(e), findings=[])

