    # -------------------------------------------------------------------------

    async def _init_layers(self) -> bool:
        """
        Initialize LayerManager and all 9 layers.

        This method:
        - Uses lazy import to avoid import costs
        - Instantiates LayerManager with config
        - Calls initialize_all() to boot all layers
        - Records a Decision Ledger event (bounded summary)
        - Handles graceful degradation if layers unavailable

        Returns:
            True if layers initialized successfully (or already initialized)
        """
        # Idempotence check
        if self._layers_initialized:
            logger.debug("Layers already initialized, skipping")
            return True

        try:
            # Lazy import to avoid import costs
            from .layers.layer_manager import LayerManager

            # Get config dict for LayerManager
            config_dict = {}
            if hasattr(self.config, 'research'):
                config_dict = {'memory_limit_mb': 5500}

            # Instantiate LayerManager
            self._layer_manager = LayerManager(config=config_dict)

            # Initialize all layers
            success = await self._layer_manager.initialize_all()

            if success:
                self._layers_initialized = True
                layer_count = len(self._layer_manager._layers)
                ghost_director = self._layer_manager.get_ghost_director() is not None

                # Record Decision Ledger event (bounded summary)
                if hasattr(self, '_evidence_log') and self._evidence_log:
                    self._evidence_log.create_decision_event(
                        kind="layers_initialized",
                        summary={
                            "layers_enabled": True,
                            "layer_count": layer_count,
                            "ghostdirector": ghost_director
                        },
                        reasons=[],
                        refs={},
                        confidence=1.0
                    )

                logger.info(f"✅ Layers initialized: {layer_count} layers, GhostDirector={ghost_director}")
            else:
                logger.warning("⚠️ LayerManager.initialize_all returned False")

            return success

        except ImportError as e:
            # Graceful degradation: layers package might not be available
            logger.warning(f"⚠️ Layers package not available: {e}")

            # Record degradation event
            if hasattr(self, '_evidence_log') and self._evidence_log:
                try:
                    self._evidence_log.create_decision_event(
                        kind="layers_unavailable",
                        summary={"layers_enabled": False, "error": str(e)[:100]},
                        reasons=["import_error"],
                        refs={},
                        confidence=0.5
                    )
                except Exception:
                    pass  # Don't fail initialization if logging fails

            self._layers_initialized = True  # Mark as "handled" to avoid retries
            return True  # Continue with degraded mode

        except Exception as e:
            logger.error(f"❌ Layer initialization failed: {e}")
            # Don't fail the whole orchestrator - degrade gracefully
            self._layers_initialized = True  # Prevent retry loops
            return True

    async def initialize(self) -> bool:
        """Inicializuje všechny komponenty."""
        # Sprint 79c: MLX Metal memory limit - kritická bezpečnostní zábrana proti OOM
        try:
            import mlx.core as mx
            # Ponecháme 2GB pro OS + CPU heap, zbytek (6GB) pro Metal
            metal_limit_gb = 6
            # Sprint 8AE: hasattr guard for mx.metal API
            if hasattr(mx, 'set_memory_limit'):
                mx.set_memory_limit(metal_limit_gb * 1024**3)
            elif hasattr(mx.metal, 'set_memory_limit'):
                mx.metal.set_memory_limit(metal_limit_gb * 1024**3)
            logger.info(f"MLX Metal memory limit set: {metal_limit_gb}GB")
        except Exception as e:
            logger.warning(f"Could not set Metal memory limit: {e}")

        # Sprint 79c: Lazy module loading - parallel light, sequential heavy
        all_lazy_modules = [mlx_lm, transformers, torch, pd]
        # Heavy: mlx_lm and torch trigger Metal shader compilation - load sequentially
        heavy_modules = [mlx_lm, torch]
        light_modules = [m for m in all_lazy_modules if m not in heavy_modules]

        # Load light modules in parallel
        if light_modules:
            await asyncio.gather(*(m.ensure_loaded() for m in light_modules), return_exceptions=True)

        # Load heavy modules sequentially (Metal shader compilation is CPU-intensive)
        for m in heavy_modules:
            try:
                await m.ensure_loaded()
            except Exception as e:
                logger.debug(f"Lazy module {m._name} not available: {e}")

        # One-time GC after all lazy imports
        import gc
        gc.collect()
        logger.info(f"All lazy modules loaded, GC collected after imports")

        # Sprint 8AJ: Boot hygiene - stale artifact cleanup BEFORE any DB/session init
        # These use narrow, idempotent cleanup helpers from paths module
        try:
            from hledac.universal.paths import (
                LMDB_ROOT, SOCKETS_ROOT, RAMDISK_ACTIVE,
                cleanup_stale_lmdb_locks, cleanup_stale_sockets,
                assert_ramdisk_alive, RAMDISK_ROOT,
            )
            # Verify RAMDISK is still alive if it was active at import
            assert_ramdisk_alive()

            # Sprint 8AJ: FD baseline telemetry
            import resource, psutil, os as _os
            _proc = psutil.Process(_os.getpid())
            _soft, _hard = resource.getrlimit(resource.RLIMIT_NOFILE)
            self._runtime_nofile_soft = _soft
            self._runtime_nofile_hard = _hard
            self._runtime_num_fds_start = _proc.num_fds()
            self._runtime_rss_mb_start = _proc.memory_info().rss // 1024**2
            self._runtime_ramdisk_active = RAMDISK_ACTIVE
            self._runtime_ramdisk_root = str(RAMDISK_ROOT)

            # Sprint 8AJ: Count artifacts outside ramdisk for telemetry
            _outside = 0
            if not RAMDISK_ACTIVE:
                # Count lock files that would be cleaned
                import pathlib
                for _lock in [pathlib.Path(LMDB_ROOT) / "lock.mdb"]:
                    if _lock.exists():
                        _outside += 1
                # Count socket files
                if pathlib.Path(SOCKETS_ROOT).exists():
                    for _sock in pathlib.Path(SOCKETS_ROOT).iterdir():
                        if _sock.suffix == ".sock":
                            _outside += 1
            self._runtime_artifacts_outside_ramdisk_count = _outside

            # Sprint 8AJ: Cleanup stale LMDB lock files (narrow, idempotent)
            _locks_removed = cleanup_stale_lmdb_locks(LMDB_ROOT)
            self._lmdb_locks_removed_at_boot = _locks_removed
            if _locks_removed > 0:
                logger.info(f"[BOOT HYGIENE] Removed {_locks_removed} stale LMDB lock file(s)")

            # Sprint 8AJ: Cleanup stale Unix sockets (narrow, idempotent)
            _sockets_removed = cleanup_stale_sockets(SOCKETS_ROOT)
            self._stale_sockets_removed_at_boot = _sockets_removed
            if _sockets_removed > 0:
                logger.info(f"[BOOT HYGIENE] Removed {_sockets_removed} stale socket file(s)")

            # Sprint 8AJ: Cleanup fallback artifacts on process exit
            if not RAMDISK_ACTIVE:
                import atexit
                def _cleanup_fallback():
                    from hledac.universal.paths import cleanup_fallback_artifacts
                    cleanup_fallback_artifacts()
                atexit.register(_cleanup_fallback)

        except Exception as _bh_e:
            # Never let boot hygiene failures prevent startup
            logger.warning(f"[BOOT HYGIENE] Cleanup error (non-fatal): {_bh_e}")

        try:
            logger.info("🔧 Initializing all components...")

            # Initialize coordinators
            self._initialize_coordinators()

            # Initialize LayerManager and all layers
            await self._init_layers()

            # Sprint 82M: Load supreme components before MemoryManager uses them
            _load_supreme_components()

            await self._memory_mgr.initialize()
            await self._brain_mgr.initialize()
            if self._security_mgr:
                await self._security_mgr.initialize()
            await self._forensics_mgr.initialize()
            await self._tool_mgr.initialize()
            await self._research_mgr.initialize()

            # Sprint 34: Initialize SourceBandit (UCB1 bandit for source selection)
            try:
                self._source_bandit = SourceBandit()
                logger.info("✅ SourceBandit initialized")
            except Exception as e:
                logger.warning(f"⚠️ SourceBandit init failed: {e}")
                self._source_bandit = None

            # Sprint 46: Initialize OSINT frameworks and Darknet connector
            try:
                self._osint_runner = OSINTFrameworkRunner()
                logger.info("✅ OSINTFrameworkRunner initialized")
            except Exception as e:
                logger.warning(f"⚠️ OSINTFrameworkRunner init failed: {e}")
                self._osint_runner = None

            try:
                self._darknet_connector = DarknetConnector()
                logger.info("✅ DarknetConnector initialized")
            except Exception as e:
                logger.warning(f"⚠️ DarknetConnector init failed: {e}")
                self._darknet_connector = None

            # Sprint 62: Initialize VisionEncoder (multimodal)
            try:
                from .core.resource_governor import ResourceGovernor
                self.governor = ResourceGovernor()
                self.vision_encoder = VisionEncoder(self.governor)
                await self.vision_encoder.load()
                logger.info("✅ VisionEncoder initialized")
            except Exception as e:
                logger.warning(f"⚠️ VisionEncoder init failed: {e}")
                self.vision_encoder = None

            # Sprint 62: Initialize fusion model (best-effort)
            try:
                self.fusion_model = MobileCLIPFusion()
                logger.info("✅ Using MobileCLIPFusion")
            except Exception:
                try:
                    self.fusion_model = MambaFusion()
                    logger.info("✅ Using MambaFusion")
                except Exception as e:
                    logger.warning(f"⚠️ Fusion model init failed: {e}")
                    self.fusion_model = None

            # Sprint 62: Initialize DHT (Kademlia + LocalGraph + SketchExchange)
            try:
                from .security.key_manager import KeyManager
                self.key_manager = KeyManager()
                self.local_graph = LocalGraphStore(self.key_manager)
                bootstrap = []
                try:
                    bootstrap = list(getattr(self.config, "dht_bootstrap", []) or [])
                except Exception:
                    bootstrap = []
                # Use run_id as node_id, or generate one if not available yet
                node_id = self._run_id or f"node_{uuid.uuid4().hex[:8]}"
                self.dht_node = KademliaNode(node_id, self.governor, bootstrap_nodes=bootstrap)
                self.dht_node.set_transport(self._tor_transport if hasattr(self, '_tor_transport') else None)
                await self.dht_node.start()
                self.sketch_exchange = SketchExchange(self.governor, node_id, self.dht_node, self.local_graph)
                await self.sketch_exchange.start()
                logger.info("✅ DHT components initialized")
            except Exception as e:
                logger.warning(f"⚠️ DHT init failed: {e}")
                self.dht_node = None
                self.local_graph = None
                self.sketch_exchange = None

            # Initialize Tree of Thoughts integration
            if TOT_INTEGRATION_AVAILABLE and getattr(self.config, 'tot_enabled', True):
                try:
                    self._tot_integration = TotIntegrationLayer(
                        config=TotConfig(
                            enable_tot_autonomous=True,
                            tot_complexity_threshold=0.70,
                            hybrid_complexity_threshold=0.45,
                            tot_max_depth=5,
                            tot_max_time=120.0,
                            tot_enable_backtracking=True,
                            tot_enable_mcts=True,
                            memory_limit_mb=5500.0,
                        )
                    )
                    logger.info("✅ ToT Integration initialized")
                except Exception as e:
                    logger.warning(f"⚠️ ToT integration failed: {e}")
                    self._tot_integration = None

            # Initialize Phase 3: Neuromorphic and Federated engines (optional)
            if self.config.enable_neuromorphic:
                await self._research_mgr._init_snn_engine()

            # Sprint 5C: Autonomous Federated activation (no config flag needed)
            # Only initialize if resources allow - will be triggered autonomously during research
            self._federated_available = True  # Local-only mode always available
            logger.info("[FEDERATED] Local-only mode available")

            self._state_mgr._initialized = True

            # Sprint 32+33: Start Autonomy Monitor background task
            # Sprint 8AB: Migrated to _start_background_task for unified tracking
            if not getattr(self, '_autonomy_monitor_running', False):
                self._original_max_hypotheses = getattr(self._research_mgr, 'MAX_FINDINGS_IN_RAM', 50)
                self._autonomy_monitor_task = self._start_background_task(
                    self._autonomy_monitor_loop(),
                    name="autonomy_monitor"
                )
                self._autonomy_monitor_running = True
                logger.info("[AUTONOMY] Memory monitor started")

            # Sprint 72: Start Thermal Monitor if memory_mgr available
            await self._ensure_thermal_monitor_started()

            # Sprint 2A: Probe for existing checkpoint before starting sprint (fail-open)
            self._probe_checkpoint_restore()

            # Sprint 1A: Begin sprint lifecycle (BOOT → WARMUP)
            self._lifecycle.begin_sprint()
            # Set wind-down hook: when T-3min triggers, stop new frontier expansion
            self._lifecycle.set_windup_hook(self._on_lifecycle_windup)
            self._lifecycle.set_export_hook(self._on_lifecycle_export)
            self._lifecycle.set_teardown_hook(self._on_lifecycle_teardown)
            # Register SIGINT/SIGTERM handlers pointing to unified shutdown
            self._lifecycle.register_signal_handlers(self.shutdown_all)

            # Sprint 7A: Initialize thread pools for bounded execution
            self._init_thread_pools()
            logger.info(f"[THREAD_POOL] IO={self._io_thread_pool_size}, CPU={self._cpu_thread_pool_size}, DNS={self._dns_thread_pool_size}")

            # Sprint 7A: Initialize httpx client for Tier-1 API paths
            await self._init_httpx_client()

            logger.info("✅ FullyAutonomousOrchestrator ready!")
            return True

        except Exception as e:
            logger.error(f"❌ Initialization failed: {e}")
            logger.error(traceback.format_exc())
            return False

