# =============================================================================

class _StateManager:
    """Manages orchestrator state machine and lifecycle."""

    def __init__(self, orchestrator: FullyAutonomousOrchestrator):
        self._orch = orchestrator
        self.state = OrchestratorState.IDLE
        self.phase = ResearchPhase.INITIAL_ANALYSIS
        self._initialized = False
        self._execution_count = 0

    async def transition_to(self, new_state: OrchestratorState) -> None:
        """Přejde do nového stavu."""
        if self.state == new_state:
            return

        logger.debug(f"State transition: {self.state.value} → {new_state.value}")

        if self._orch.config.context_swap_enabled and self._orch._memory_mgr:
            await self._orch._memory_mgr.transition_state(self.state, new_state)

        self.state = new_state

    async def transition_to_brain(self) -> None:
        """Přechod do BRAIN fáze: Načíst Hermes-3 pro plánování."""
        if self.state == OrchestratorState.PLANNING:
            return

        logger.info("[PHASE START] BRAIN")

        # Uvolni non-brain modely
        await self._unload_non_brain_models()

        # Explicitní načtení Hermes přes ModelManager
        from .brain.model_manager import get_model_manager
        mm = get_model_manager()

        try:
            logger.info("[MODEL LOAD] hermes (BRAIN phase)")
            mm.acquire("hermes")

            logger.info("🧠 BRAIN Phase: Hermes-3 ready for decision making")

            # Initialize Tree Planner if available
            _load_supreme_components()
            if SUPREME_AVAILABLE and SerializedTreePlanner:
                if not hasattr(self._orch, '_tree_planner') or self._orch._tree_planner is None:
                    self._orch._tree_planner = SerializedTreePlanner(
                        max_depth=5,
                        max_branches=3,
                        max_evaluations=15
                    )
                    if self._orch._brain_mgr and self._orch._brain_mgr.hermes:
                        self._orch._tree_planner.set_brain(self._orch._brain_mgr.hermes)

            self.state = OrchestratorState.PLANNING
            logger.info("[PHASE END] BRAIN (planning complete)")

            await self._force_memory_cleanup()

        except Exception as e:
            logger.error(f"[PHASE ERROR] BRAIN: {e}")
            # Garantovaný release i při chybě
            mm.release("hermes")
            raise

    async def transition_to_tools(self) -> None:
        """Přechod do TOOLS fáze: Uvolnit BRAIN, načíst nástroje."""
        if self.state == OrchestratorState.EXECUTING:
            return

        logger.info("[PHASE START] TOOLS")

        # Uvolni BRAIN modely (Hermes) pro uvolnění RAM
        from .brain.model_manager import get_model_manager
        mm = get_model_manager()
        mm.release("hermes")

        # Cleanup Tree Planner
        if hasattr(self._orch, '_tree_planner') and self._orch._tree_planner:
            if hasattr(self._orch._tree_planner, 'cleanup'):
                self._orch._tree_planner.cleanup()
            self._orch._tree_planner = None

        logger.info("🔧 TOOLS Phase: Execution environment ready")
        logger.info("   ModernBERT (embeddings) a GLiNER (NER) se načtou on-demand")

        # Tools jsou lazy-loaded, nic se nenačítá hned
        _load_supreme_components()
        if SUPREME_AVAILABLE and RustMiner:
            if not hasattr(self._orch, '_rust_miner'):
                self._orch._rust_miner = RustMiner()

        if SUPREME_AVAILABLE and SecurityGate:
            if not hasattr(self._orch, '_security_gate'):
                self._orch._security_gate = SecurityGate()

        self.state = OrchestratorState.EXECUTING
        logger.info("[PHASE END] TOOLS (ready for execution)")

        await self._force_memory_cleanup()

    async def transition_to_synthesis(self) -> None:
        """Přechod do SYNTHESIS fáze: Uvolnit TOOLS, načíst Hermes-3."""
        if self.state == OrchestratorState.SYNTHESIZING:
            return

        logger.info("[PHASE START] SYNTHESIS")

        # Uvolni všechny TOOLS modely
        from .brain.model_manager import get_model_manager
        mm = get_model_manager()

        # Uvolni ModernBERT a GLiNER pokud jsou načtené
        mm.release("modernbert")
        mm.release("gliner")

        try:
            # Načti Hermes pro syntézu
            logger.info("[MODEL LOAD] hermes (SYNTHESIS phase)")
            mm.acquire("hermes")

            logger.info("🧠 SYNTHESIS Phase: Hermes-3 ready for synthesis")

            # Ensure Hermes is ready via brain manager
            if self._orch._brain_mgr and self._orch._brain_mgr.hermes:
                if hasattr(self._orch._brain_mgr.hermes, 'initialize'):
                    await self._orch._brain_mgr.hermes.initialize()

            self.state = OrchestratorState.SYNTHESIZING
            logger.info("[PHASE END] SYNTHESIS (ready)")

            await self._force_memory_cleanup()

        except Exception as e:
            logger.error(f"[PHASE ERROR] SYNTHESIS: {e}")
            # Garantovaný release i při chybě
            mm.release("hermes")
            raise

    async def _unload_non_brain_models(self) -> None:
        """Uvolnit modely které nejsou potřeba v BRAIN fázi."""
        logger.info("🗑️  [MODEL RELEASE] Unloading non-brain models...")

        # Explicitní uvolnění přes ModelManager
        from .brain.model_manager import get_model_manager
        mm = get_model_manager()

        # Uvolni ModernBERT a GLiNER (pokud jsou načteny)
        mm.release("modernbert")
        mm.release("gliner")

        # Cleanup tools
        if hasattr(self._orch, '_rust_miner'):
            self._orch._rust_miner = None

        # Force garbage collection
        gc.collect()

        if MLX_AVAILABLE and mx:
            try:
                mx.eval([])
                # Sprint 8AE: prefer modern mx.clear_cache()
                if hasattr(mx, 'clear_cache'):
                    mx.clear_cache()
                elif hasattr(mx.metal, 'clear_cache'):
                    mx.metal.clear_cache()
            except Exception:
                pass  # MLX memory cleanup failure

        logger.info("✓ [MODEL RELEASE] Non-brain models unloaded")

    async def _force_memory_cleanup(self) -> None:
        """Agresivní cleanup paměti."""
        gc.collect()

        if MLX_AVAILABLE and mx:
            try:
                mx.eval([])
                # Sprint 8AE: prefer modern mx.clear_cache()
                if hasattr(mx, 'clear_cache'):
                    mx.clear_cache()
                elif hasattr(mx.metal, 'clear_cache'):
                    mx.metal.clear_cache()
            except Exception:
                pass  # MLX memory cleanup failure

        # Memory layer cleanup if available
        if self._orch._memory_mgr:
            await self._orch._memory_mgr.aggressive_cleanup()

        # Darwin malloc zone pressure relief (fail-safe)
        try:
            import ctypes
            libc = ctypes.CDLL("libSystem.dylib")
            libc.malloc_zone_pressure_relief(None, 0)
        except Exception:
            pass

        # Log RSS after cleanup (fail-safe)
        try:
            import psutil
            proc = psutil.Process()
            logger.info(f"[MemCleanup] RSS after cleanup: {proc.memory_info().rss / 1e9:.2f} GB")
        except Exception:
            pass


class _MemoryManager:
    """Manages memory, cache, and knowledge systems with M1 optimization."""

    def __init__(self, orchestrator: FullyAutonomousOrchestrator):
        self._orch = orchestrator
        self._memory: Optional[MemoryLayer] = None
        self._cache: Optional[IntelligentCache] = None
        self._rag: Optional[RAGEngine] = None
        # Sprint 28: Use PersistentKnowledgeLayer instead of AtomicJSONKnowledgeGraph
        self._knowledge_graph: Optional[PersistentKnowledgeLayer] = None
        self._context_graph: Optional[ContextGraph] = None
        self._initialized = False
        self._use_persistent_layer = True  # Sprint 28: fallback flag

    async def initialize(self) -> None:
        """Lazy initialize memory components."""
        if self._initialized:
            return

        self._cache = IntelligentCache()
        await self._cache.initialize()

        # Sprint 28: Use PersistentKnowledgeLayer (unified graph storage)
        if self._use_persistent_layer:
            db_path = getattr(self._orch.config.storage, 'knowledge_graph_path', None) if hasattr(self._orch.config, 'storage') else None
            self._knowledge_graph = PersistentKnowledgeLayer(
                db_path=db_path,
                enable_cache=False  # Disable cache for M1 8GB
            )
            self._knowledge_graph.initialize()
        else:
            # Legacy: AtomicJSONKnowledgeGraph (deprecated)
            # self._knowledge_graph = AtomicJSONKnowledgeGraph()
            # await self._knowledge_graph.initialize()
            pass

        self._context_graph = ContextGraph()

        self._rag = RAGEngine()
        await self._rag.initialize()

        self._memory = MemoryLayer(self._orch.config.memory)
        await self._memory.initialize()

        self._initialized = True
        logger.info("✅ MemoryManager initialized")

    async def transition_state(self, old_state: OrchestratorState, new_state: OrchestratorState) -> None:
        """Handle state transition memory operations."""
        if self._memory and hasattr(self._memory, 'transition_state'):
            await self._memory.transition_state(old_state, new_state)

    async def aggressive_cleanup(self) -> None:
        """Aggressive memory cleanup for M1."""
        gc.collect()

        if MLX_AVAILABLE and mx:
            try:
                mx.eval([])
                # Sprint 8AE: prefer modern mx.clear_cache()
                if hasattr(mx, 'clear_cache'):
                    mx.clear_cache()
                elif hasattr(mx.metal, 'clear_cache'):
                    mx.metal.clear_cache()
            except Exception:
                pass  # MLX memory cleanup failure

        if self._memory and hasattr(self._memory, 'aggressive_cleanup'):
            try:
                self._memory.aggressive_cleanup()
            except Exception:
                pass  # Memory layer cleanup failure

    async def cleanup(self) -> None:
        """Cleanup all memory resources."""
        if self._cache:
            await self._cache.close()
        if self._memory:
            await self._memory.cleanup()
        await self.aggressive_cleanup()

    @property
    def memory(self) -> Optional[MemoryLayer]:
        return self._memory

    @property
    def cache(self) -> Optional[IntelligentCache]:
        return self._cache

    @property
    def rag(self) -> Optional[RAGEngine]:
        return self._rag

    @property
    def knowledge_graph(self) -> Optional[PersistentKnowledgeLayer]:
        return self._knowledge_graph

    @property
    def context_graph(self) -> Optional[ContextGraph]:
        return self._context_graph

    def add_evidence_packet_edge_ref(self, evidence_id: str, edge_id: str) -> bool:
        """
        Add edge reference to evidence packet graph_refs (with hard limit).

        Args:
            evidence_id: ID of evidence packet
            edge_id: ID of graph edge to add

        Returns:
            True if added, False if packet not found
        """
        try:
            packet = self._evidence_packet_storage.load_packet(evidence_id)
            if packet is None:
                return False
            packet.add_edge_ref(edge_id)
            return self._evidence_packet_storage.store_packet(evidence_id, packet)
        except Exception as e:
            logger.warning(f"[EVIDENCE PACKET] Failed to add edge ref: {e}")
            return False

    def load_evidence_packet(self, evidence_id: str):
        """
        Load evidence packet from disk (replay hook).

        Args:
            evidence_id: ID of evidence packet

        Returns:
            EvidencePacket or None
        """
        return self._evidence_packet_storage.load_packet(evidence_id)

    def get_stats(self) -> Dict[str, Any]:
        """Get memory statistics."""
        stats = {}
        if self._cache and hasattr(self._cache, 'get_stats'):
            stats['cache'] = self._cache.get_stats()
        if self._memory and hasattr(self._memory, 'get_current_state'):
            stats['memory_state'] = self._memory.get_current_state().value
        return stats


class _BrainManager:
    """Manages AI brains and decision engines."""

    def __init__(self, orchestrator: FullyAutonomousOrchestrator):
        self._orch = orchestrator
        self.decision_engine = DecisionEngine()
        self.hermes: Optional[Hermes3Engine] = None
        self._hermes_initialized = False
        # MoE Router
        self.moe_router: Optional['MoERouter'] = None  # Forward reference
        self._moe_initialized = False
        self.distillation_engine: Optional['DistillationEngine'] = None
        # Sprint 35: InferenceEngine for abductive reasoning
        self.inference_engine: Optional['InferenceEngine'] = None
        self._inference_initialized = False
        # Sprint 75: Adaptive inference profile
        self._profile = "full"  # full, no-draft, short-context
        self._profile_task: Optional[asyncio.Task] = None
        self._stop_profile = asyncio.Event()
        self._profile_lock = asyncio.Lock()
        self._coreml_classifier = None
        # Sprint 78: Prompt engineering
        self._prompt_bandit = None
        self._dspy_optimizer = None
        self._prompt_cache = PromptCache(max_entries=500)
        self._mlx_memory_pool = None

    async def initialize(self) -> None:
        """Initialize AI brains with lazy loading."""
        # Get sanitizer from orchestrator's security manager (centralized security)
        sanitize_callback = None
        if self._orch._security_mgr and hasattr(self._orch._security_mgr, 'sanitize_for_logs'):
            sanitize_callback = self._orch._security_mgr.sanitize_for_logs

        # Existující Hermes inicializace
        if MLX_AVAILABLE and not self._hermes_initialized:
            self.hermes = Hermes3Engine(sanitize_for_llm=sanitize_callback)
            await self.hermes.initialize()
            self._hermes_initialized = True
            logger.info("✅ BrainManager initialized (Hermes ready)")

        # MoE Router inicializace
        if not self._moe_initialized:
            try:
                from .brain.moe_router import MoERouter, MoERouterConfig

                config = MoERouterConfig(
                    expert_names=["osint", "security", "temporal", "graph", "synthesis"],
                    model_paths={
                        "osint": "mlx-community/Hermes-3-Llama-3.2-3B-4bit",
                        "security": "mlx-community/Hermes-3-Llama-3.2-3B-4bit",
                        "temporal": "mlx-community/Hermes-3-Llama-3.2-3B-4bit",
                        "graph": "mlx-community/Hermes-3-Llama-3.2-3B-4bit",
                        "synthesis": "mlx-community/Hermes-3-Llama-3.2-3B-4bit",
                    },
                    max_active_experts=2,  # M1 8GB limit
                    temperature=0.3,
                    max_tokens_per_expert=1024,
                )

                self.moe_router = MoERouter(config, sanitize_for_llm=sanitize_callback)
                await self.moe_router.initialize()
                self._moe_initialized = True
                logger.info("✅ MoE Router initialized (5 experts, max 2 active)")

            except Exception as e:
                logger.warning(f"MoE Router initialization failed: {e}")
                self.moe_router = None

        # Initialize distillation engine if enabled
        if self._orch.config.enable_distillation:
            _load_distillation()
            if DISTILLATION_AVAILABLE:
                try:
                    from .brain.distillation_engine import create_distillation_engine
                    self.distillation_engine = create_distillation_engine()
                    if self.distillation_engine:
                        await self.distillation_engine.initialize()
                        logger.info("✓ Distillation Engine initialized")
                except Exception as e:
                    logger.warning(f"Distillation Engine failed to initialize: {e}")

        # Sprint 35: Auto-wire InferenceEngine if enough free RAM
        try:
            import psutil
            free_gb = psutil.virtual_memory().available / (1024**3)
        except ImportError:
            free_gb = 0  # fallback – neinicializovat

        if free_gb > 2.0 and not self._inference_initialized:
            try:
                from .brain.inference_engine import InferenceEngine
                self.inference_engine = InferenceEngine()  # __init__ only, no async initialize
                self._inference_initialized = True
                logger.info(f"✅ InferenceEngine auto-wired (free RAM: {free_gb:.1f} GB)")
            except Exception as e:
                logger.warning(f"InferenceEngine wiring failed: {e}")

        # Sprint 75: Start adaptive profile manager
        await self.start_profile_manager()

        # Sprint 78: Initialize MLX memory pool
        await self._init_mlx_memory_pool()

        # Sprint 78: Initialize bandit
        self._prompt_bandit = PromptBandit(brain_manager=self, alpha=1.0, lambda_reg=0.01)

        # Sprint 78: Initialize DSPy optimizer (only if enough RAM)
        try:
            import psutil
            available_gb = psutil.virtual_memory().available / (1024**3)
            if available_gb > 4.0:
                self._dspy_optimizer = DSPyOptimizer(self)
                await self._dspy_optimizer.start()
                logger.info("✅ DSPy optimizer initialized")
            else:
                logger.info(f"[DSPy] Skipped - insufficient RAM ({available_gb:.1f}GB available)")
        except ImportError:
            logger.debug("DSPy not available, prompt optimization disabled")

    async def start_profile_manager(self) -> None:
        """Start adaptive inference profile manager (Sprint 75)."""
        self._profile_task = asyncio.create_task(self._profile_manager(), name="profile_manager")
        if hasattr(self._orch, '_bg_tasks'):
            self._orch._bg_tasks.add(self._profile_task)
        logger.info("[PROFILE] Profile manager started")

    async def _profile_manager(self) -> None:
        """Manage adaptive inference profile based on memory and thermal state."""
        from .coordinators.memory_coordinator import ThermalState

        while not self._stop_profile.is_set():
            await asyncio.sleep(60)
            try:
                import psutil
                available_gb = psutil.virtual_memory().available / (1024**3)

                # Get thermal state (S73)
                thermal = ThermalState.NORMAL
                if hasattr(self._orch, '_memory_mgr') and self._orch._memory_mgr:
                    try:
                        thermal = self._orch._memory_mgr.get_thermal_state()
                    except Exception:
                        pass

                async with self._profile_lock:
                    old = self._profile
                    if available_gb < 2.5 or thermal in (ThermalState.HOT, ThermalState.CRITICAL):
                        self._profile = "short-context"
                    elif available_gb < 3.5:
                        self._profile = "no-draft"
                    else:
                        self._profile = "full"

                    if old != self._profile:
                        logger.info(f"[PROFILE] {old} -> {self._profile} (mem={available_gb:.1f}GB, thermal={thermal.name})")
                        await self._apply_profile()

                        # Audit log to evidence_log
                        if hasattr(self._orch, '_evidence_log') and self._orch._evidence_log:
                            try:
                                self._orch._evidence_log.create_event("profile_change", {
                                    "from": old,
                                    "to": self._profile,
                                    "available_gb": round(available_gb, 2),
                                    "thermal": thermal.name
                                })
                            except Exception:
                                pass
            except Exception as e:
                logger.debug(f"[PROFILE] Manager error: {e}")

    async def _apply_profile(self) -> None:
        """Apply the current inference profile."""
        hermes = self.hermes
        if not hermes or not hasattr(hermes, '_speculative_enabled'):
            return

        try:
            async with self._profile_lock:
                if self._profile == "no-draft":
                    hermes._speculative_enabled = False
                    if hermes._draft_model_obj:
                        hermes._draft_model_obj = None
                        import gc
                        gc.collect()
                        clear_mlx_cache()
                elif self._profile == "short-context":
                    hermes._speculative_enabled = False
                    hermes._max_context_tokens = 2048
                    if hermes._draft_model_obj:
                        hermes._draft_model_obj = None
                else:  # full
                    hermes._speculative_enabled = True
                    if hasattr(hermes, '_max_context_tokens'):
                        hermes._max_context_tokens = 8192
        except Exception as e:
            logger.warning(f"[PROFILE] Apply failed: {e}")

    async def stop_profile_manager(self, timeout: float = 2.0) -> None:
        """Stop adaptive profile manager (Sprint 75)."""
        self._stop_profile.set()
        if self._profile_task:
            try:
                await asyncio.wait_for(self._profile_task, timeout=timeout)
            except asyncio.TimeoutError:
                self._profile_task.cancel()
                try:
                    await self._profile_task
                except asyncio.CancelledError:
                    pass
        logger.info("[PROFILE] Profile manager stopped")

    def _get_mlx_memory_usage(self) -> dict:
        """Get MLX memory usage (Sprint 75)."""
        try:
            import mlx.core as mx
            # Sprint 8AE: prefer top-level mx API first, then metal fallback
            if hasattr(mx, 'get_active_memory'):
                active = mx.get_active_memory()
                peak = mx.get_peak_memory() if hasattr(mx, 'get_peak_memory') else 0
            elif hasattr(mx.metal, 'get_active_memory'):
                active = mx.metal.get_active_memory()
                peak = mx.metal.get_peak_memory() if hasattr(mx.metal, 'get_peak_memory') else 0
            else:
                return {'active_mb': 0, 'peak_mb': 0}
            return {'active_mb': active / (1024**2), 'peak_mb': peak / (1024**2)}
        except Exception:
            return {'active_mb': 0, 'peak_mb': 0}

    async def _init_mlx_memory_pool(self):
        """Pre-allocate MLX memory pool to reduce fragmentation (Sprint 78)."""
        try:
            import mlx.core as mx
            import psutil
            available_gb = psutil.virtual_memory().available / (1024**3)
            pool_size_mb = min(256, int(available_gb * 64))  # scale with available RAM
            self._mlx_memory_pool = mx.zeros((pool_size_mb * 1024 * 1024 // 4,), dtype=mx.float32)
            logger.info(f"[MLX] Pre-allocated {pool_size_mb}MB memory pool")
        except Exception as e:
            logger.debug(f"[MLX] Pool allocation failed: {e}")
            self._mlx_memory_pool = None

    async def cleanup(self) -> None:
        """Cleanup brain resources."""
        # Sprint 75: Stop profile manager
        await self.stop_profile_manager()

        # Sprint 78: Cleanup DSPy optimizer
        if self._dspy_optimizer:
            await self._dspy_optimizer.stop()
        # Sprint 78: Save bandit state
        if self._prompt_bandit:
            await self._prompt_bandit.final_save()

        # Sprint 35: Hermes cleanup
        if self.hermes:
            try:
                await self.hermes.unload()
                self.hermes = None
                self._hermes_initialized = False
                logger.info("✅ Hermes unloaded")
            except Exception as e:
                logger.warning(f"Hermes cleanup failed: {e}")

        if self.moe_router:
            try:
                await self.moe_router.cleanup()
                logger.info("✅ MoE Router cleaned up")
            except Exception as e:
                logger.warning(f"MoE Router cleanup failed: {e}")

        # Sprint 35: InferenceEngine cleanup
        if self.inference_engine:
            try:
                await self.inference_engine.cleanup()
                self.inference_engine = None
                self._inference_initialized = False
                logger.info("✅ InferenceEngine cleaned up")
            except Exception as e:
                logger.warning(f"InferenceEngine cleanup failed: {e}")

    async def generate(self, system_prompt: str, user_prompt: str, max_tokens: int = 4096) -> str:
        """Generate text using Hermes."""
        if not self.hermes:
            raise RuntimeError("Hermes not available")

        if hasattr(self.hermes, 'generate'):
            if inspect.iscoroutinefunction(self.hermes.generate):
                return await self.hermes.generate(user_prompt, system_msg=system_prompt, max_tokens=max_tokens)
            else:
                return self.hermes.generate(user_prompt, system_msg=system_prompt, max_tokens=max_tokens)

        raise RuntimeError("Hermes generate method not available")


class _SecurityManager:
    """Manages security, privacy, and stealth operations."""

    # Constants for bounded operations
    MAX_SANITIZE_LENGTH = 8192
    MAX_ANALYSIS_LENGTH = 12288
    MAX_DECODED_PREVIEW = 512
    MAX_GHOST_URLS_PER_RUN = 1
    MAX_GHOST_MEMENTOS_PER_URL = 3
    MAX_STEGO_SIZE = 256 * 1024  # 256KB
    # High-confidence PII categories only (not USERNAME/DATE/URL which are overly broad)
    ALLOWED_PII_CATEGORIES = {'EMAIL', 'PHONE', 'SSN', 'CREDIT_CARD', 'IP_ADDRESS', 'PASSPORT', 'DRIVER_LICENSE', 'ADDRESS'}

    def __init__(self, orchestrator: FullyAutonomousOrchestrator):
        self._orch = orchestrator
        self._security: Optional[SecurityLayer] = None
        self._stealth: Optional[StealthLayer] = None
        self._privacy: Optional[PrivacyLayer] = None
        self._privacy_mgr: Optional[Any] = None
        self._deep_security: Optional[Any] = None
        self._obfuscator: Optional[Any] = None
        # New security pipeline components
        self._pii_gate: Optional[Any] = None
        self._pii_fallback_used: bool = False  # Track if fallback was used (for ledger event)
        self._unicode: Optional[Any] = None
        self._encoding: Optional[Any] = None
        self._hash_id: Optional[Any] = None
        self._ghost: Optional[Any] = None
        self._stego: Optional[Any] = None
        self._destructor: Optional[Any] = None
        self._net_breaker: Optional[Any] = None
        self._model_breaker: Optional[Any] = None
        self._initialized = False
        # Sprint 41: Tool registry for DNS tunnel detection
        self._tool_registry = ToolRegistry()

    async def initialize(self) -> None:
        """Initialize security components with lazy loading."""
        if self._initialized:
            return

        # Core layers
        if self._orch.config.enable_security_layer:
            self._security = SecurityLayer(self._orch.config.security)
            await self._security.initialize()

        if self._orch.config.enable_stealth_layer:
            self._stealth = StealthLayer(self._orch.config.stealth)
            await self._stealth.initialize()

        if self._orch.config.enable_privacy_layer:
            self._privacy = PrivacyLayer(self._orch.config.privacy)
            await self._privacy.initialize()

        # Optional components
        _load_privacy_mgr()
        if PRIVACY_MGR_AVAILABLE and PersonalPrivacyManager:
            self._privacy_mgr = PersonalPrivacyManager()
            if hasattr(self._privacy_mgr, 'initialize'):
                await self._privacy_mgr.initialize()

        _load_deep_sec()
        if DEEP_SEC_AVAILABLE and DeepResearchSecurity:
            self._deep_security = DeepResearchSecurity()
            if hasattr(self._deep_security, 'initialize'):
                await self._deep_security.initialize()

        _load_obfuscator()
        if OBFS_AVAILABLE and ResearchObfuscator:
            self._obfuscator = ResearchObfuscator()

        # Initialize new security pipeline components (lazy, no user toggles)
        await self._initialize_security_pipeline()

        self._initialized = True
        logger.info("✅ SecurityManager initialized")

    async def _initialize_security_pipeline(self) -> None:
        """Initialize the security & text safety pipeline components."""
        import hashlib

        # PII Gate
        _load_pii_gate()
        if PII_GATE_AVAILABLE and SecurityGate:
            try:
                from .security.pii_gate import create_security_gate
                self._pii_gate = create_security_gate()
                logger.info("PII Gate initialized")
            except Exception as e:
                logger.warning(f"PII Gate init failed: {e}")

        # Unicode Analyzer
        _load_unicode_analyzer()
        if UNICODE_ANALYZER_AVAILABLE and UnicodeAttackAnalyzer:
            try:
                from .text.unicode_analyzer import create_unicode_analyzer
                config = UnicodeConfig(
                    detect_bidi=True,
                    detect_zero_width=True,
                    detect_homoglyphs=True,
                    detect_mixed_script=True,
                    max_findings=50
                )
                self._unicode = create_unicode_analyzer(config)
                logger.info("Unicode Analyzer initialized")
            except Exception as e:
                logger.warning(f"Unicode Analyzer init failed: {e}")

        # Encoding detector (reuse from ForensicsManager if available)
        _load_encoding_detector()
        if ENCODING_DETECTOR_AVAILABLE and BaseEncodingDetector:
            try:
                from .text.encoding_detector import EncodingConfig
                config = EncodingConfig(
                    min_length=16,
                    detect_nested=True,
                    max_depth=3,
                    chunk_size=4096
                )
                self._encoding = BaseEncodingDetector(config)
                logger.info("Encoding Detector initialized")
            except Exception as e:
                logger.warning(f"Encoding Detector init failed: {e}")

        # Hash Identifier (reuse from ForensicsManager if available)
        _load_hash_identifier()
        if HASH_IDENTIFIER_AVAILABLE and HashIdentifier:
            try:
                from .text.hash_identifier import HashConfig
                config = HashConfig(
                    min_confidence=0.7,
                    top_k_results=3,
                    detect_salted=False,
                    batch_size=32
                )
                self._hash_id = HashIdentifier(config)
                logger.info("Hash Identifier initialized")
            except Exception as e:
                logger.warning(f"Hash Identifier init failed: {e}")

        # Digital Ghost Detector
        _load_digital_ghost_detector()
        if DIGITAL_GHOST_AVAILABLE and DigitalGhostDetector:
            try:
                self._ghost = DigitalGhostDetector()
                logger.info("Digital Ghost Detector initialized")
            except Exception as e:
                logger.warning(f"Digital Ghost Detector init failed: {e}")

        # Stego Detector
        _load_stego_detector()
        if STEGO_DETECTOR_AVAILABLE and StatisticalStegoDetector:
            try:
                config = StegoConfig(
                    chi_square_enabled=True,
                    rs_enabled=True,
                    dct_enabled=True,
                    max_image_size=self.MAX_STEGO_SIZE
                )
                self._stego = StatisticalStegoDetector(config)
                logger.info("Stego Detector initialized")
            except Exception as e:
                logger.warning(f"Stego Detector init failed: {e}")

        # Secure Destructor
        _load_destruction()
        if DESTRUCTION_AVAILABLE and SecureDestructor:
            try:
                config = DestructionConfig(
                    method='gutmann',  # Secure default
                    verify=True
                )
                self._destructor = SecureDestructor(config)
                logger.info("Secure Destructor initialized")
            except Exception as e:
                logger.warning(f"Secure Destructor init failed: {e}")

        # Circuit Breakers
        _load_circuit_breaker()
        if CIRCUIT_BREAKER_AVAILABLE and CircuitBreaker:
            try:
                # Network breaker - conservative settings
                self._net_breaker = CircuitBreaker(
                    failure_threshold=5,
                    recovery_timeout=30.0,
                    expected_exception=Exception
                )
                # Model breaker - for heavy operations
                self._model_breaker = CircuitBreaker(
                    failure_threshold=3,
                    recovery_timeout=60.0,
                    expected_exception=Exception
                )
                logger.info("Circuit Breakers initialized")
            except Exception as e:
                logger.warning(f"Circuit Breaker init failed: {e}")

    async def cleanup(self) -> None:
        """Cleanup security resources."""
        if self._privacy_mgr and hasattr(self._privacy_mgr, 'cleanup'):
            await self._privacy_mgr.cleanup()
        if self._deep_security and hasattr(self._deep_security, 'cleanup'):
            await self._deep_security.cleanup()

