@dataclass
class Checkpoint:
    """Checkpoint pro resume deep crawlu napříč běhy."""
    run_id: str
    timestamp: float
    frontier_data: List[Dict[str, Any]]
    visited_hashes: List[str]  # Bloom filter approximation
    domain_cooldowns: Dict[str, float]  # domain -> last_request_at
    processed_count: int
    url_count: int
    host_penalties: Dict[str, float] = field(default_factory=dict)  # host -> penalty
    microplan_head: List[Dict[str, Any]] = field(default_factory=list)  # microplan queue head

    def to_dict(self) -> Dict[str, Any]:
        return {
            'run_id': self.run_id,
            'timestamp': self.timestamp,
            'frontier_data': self.frontier_data,
            'visited_hashes': self.visited_hashes,
            'domain_cooldowns': self.domain_cooldowns,
            'processed_count': self.processed_count,
            'url_count': self.url_count,
            'host_penalties': self.host_penalties,
            'microplan_head': self.microplan_head
        }

    @classmethod
    def from_dict(cls, data: Dict[str, Any]) -> 'Checkpoint':
        return cls(
            run_id=data['run_id'],
            timestamp=data['timestamp'],
            frontier_data=data.get('frontier_data', []),
            visited_hashes=data.get('visited_hashes', []),
            domain_cooldowns=data.get('domain_cooldowns', {}),
            processed_count=data.get('processed_count', 0),
            url_count=data.get('url_count', 0),
            host_penalties=data.get('host_penalties', {}),
            microplan_head=data.get('microplan_head', [])
        )


class CheckpointManager:
    """Spravuje checkpointy pro deep crawl."""

    def __init__(self, storage_dir: Optional[Path] = None, encrypt_at_rest: bool = False):
        import os

        self._storage_dir = storage_dir or Path.home() / '.hledac' / 'checkpoints'
        self._storage_dir.mkdir(parents=True, exist_ok=True)

        # Encryption setup
        self._encrypt_at_rest = encrypt_at_rest or os.environ.get('ENCRYPT_AT_REST', '0') == '1'
        self._encryption_key = os.environ.get('ENCRYPTION_KEY', '').encode() if self._encrypt_at_rest else None

        if self._encrypt_at_rest:
            logger.info("[ENCRYPT] enabled=True target=checkpoint")
            self._init_encryption()
        else:
            self._cipher = None

    def _init_encryption(self):
        """Initialize encryption cipher."""
        if not self._encryption_key:
            import secrets
            self._encryption_key = secrets.token_bytes(32)

        try:
            from cryptography.hazmat.primitives.ciphers import Cipher, algorithms, modes
            self._cipher = (Cipher, algorithms, modes)
        except ImportError:
            logger.warning("[ENCRYPT] cryptography not available")
            self._encrypt_at_rest = False
            self._cipher = None

    def _get_checkpoint_path(self, run_id: str) -> Path:
        ext = '.enc' if self._encrypt_at_rest else '.json'
        return self._storage_dir / f"checkpoint_{run_id}{ext}"

    def _bound_host_penalties(self, obj: Dict[str, Any]) -> Dict[str, Any]:
        """
        Bound host_penalties dict to MAX_HOST_PENALTIES entries.
        Keeps top-K highest penalties.
        """
        hp = obj.get("host_penalties")
        if not isinstance(hp, dict):
            return obj
        if len(hp) <= MAX_HOST_PENALTIES:
            return obj

        # Convert to list of (penalty, host) tuples
        items = []
        for k, v in hp.items():
            try:
                host = str(k)[:MAX_HOST_LEN]
                pen = float(v)
                if pen < 0.0:
                    pen = 0.0
                items.append((pen, host))
            except (ValueError, TypeError):
                continue

        # Sort by penalty descending, keep top K
        items.sort(key=lambda t: t[0], reverse=True)
        bounded = {host: pen for pen, host in items[:MAX_HOST_PENALTIES]}

        logger.debug(f"Bounded host_penalties from {len(hp)} to {len(bounded)} entries")
        return {**obj, "host_penalties": bounded}

    def save_checkpoint(self, checkpoint: Checkpoint) -> bool:
        """Uloží checkpoint na disk."""
        try:
            path = self._get_checkpoint_path(checkpoint.run_id)
            # Bound host_penalties BEFORE first json.dumps
            obj = checkpoint.to_dict()
            obj = self._bound_host_penalties(obj)
            data = json.dumps(obj).encode('utf-8')
            bytes_in = len(data)

            if self._encrypt_at_rest and self._cipher:
                try:
                    import secrets
                    from cryptography.hazmat.primitives.ciphers import Cipher, algorithms, modes

                    nonce = secrets.token_bytes(12)
                    cipher = Cipher(algorithms.AES(self._encryption_key), modes.GCM(nonce))
                    encryptor = cipher.encryptor()
                    encrypted = encryptor.update(data) + encryptor.finalize()
                    data = nonce + encryptor.tag + encrypted
                    logger.debug(f"[ENCRYPT] stored bytes_in={bytes_in} bytes_out={len(data)}")
                except Exception as e:
                    logger.warning(f"[ENCRYPT] failed: {e}")

            with open(path, 'wb') as f:
                f.write(data)
            logger.info(f"[CHECKPOINT] Saved for run {checkpoint.run_id}: "
                       f"{checkpoint.url_count} URLs, {checkpoint.processed_count} processed")
            return True
        except Exception as e:
            logger.error(f"[CHECKPOINT] Failed to save: {e}")
            return False

    def load_checkpoint(self, run_id: str) -> Optional[Checkpoint]:
        """Načte checkpoint z disku."""
        try:
            path = self._get_checkpoint_path(run_id)
            if not path.exists():
                return None

            with open(path, 'rb') as f:
                data = f.read()

            # Decrypt if needed
            if self._encrypt_at_rest and self._cipher and len(data) > 28:
                try:
                    from cryptography.hazmat.primitives.ciphers import Cipher, algorithms, modes

                    nonce = data[:12]
                    tag = data[12:28]
                    ciphertext = data[28:]
                    cipher = Cipher(algorithms.AES(self._encryption_key), modes.GCM(nonce, tag))
                    decryptor = cipher.decryptor()
                    data = decryptor.update(ciphertext) + decryptor.finalize()
                except Exception as e:
                    logger.warning(f"[ENCRYPT] decrypt failed: {e}")

            checkpoint_data = json.loads(data.decode('utf-8'))
            checkpoint = Checkpoint.from_dict(checkpoint_data)
            logger.info(f"[CHECKPOINT] Loaded for run {run_id}: "
                       f"{checkpoint.url_count} URLs, {checkpoint.processed_count} processed")
            return checkpoint
        except Exception as e:
            logger.error(f"[CHECKPOINT] Failed to load: {e}")
            return None

    def list_checkpoints(self) -> List[str]:
        """Vrátí seznam dostupných checkpoint run_id."""
        try:
            return [p.stem.replace('checkpoint_', '')
                    for p in self._storage_dir.glob('checkpoint_*.json')]
        except Exception:
            return []


