# M1 8GB: Temporal Recrawl Planner
# =============================================================================

@dataclass
class RecrawlItem:
    """Položka v recrawl queue."""
    url: str
    evidence_id: str
    priority: float
    last_crawled_at: float
    content_hash: Optional[str] = None
    drift_detected: bool = False
    contested: bool = False
    high_value: bool = False

    def __lt__(self, other: 'RecrawlItem') -> bool:
        return self.priority > other.priority  # Higher priority first


class RecrawlPlanner:
    """Plánuje recrawl na základě drift/contested/high-value."""

    def __init__(self, max_queue_size: int = 100):
        self._heap: List[RecrawlItem] = []
        self._url_to_item: Dict[str, RecrawlItem] = {}
        self._max_queue_size = max_queue_size

    def schedule_recheck(
        self,
        url: str,
        evidence_id: str,
        last_crawled_at: float,
        content_hash: Optional[str] = None,
        drift_detected: bool = False,
        contested: bool = False,
        high_value: bool = False
    ) -> bool:
        """Přidá URL do recrawl queue."""
        if url in self._url_to_item:
            return False

        # Priority calculation
        priority = 0.0
        if contested:
            priority += 1.0
        if drift_detected:
            priority += 0.7
        if high_value:
            priority += 0.5

        # Recency decay (older = higher priority)
        age_hours = (time.time() - last_crawled_at) / 3600
        priority += min(0.3, age_hours / 168)  # Max +0.3 after 1 week

        item = RecrawlItem(
            url=url,
            evidence_id=evidence_id,
            priority=priority,
            last_crawled_at=last_crawled_at,
            content_hash=content_hash,
            drift_detected=drift_detected,
            contested=contested,
            high_value=high_value
        )

        heappush(self._heap, item)
        self._url_to_item[url] = item

        # Evict lowest priority if over limit
        while len(self._heap) > self._max_queue_size:
            evicted = heappop(self._heap)
            self._url_to_item.pop(evicted.url, None)

        return True

    def pop_next(self) -> Optional[RecrawlItem]:
        """Vrátí další URL k rechecku."""
        while self._heap:
            item = heappop(self._heap)
            if item.url in self._url_to_item:
                del self._url_to_item[item.url]
                return item
        return None

    def __len__(self) -> int:
        return len(self._heap)


# =============================================================================
# M1 8GB: DomainStats pro yield-based learning napříč běhy
# =============================================================================

@dataclass
class DomainStats:
    """Per-domain statistiky pro yield tracking a domain diversity."""
    domain: str
    requests: int = 0
    new_docs: int = 0
    dedup_hits: int = 0
    total_latency_ms: float = 0.0
    http_errors: int = 0
    robots_blocked: int = 0
    last_request_at: Optional[float] = None
    yield_score: float = 1.0  # 0-1, klesá při nízkém yieldu

    @property
    def avg_latency_ms(self) -> float:
        if self.requests == 0:
            return 0.0
        return self.total_latency_ms / self.requests

    def record_request(self, latency_ms: float, is_new: bool, is_dedup: bool = False,
                       is_error: bool = False, blocked_by_robots: bool = False):
        """Zaznamená výsledek requestu a aktualizuje yield."""
        self.requests += 1
        self.total_latency_ms += latency_ms
        self.last_request_at = time.time()

        if is_error:
            self.http_errors += 1
        if blocked_by_robots:
            self.robots_blocked += 1
        if is_dedup:
            self.dedup_hits += 1
        if is_new:
            self.new_docs += 1

        # Yield = ratio nových dokumentů k requestům (s decay)
        if self.requests > 0:
            raw_yield = self.new_docs / self.requests
            # Penalizace pro domény s mnoha chybami
            error_penalty = min(0.5, self.http_errors / max(1, self.requests))
            self.yield_score = max(0.1, raw_yield - error_penalty)


class DomainStatsManager:
    """Spravuje DomainStats s persistencí na disk."""

    def __init__(self, storage_dir: Optional[Path] = None, max_domains: int = 500):
        self._storage_dir = storage_dir or Path.home() / '.hledac' / 'domain_stats'
        self._storage_dir.mkdir(parents=True, exist_ok=True)
        self._max_domains = max_domains
        self._stats: Dict[str, DomainStats] = {}
        self._load_stats()

    def _get_storage_path(self) -> Path:
        return self._storage_dir / 'domain_stats.json'

    def _load_stats(self) -> None:
        """Načte statistiky z disku."""
        path = self._get_storage_path()
        if path.exists():
            try:
                with open(path, 'r') as f:
                    data = json.load(f)
                for domain, stats_data in data.items():
                    self._stats[domain] = DomainStats(**stats_data)
                logger.info(f"[DOMAIN STATS] Loaded {len(self._stats)} domains from disk")
            except Exception as e:
                logger.warning(f"Failed to load domain stats: {e}")

    def save_stats(self) -> None:
        """Uloží statistiky na disk."""
        try:
            path = self._get_storage_path()
            data = {}
            for domain, stats in self._stats.items():
                data[domain] = {
                    'domain': stats.domain,
                    'requests': stats.requests,
                    'new_docs': stats.new_docs,
                    'dedup_hits': stats.dedup_hits,
                    'total_latency_ms': stats.total_latency_ms,
                    'http_errors': stats.http_errors,
                    'robots_blocked': stats.robots_blocked,
                    'last_request_at': stats.last_request_at,
                    'yield_score': stats.yield_score
                }
            with open(path, 'w') as f:
                json.dump(data, f)
            logger.debug(f"[DOMAIN STATS] Saved {len(self._stats)} domains to disk")
        except Exception as e:
            logger.warning(f"Failed to save domain stats: {e}")

    def get_stats(self, domain: str) -> DomainStats:
        """Vrátí statistiky pro doménu (vytvoří nové pokud neexistují)."""
        if domain not in self._stats:
            # Evict nejstarší pokud jsme nad limitem
            if len(self._stats) >= self._max_domains:
                oldest = min(self._stats.items(), key=lambda x: x[1].last_request_at or 0)
                del self._stats[oldest[0]]
            self._stats[domain] = DomainStats(domain=domain)
        return self._stats[domain]

    def get_yield_penalty(self, domain: str) -> float:
        """Vrátí yield-based penalty pro doménu (0-1, vyšší = více penalizace)."""
        stats = self.get_stats(domain)
        # Cooldown pro domény s nízkým yieldem
        if stats.yield_score < 0.2:
            return 0.5  # 50% penalty
        if stats.yield_score < 0.5:
            return 0.2  # 20% penalty
        return 0.0

    def get_all_stats(self) -> Dict[str, DomainStats]:
        return dict(self._stats)


# =============================================================================
# M1 8GB: DomainLimiter - Per-domain throttling and concurrency control
# =============================================================================

@dataclass
class _DomainState:
    """Lightweight per-domain state for throttling."""
    next_allowed_ts: float = 0.0
    concurrency_limit: int = 2
    in_flight: int = 0
    consecutive_errors: int = 0
    last_latency_ms: float = 0.0
    yield_score: float = 1.0
    last_status: int = 200


class TimingProfile(Enum):
    """Behavior timing profiles for stealth."""
    FAST = "fast"      # Minimal jitter
    NORMAL = "normal"  # Balanced
    CAREFUL = "careful"  # Maximum stealth


class DomainLimiter:
    """
    Per-domain rate limiter with adaptive concurrency and backoff.

    M1 8GB Optimized:
    - Lightweight state (no unbounded growth)
    - Automatic cleanup of stale domains
    - No heavy data structures
    - Integrated behavior jitter for stealth
    """

    # Hard caps
    MAX_CONCURRENCY = 3
    DEFAULT_CONCURRENCY = 2
    MIN_CONCURRENCY = 1

    # Timing constants
    BASE_JITTER = 0.1
    MAX_JITTER = 0.5
    ERROR_BACKOFF_BASE = 2.0
    HIGH_LATENCY_THRESHOLD_MS = 2000
    LOW_YIELD_THRESHOLD = 0.1

    # Behavior jitter limits (hard caps)
    JITTER_LIMITS = {
        TimingProfile.FAST: (0.05, 0.3),      # 0.05-0.3s extra
        TimingProfile.NORMAL: (0.1, 0.8),     # 0.1-0.8s extra
        TimingProfile.CAREFUL: (0.5, 1.5),   # 0.5-1.5s extra
    }

    def __init__(self, max_domains: int = 500, timing_profile: TimingProfile = TimingProfile.NORMAL):
        self._max_domains = max_domains
        self._domains: Dict[str, _DomainState] = {}
        self._lock = asyncio.Lock()
        self._timing_profile = timing_profile
        # Seedable RNG for deterministic behavior in tests
        self._rng_seed: Optional[int] = None

    def set_timing_profile(self, profile: TimingProfile) -> None:
        """Set timing profile for behavior simulation."""
        self._timing_profile = profile

    def set_rng_seed(self, seed: int) -> None:
        """Set RNG seed for deterministic jitter (for testing)."""
        self._rng_seed = seed
        import random
        random.seed(seed)

    def _compute_behavior_jitter(self, domain: str) -> float:
        """
        Compute behavior jitter based on timing profile.

        Returns jitter in seconds (deterministic if seed set).
        """
        import random
        min_jitter, max_jitter = self.JITTER_LIMITS[self._timing_profile]

        # Use domain as seed component for determinism
        if self._rng_seed is not None:
            # Deterministic: hash domain + seed
            seed_component = (hash(domain) + self._rng_seed) % 10000
            random.seed(seed_component)

        jitter = random.uniform(min_jitter, max_jitter)
        return jitter

    def _get_or_create_state(self, domain: str) -> _DomainState:
        """Get or create domain state with automatic cleanup."""
        if domain not in self._domains:
            # Cleanup if at limit (remove oldest by next_allowed_ts)
            if len(self._domains) >= self._max_domains:
                oldest = min(
                    self._domains.items(),
                    key=lambda x: x[1].next_allowed_ts
                )
                del self._domains[oldest[0]]
                logger.debug(f"[THROTTLE] Evicted stale domain: {oldest[0]}")
            self._domains[domain] = _DomainState()
        return self._domains[domain]

    def compute_delay(self, domain: str, now_ts: float) -> float:
        """
        Compute required delay for domain (does NOT sleep).

        Returns:
            float: Seconds to wait (0.0 if no delay needed)
        """
        state = self._get_or_create_state(domain)
        delay = max(0.0, state.next_allowed_ts - now_ts)

        if delay > 0:
            logger.debug(
                f"[THROTTLE] domain={domain} delay={delay:.2f}s "
                f"inflight={state.in_flight} limit={state.concurrency_limit} "
                f"reason=rate_limited"
            )
        return delay

    def compute_final_delay(self, domain: str, now_ts: Optional[float] = None) -> Tuple[float, float]:
        """
        Compute final delay including behavior jitter.

        Returns:
            Tuple of (base_delay, jitter)
        """
        if now_ts is None:
            now_ts = time.time()

        base_delay = self.compute_delay(domain, now_ts)
        behavior_jitter = self._compute_behavior_jitter(domain)

        # Log the timing
        logger.info(
            f"[TIMING] domain={domain} base={base_delay:.3f}s jitter={behavior_jitter:.3f}s "
            f"final={base_delay + behavior_jitter:.3f}s profile={self._timing_profile.value}"
        )

        return base_delay, behavior_jitter

    def on_response(
        self,
        domain: str,
        status: int,
        retry_after: Optional[float] = None,
        latency_ms: float = 0.0,
        robots_delay: float = 0.0
    ) -> None:
        """
        Update internal state based on response.

        Args:
            domain: Target domain
            status: HTTP status code
            retry_after: Retry-After header value in seconds
            latency_ms: Request latency in milliseconds
            robots_delay: robots.txt crawl-delay in seconds
        """
        state = self._get_or_create_state(domain)
        now = time.time()

        state.last_status = status
        state.last_latency_ms = latency_ms

        # Calculate dynamic delay
        dynamic_delay = self._compute_dynamic_delay(state, latency_ms)

        if status == 429 and retry_after is not None:
            # Rate limited - respect Retry-After with jitter
            jitter = self.BASE_JITTER + (hash(domain) % 100) / 100 * (self.MAX_JITTER - self.BASE_JITTER)
            state.next_allowed_ts = now + retry_after + jitter
            state.consecutive_errors += 1
            state.concurrency_limit = max(self.MIN_CONCURRENCY, state.concurrency_limit - 1)
            self._log_throttle(domain, state, "rate_limit_429")

        elif 500 <= status < 600:
            # Server error - exponential backoff
            state.consecutive_errors += 1
            backoff = self.ERROR_BACKOFF_BASE ** min(state.consecutive_errors, 5)
            state.next_allowed_ts = now + backoff
            state.concurrency_limit = max(self.MIN_CONCURRENCY, state.concurrency_limit - 1)
            self._log_throttle(domain, state, f"server_error_{status}")

        elif status >= 400:
            # Client error - moderate backoff
            state.consecutive_errors += 1
            state.next_allowed_ts = now + 1.0
            self._log_throttle(domain, state, f"client_error_{status}")

        else:
            # Success - reset error count, adjust based on performance
            state.consecutive_errors = max(0, state.consecutive_errors - 1)

            # Base delay from robots or dynamic calculation
            base_delay = max(robots_delay, dynamic_delay)
            state.next_allowed_ts = now + base_delay

            # Adjust concurrency based on yield score and latency
            if state.yield_score < self.LOW_YIELD_THRESHOLD:
                state.concurrency_limit = self.MIN_CONCURRENCY
                state.next_allowed_ts += 5.0  # Extra cooldown for low yield
                self._log_throttle(domain, state, "low_yield_cooldown")
            elif latency_ms > self.HIGH_LATENCY_THRESHOLD_MS:
                state.concurrency_limit = max(self.MIN_CONCURRENCY, state.concurrency_limit - 1)
                self._log_throttle(domain, state, "high_latency")
            elif state.yield_score > 0.8 and state.consecutive_errors == 0:
                # High yield domain - can increase concurrency
                state.concurrency_limit = min(self.MAX_CONCURRENCY, state.concurrency_limit + 1)
                self._log_throttle(domain, state, "high_yield_boost")
            else:
                self._log_throttle(domain, state, "normal")

    def _compute_dynamic_delay(self, state: _DomainState, latency_ms: float) -> float:
        """Compute dynamic delay based on latency and error history."""
        # Base delay scales with latency (be polite to slow servers)
        base = min(1.0, latency_ms / 1000.0 * 0.5)

        # Error penalty
        error_penalty = state.consecutive_errors * 0.5

        return base + error_penalty

    def _log_throttle(self, domain: str, state: _DomainState, reason: str) -> None:
        """Log throttle decision in consistent format."""
        delay = max(0.0, state.next_allowed_ts - time.time())
        logger.info(
            f"[THROTTLE] domain={domain} delay={delay:.2f}s "
            f"inflight={state.in_flight} limit={state.concurrency_limit} "
            f"reason={reason}"
        )

    # Sprint 43: Distributed Tracing
    def _log_span(self, phase: str, message: str, extra: dict = None) -> None:
        """Log with trace_id and elapsed time."""
        extra = extra or {}
        extra.update({
            'trace_id': getattr(self, '_current_trace_id', 'no-trace'),
            'span_duration_ms': int((time.time() - getattr(self, '_trace_start_time', 0)) * 1000)
        })
        logger.info(f"[{phase}] {message}", extra=extra)

    async def acquire(self, domain: str) -> bool:
        """
        Acquire in-flight slot for domain.

        Returns:
            bool: True if acquired, False if at concurrency limit
        """
        async with self._lock:
            state = self._get_or_create_state(domain)
            if state.in_flight >= state.concurrency_limit:
                return False
            state.in_flight += 1
            return True

    async def release(self, domain: str) -> None:
        """Release in-flight slot for domain."""
        async with self._lock:
            state = self._domains.get(domain)
            if state:
                state.in_flight = max(0, state.in_flight - 1)

    def update_yield_score(self, domain: str, yield_score: float) -> None:
        """Update yield score for domain (called by external stats manager)."""
        state = self._get_or_create_state(domain)
        state.yield_score = yield_score

    def get_stats(self, domain: str) -> Dict[str, Any]:
        """Get current stats for domain (for monitoring)."""
        state = self._domains.get(domain)
        if not state:
            return {}
        return {
            "next_allowed_ts": state.next_allowed_ts,
            "concurrency_limit": state.concurrency_limit,
            "in_flight": state.in_flight,
            "consecutive_errors": state.consecutive_errors,
            "last_latency_ms": state.last_latency_ms,
            "yield_score": state.yield_score,
            "last_status": state.last_status,
        }

    def get_all_domains(self) -> Set[str]:
        """Get all tracked domains."""
        return set(self._domains.keys())



# =============================================================================
# M1 8GB: SimHash pro near-duplicate detection
# =============================================================================

class SimHash:
    """Lightweight SimHash (64-bit) pro text deduplication."""

    def __init__(self, hashbits: int = 64):
        self.hashbits = hashbits

    def _tokenize(self, text: str) -> List[str]:
        """Simple tokenization - shingle by 3 words."""
        words = text.lower().split()
        if len(words) < 3:
            return words
        return [' '.join(words[i:i+3]) for i in range(len(words)-2)]

    def _hash_token(self, token: str) -> int:
        """Hash token to 64-bit integer."""
        return int(hashlib.sha256(token.encode()).hexdigest()[:16], 16)

    def compute(self, text: str) -> int:
        """Compute SimHash for text."""
        tokens = self._tokenize(text[:5000])  # Limit for M1 8GB
        if not tokens:
            return 0

        # Weighted hash vector
        v = [0] * self.hashbits

        for token in tokens:
            h = self._hash_token(token)
            for i in range(self.hashbits):
                bit = (h >> i) & 1
                if bit:
                    v[i] += 1
                else:
                    v[i] -= 1

        # Create fingerprint
        fingerprint = 0
        for i in range(self.hashbits):
            if v[i] > 0:
                fingerprint |= (1 << i)

        return fingerprint

    @staticmethod
    def hamming_distance(hash1: int, hash2: int) -> int:
        """Compute Hamming distance between two hashes."""
        x = hash1 ^ hash2
        distance = 0
        while x:
            distance += 1
            x &= x - 1
        return distance

    def is_near_duplicate(self, hash1: int, hash2: int, threshold: int = 3) -> bool:
        """Check if two hashes are near-duplicates (Hamming <= threshold)."""
        return self.hamming_distance(hash1, hash2) <= threshold


# =============================================================================
# M1 8GB: SnapshotStorage pro WARC-lite ukládání
# =============================================================================

@dataclass
class SnapshotEntry:
    """Metadata snapshotu uloženého na disku."""
    evidence_id: str
    url: str
    snapshot_path: str
    content_hash: str
    content_type: str
    size_bytes: int
    compressed: bool
    created_at: float
    metadata: Dict[str, Any] = field(default_factory=dict)


class SnapshotStorage:
    """WARC-lite snapshot storage - disk-only, RAM nikdy nedrží full body."""

    # M1 8GB HARD LIMITY
    MAX_SNAPSHOT_SIZE = 5 * 1024 * 1024  # 5MB hard limit
    MAX_TOTAL_SNAPSHOTS = 100  # Max počet snapshotů v RAM indexu

    def __init__(self, storage_dir: Optional[Path] = None):
        self._storage_dir = storage_dir or Path.home() / '.hledac' / 'snapshots'
        self._storage_dir.mkdir(parents=True, exist_ok=True)
        self._index: Dict[str, SnapshotEntry] = {}  # evidence_id -> metadata only

    def _get_snapshot_path(self, evidence_id: str) -> Path:
        """Generate path for snapshot file."""
        # Shard by first 2 chars of evidence_id
        shard = evidence_id[:2]
        shard_dir = self._storage_dir / shard
        shard_dir.mkdir(exist_ok=True)
        return shard_dir / f"{evidence_id}.gz"

    async def store_snapshot(self, evidence_id: str, url: str,
                            content_bytes: bytes, content_type: str,
                            metadata: Optional[Dict[str, Any]] = None) -> Optional[SnapshotEntry]:
        """Uloží snapshot na disk (nikdy ne do RAM)."""
        import gzip

        # Check size limit
        if len(content_bytes) > self.MAX_SNAPSHOT_SIZE:
            logger.warning(f"[SNAPSHOT] Content too large ({len(content_bytes)} bytes), truncating")
            content_bytes = content_bytes[:self.MAX_SNAPSHOT_SIZE]

        try:
            snapshot_path = self._get_snapshot_path(evidence_id)
            content_hash = hashlib.sha256(content_bytes).hexdigest()[:32]

            # Compress and save to disk (never to RAM)
            compressed = gzip.compress(content_bytes, compresslevel=6)
            # Get original content length from metadata for F_NOCACHE decision
            original_content_length = None
            if metadata and 'content_length' in metadata:
                original_content_length = metadata['content_length']
            # Open file with fd to apply F_NOCACHE for large downloads (>50MB)
            with open(snapshot_path, 'wb') as f:
                # Apply F_NOCACHE for large files - Darwin optimization
                apply_fcntl_nocache(f.fileno(), original_content_length)
                f.write(compressed)

            # Store only metadata in RAM
            entry = SnapshotEntry(
                evidence_id=evidence_id,
                url=url,
                snapshot_path=str(snapshot_path),
                content_hash=content_hash,
                content_type=content_type,
                size_bytes=len(content_bytes),
                compressed=True,
                created_at=time.time(),
                metadata=metadata or {}
            )

            # Evict oldest if needed
            if len(self._index) >= self.MAX_TOTAL_SNAPSHOTS:
                oldest = min(self._index.items(), key=lambda x: x[1].created_at)
                del self._index[oldest[0]]

            self._index[evidence_id] = entry

            logger.info(f"[SNAPSHOT] Stored {evidence_id}: {len(content_bytes)} bytes -> {len(compressed)} compressed")
            return entry

        except Exception as e:
            logger.error(f"[SNAPSHOT] Failed to store: {e}")
            return None

    async def load_snapshot(self, evidence_id: str) -> Optional[bytes]:
        """Načte snapshot z disku (on-demand, ne cache)."""
        import gzip

        if evidence_id not in self._index:
            return None

        entry = self._index[evidence_id]
        try:
            with open(entry.snapshot_path, 'rb') as f:
                compressed = f.read()
            return gzip.decompress(compressed)
        except Exception as e:
            logger.error(f"[SNAPSHOT] Failed to load: {e}")
            return None

    def get_entry(self, evidence_id: str) -> Optional[SnapshotEntry]:
        """Vrátí metadata snapshotu (bez obsahu)."""
        return self._index.get(evidence_id)

    def is_stored(self, evidence_id: str) -> bool:
        return evidence_id in self._index


