    def _rrf_merge(self, result_lists: List[List[Dict]], k: int = 60) -> List[Dict]:
        """
        Reciprocal Rank Fusion merge of multiple result lists.

        Args:
            result_lists: List of result lists to merge
            k: RRF constant (default 60)

        Returns:
            Merged and ranked results
        """
        from collections import defaultdict
        scores = defaultdict(float)
        docs = {}
        for result_list in result_lists:
            if not result_list:
                continue
            for rank, doc in enumerate(result_list):
                url = doc.get('url', str(rank))
                scores[url] += 1.0 / (k + rank + 1)
                docs[url] = doc
        # Sort by score descending
        sorted_urls = sorted(scores, key=scores.__getitem__, reverse=True)
        return [docs[u] for u in sorted_urls]

