    def _is_crawl_trap(self, url: str) -> Tuple[bool, str, float]:
        """
        Detect crawl traps using heuristics - M1 8GB optimized.

        Returns: (is_trap, reason, trap_score)
        """
        from urllib.parse import urlparse, parse_qs

        parsed = urlparse(url)
        query_params = parse_qs(parsed.query)

        trap_score = 0.0
        reasons = []

        # 1. High entropy query parameters (combinatorial filters)
        if query_params:
            # Calculate entropy of parameter values
            total_entropy = 0
            for key, values in query_params.items():
                for val in values:
                    if len(val) > 20:  # Long values = high entropy
                        # Calculate Shannon entropy
                        from math import log2
                        freq = {}
                        for c in val:
                            freq[c] = freq.get(c, 0) + 1
                        entropy = -sum((f/len(val)) * log2(f/len(val)) for f in freq.values())
                        total_entropy += entropy

            if total_entropy > 15:  # Threshold for high entropy
                trap_score += 0.4
                reasons.append(f"high_entropy({total_entropy:.1f})")

        # 2. Infinite pagination patterns (page=, offset=, calendar)
        pagination_params = {'page', 'offset', 'start', 'from', 'cursor', 'skip'}
        calendar_params = {'year', 'month', 'day', 'date', 'calendar'}

        for param in query_params:
            param_lower = param.lower()
            if param_lower in pagination_params:
                try:
                    val = int(query_params[param][0])
                    if val > 1000:  # Very high page numbers
                        trap_score += 0.5
                        reasons.append(f"deep_pagination({param}={val})")
                    elif val > 100:
                        trap_score += 0.2
                        reasons.append(f"high_pagination({param}={val})")
                except (ValueError, IndexError):
                    pass

            if param_lower in calendar_params:
                trap_score += 0.3
                reasons.append(f"calendar_param({param})")

        # 3. Faceted navigation (combinatorial filters)
        filter_keywords = {'filter', 'facet', 'sort', 'order', 'dir', 'view', 'format'}
        filter_count = sum(1 for p in query_params if any(k in p.lower() for k in filter_keywords))
        if filter_count >= 3:
            trap_score += 0.3
            reasons.append(f"faceted_nav({filter_count})")

        # 4. Pattern repetition in path (calendar trap, etc.)
        path_parts = [p for p in parsed.path.split('/') if p]
        if len(path_parts) >= 4:
            # Check for date-like patterns (YYYY/MM/DD)
            date_pattern = r'^\d{4}$'
            month_pattern = r'^\d{1,2}$'
            date_parts = sum(1 for p in path_parts[-3:] if re.match(date_pattern, p) or re.match(month_pattern, p))
            if date_parts >= 2:
                trap_score += 0.25
                reasons.append("date_path_pattern")

        # 5. Session/state parameters (indicate user-specific content)
        session_params = {'session', 'token', 'sid', 'phpsessid', 'jsessionid', 'asp_session'}
        for param in query_params:
            if any(s in param.lower() for s in session_params):
                trap_score += 0.2
                reasons.append(f"session_param({param})")
                break

        is_trap = trap_score >= 0.5  # Threshold for blocking

        if is_trap:
            self._trap_stats['skipped_traps'] += 1
            self._trap_stats['trap_score'] += trap_score
            reason_str = ','.join(reasons[:3])  # Limit reasons
            logger.info(f"[TRAP] Blocked URL: {url[:80]}... | Score: {trap_score:.2f} | Reasons: {reason_str}")

        return is_trap, ','.join(reasons), trap_score

