    # M1 8GB RAM Management Methods
    # ========================================================================

    def _check_memory_usage(self) -> Tuple[float, bool]:
        """
        Zkontroluje využití RAM a vrátí stav.

        Returns:
            Tuple (GB použito, zda je nad threshold)
        """
        if not PSUTIL_AVAILABLE or psutil is None:
            return 0.0, False

        try:
            mem = psutil.virtual_memory()
            used_gb = mem.used / (1024**3)
            return used_gb, used_gb > self.MEMORY_THRESHOLD_GB
        except Exception:
            return 0.0, False

    def _check_swap_usage(self) -> Tuple[float, bool]:
        """
        Sprint 81 Fáze 3: Zkontroluje swap usage.

        Returns:
            Tuple (swap percent, zda je swapping)
        """
        if not PSUTIL_AVAILABLE or psutil is None:
            return 0.0, False

        try:
            swap = psutil.swap_memory()
            return swap.percent, swap.percent > 10
        except Exception:
            return 0.0, False

    def _aggressive_gc(self) -> None:
        """Agresivní garbage collection pro M1 8GB."""
        gc.collect()

        # MLX cache clear pokud je dostupný
        clear_mlx_cache()

        logger.debug("🧹 Aggressive GC executed")

    def _maybe_gc(self) -> None:
        """Spustí GC pokud je RAM nad thresholdem."""
        _, over_threshold = self._check_memory_usage()
        if over_threshold:
            self._aggressive_gc()

    def _add_processed_hash(self, content_hash: str) -> None:
        """Add hash to processed set with FIFO eviction at 5000 limit."""
        self._processed_hashes[content_hash] = None
        # Evict oldest if over limit
        while len(self._processed_hashes) > 5000:
            self._processed_hashes.popitem(last=False)

    def _estimate_bytes(self, obj: Any) -> Optional[int]:
        """
        Odhadne velikost objektu v bytech (fail-safe).
        Return None pokud nelze odhadnout.
        """
        try:
            # Preferuj content atribut
            content = getattr(obj, 'content', None)
            if content is not None:
                return len(str(content).encode('utf-8'))
            # Fallback na string representation
            return len(str(obj).encode('utf-8'))
        except Exception:
            return None

    def _add_finding_with_limit(
        self,
        finding: Any,
        score: float = 0.5
    ) -> bool:
        """
        Přidá finding do heapu s limitem - starší/low-score se vyřadí.

        Args:
            finding: Finding objekt
            score: Relevance score (0-1)

        Returns:
            True pokud byl finding přidán, False pokud byl vyřazen
        """
        # Deduplikace pomocí content hashe
        content = getattr(finding, 'content', str(finding))
        content_hash = hashlib.sha256(content[:100].encode()).hexdigest()[:16]

        if content_hash in self._processed_hashes:
            return False

        # Sprint 68B: Size-limit check (256KB max)
        est_bytes = self._estimate_bytes(finding)
        if est_bytes is None:
            logger.warning(f"Finding size unknown, discarding: {content_hash}")
            return False
        if est_bytes > 256 * 1024:
            logger.warning(f"Finding too large ({est_bytes} bytes), discarding: {content_hash}")
            # Ulož oříznutý preview do metadata pokud existuje
            if hasattr(finding, 'metadata'):
                try:
                    preview = content[:65536]  # prvních 64KB
                    finding.metadata['content_preview'] = preview
                    logger.info(f"Saved content_preview (64KB) for: {content_hash}")
                except Exception:
                    pass
            return False

        self._add_processed_hash(content_hash)

        # Přidej do heapu (min-heap: nejnižší score je na vrcholu)
        # Invertujeme score pro max-heap chování
        entry = (-score, content_hash, finding)
        heappush(self._findings_heap, entry)

        # Omez na MAX_FINDINGS_IN_RAM - vyhoď nejslabší
        while len(self._findings_heap) > self.MAX_FINDINGS_IN_RAM:
            removed = heappop(self._findings_heap)
            # Odstraň z hash setu aby mohl být potenciálně znovu přidán
            # pokud přijde s vyšším score
            _, removed_hash, _ = removed
            self._processed_hashes.pop(removed_hash, None)

        return True

    def _add_source_with_limit(
        self,
        source: Any,
        score: float = 0.5
    ) -> bool:
        """
        Přidá source do heapu s limitem.

        Args:
            source: Source objekt
            score: Reliability score (0-1)

        Returns:
            True pokud byl source přidán, False pokud byl vyřazen
        """
        # Deduplikace pomocí URL nebo ID
        url = getattr(source, 'url', None) or getattr(source, 'id', str(source))
        url_hash = hashlib.sha256(url.encode()).hexdigest()[:16]

        if url_hash in self._url_dedup:
            return False

        # Sprint 68B: Size-limit check (256KB max)
        est_bytes = self._estimate_bytes(source)
        if est_bytes is None:
            logger.warning(f"Source size unknown, discarding: {url_hash}")
            return False
        if est_bytes > 256 * 1024:
            logger.warning(f"Source too large ({est_bytes} bytes), discarding: {url_hash}")
            return False

        # Metadata-based deduplication check (syndicated/near-duplicate suppression)
        # Build MetadataEntry from source fields
        title = getattr(source, 'title', '') or ''
        content = getattr(source, 'content', '') or ''
        snippet = content[:500] if content else ''  # Use first 500 chars as description
        canonical_url = getattr(source, 'metadata', {}).get('canonical_url', '') if hasattr(source, 'metadata') else ''

        # Check if this source's metadata hash is in loser hashes (suppressed)
        entry_hash = hashlib.sha256(f"{canonical_url or url}|{title}|{snippet}".encode()).hexdigest()[:16]
        if entry_hash in self._metadata_loser_set:
            # Suppressed by metadata dedup - don't add
            return False

        self._url_dedup.add(url_hash)

        # Add to metadata entries for dedup tracking
        metadata_entry = MetadataEntry(
            url=url,
            canonical_url=canonical_url,
            title=title,
            description=snippet
        )
        self._metadata_entries.append(metadata_entry)

        # Bounded list maintenance (<=200)
        if len(self._metadata_entries) > 200:
            self._metadata_entries = self._metadata_entries[-200:]

        # Periodic metadata dedup at 25, 50, 75, 100, 150, 200
        dedup_triggers = {25, 50, 75, 100, 150, 200}
        if len(self._metadata_entries) in dedup_triggers:
            self._run_metadata_dedup()

        # Přidej do heapu
        entry = (-score, url_hash, source)
        heappush(self._sources_heap, entry)

        # Omez na MAX_SOURCES_IN_RAM
        while len(self._sources_heap) > self.MAX_SOURCES_IN_RAM:
            removed = heappop(self._sources_heap)
            _, removed_hash, _ = removed
            if removed_hash in self._url_dedup:
                self._url_dedup.discard(removed_hash)

        return True

    def _run_metadata_dedup(self) -> None:
        """
        Spustí metadata deduplication na entries.
        Shromáždí loser hashes pro budoucí suppression.
        """
        if len(self._metadata_entries) < 2:
            return

        # Build metadata dicts for dedup
        metadata_list = [
            {
                'url': e.url,
                'canonical_url': e.canonical_url,
                'title': e.title,
                'description': e.description
            }
            for e in self._metadata_entries
        ]

        # Run dedup
        results = self._metadata_dedup.deduplicate(metadata_list)

        # Collect loser hashes for suppression
        for result in results:
            self._metadata_loser_set.add(result.loser_hash)
            self._metadata_loser_deque.append(result.loser_hash)

    def _get_top_findings(self, k: Optional[int] = None) -> List[Any]:
        """
        Vrátí top-K findings z heapu.

        Args:
            k: Počet findings (None = všechny)

        Returns:
            Seznam findings seřazených podle score
        """
        if k is None:
            k = len(self._findings_heap)
        k = min(k, len(self._findings_heap))

        # nsmallest vrátí nejmenší, ale my máme negativní score
        top_entries = nsmallest(k, self._findings_heap)
        return [entry[2] for entry in top_entries]

    def _get_top_sources(self, k: Optional[int] = None) -> List[Any]:
        """Vrátí top-K sources z heapu."""
        if k is None:
            k = len(self._sources_heap)
        k = min(k, len(self._sources_heap))

        top_entries = nsmallest(k, self._sources_heap)
        return [entry[2] for entry in top_entries]

    def _clear_temporary_data(self) -> None:
        """Vyčistí data po fázi dočasná pro RAM šetření."""
        # Zachovej jen top findings a sources v heapu
        # Vyčisti všechny dočasné listy pokud existují
        import sys
        # Vynutí garbage collection
        self._aggressive_gc()

    # FIX 2: Async wrapper for inference engine (multi_hop mode)
    async def _infer_hypotheses(self, observations: List[str], query: str = "") -> Dict[str, Any]:
        """Run inference engine on research observations (max 20)."""
        try:
            # Get tool registry from orchestrator
            if not hasattr(self._orch, '_tool_registry_mgr') or self._orch._tool_registry_mgr is None:
                return {"paths": []}

            tool_registry = self._orch._tool_registry_mgr._registry
            if not tool_registry.has_tool("infer"):
                return {"paths": []}

            # Add observations as evidence (bounded to 20)
            engine = tool_registry._inference_engine
            import time
            for obs in observations[:20]:
                from .brain.inference_engine import Evidence
                engine.add_evidence(Evidence(fact=obs, source="research", confidence=0.7, timestamp=time.time()))

            # Rough entity extraction from query (simple heuristic)
            words = query.split()
            entities = [w for w in words if len(w) > 4 and w[0].isupper()][:5]

            if entities:
                # Direct async call to multi_hop_inference
                result = await engine.multi_hop_inference(query=query, entities=entities)
            else:
                result = {"paths": []}

            return result
        except Exception as e:
            logger.warning(f"Inference failed: {e}")
            return {"paths": []}

