    async def _init_snn_engine(self) -> bool:
        """Initialize SNN Engine for neuromorphic prioritization."""
        if self._snn_initialized:
            return True

        _load_snn_engine()
        if not SNN_ENGINE_AVAILABLE or not SNNEngine:
            logger.debug("SNN Engine not available")
            return False

        try:
            from .types import SNNConfig, STDPParams, NeuronParameters

            config = SNNConfig(
                n_neurons=500,  # Reduced for M1 8GB
                connection_prob=0.05,  # Sparse connections
                use_metal=MLX_AVAILABLE,
                enable_stdp=True,
            )
            stdp_params = STDPParams()
            neuron_params = NeuronParameters()

            self._snn_engine = SNNEngine(config, stdp_params, neuron_params)
            self._snn_initialized = True
            logger.info("✅ SNN Engine initialized (500 neurons, STDP enabled)")
            return True

        except Exception as e:
            logger.warning(f"Failed to initialize SNN Engine: {e}")
            return False

    async def _init_federated_engine(self) -> bool:
        """Initialize Federated Learning Engine."""
        if self._federated_initialized:
            return True

        _load_federated_engine()
        if not FEDERATED_ENGINE_AVAILABLE or not FederatedEngine:
            logger.debug("Federated Engine not available")
            return False

        try:
            from ..federated.federated_engine import FederatedConfig

            config = FederatedConfig(
                enabled=True,
                dp_epsilon=0.1,
                batch_size=16,  # M1 8GB limit
                gradient_bits=8,
            )

            # Reference to main model (Hermes or MoE)
            model_ref = None
            if self._orch._brain_mgr:
                model_ref = (
                    self._orch._brain_mgr.moe_router or
                    self._orch._brain_mgr.hermes
                )

            self._federated_engine = FederatedEngine(config, model_ref)
            self._federated_initialized = True
            logger.info("✅ Federated Engine initialized (DP epsilon=0.1)")
            return True

        except Exception as e:
            logger.warning(f"Failed to initialize Federated Engine: {e}")
            return False

    async def prioritize_findings_with_snn(
        self,
        findings: List[ResearchFinding]
    ) -> List[Tuple[ResearchFinding, float]]:
        """
        Prioritize findings using neuromorphic SNN.

        Args:
            findings: List of research findings to prioritize

        Returns:
            List of (finding, priority_score) tuples sorted by score
        """
        if len(findings) < 5:  # Not worth SNN overhead for small sets
            return [(f, f.confidence) for f in sorted(
                findings, key=lambda x: x.confidence, reverse=True
            )]

        # Initialize SNN engine if needed
        if not self._snn_initialized:
            await self._init_snn_engine()

        if not self._snn_engine:
            # Fallback to confidence-based sorting
            return [(f, f.confidence) for f in sorted(
                findings, key=lambda x: x.confidence, reverse=True
            )]

        try:
            result = self._snn_engine.prioritize(findings)
            logger.info(f"🧠 SNN prioritized {len(findings)} findings "
                       f"(energy: {result.processing_result.metrics.energy_consumption_joules:.2e}J)")
            return result.findings

        except Exception as e:
            logger.warning(f"SNN prioritization failed: {e}")
            return [(f, f.confidence) for f in sorted(
                findings, key=lambda x: x.confidence, reverse=True
            )]

    async def collect_federated_training_data(
        self,
        findings: List[ResearchFinding],
        report: str,
        query: str
    ) -> int:
        """
        Collect training data for federated learning.

        Args:
            findings: Research findings
            report: Generated report
            query: Original query

        Returns:
            Number of examples collected
        """
        if not self._federated_initialized:
            await self._init_federated_engine()

        if not self._federated_engine:
            return 0

        try:
            count = self._federated_engine.collect_training_examples(
                findings, [report], query
            )
            if count > 0:
                logger.info(f"📚 Collected {count} federated training examples")
            return count

        except Exception as e:
            logger.warning(f"Failed to collect federated training data: {e}")
            return 0

    async def run_federated_round(self) -> Optional[Dict[str, Any]]:
        """
        Run one federated learning round.

        Returns:
            Round result dictionary or None if disabled
        """
        if not self._federated_initialized:
            await self._init_federated_engine()

        if not self._federated_engine:
            return None

        try:
            result = await self._federated_engine.run_round()
            if result.get('status') == 'success':
                logger.info(f"🔄 Federated round {result['round_id']} completed "
                           f"({result['samples_processed']} samples)")
            return result

        except Exception as e:
            logger.warning(f"Federated round failed: {e}")
            return None

        # Register agents
        await self._register_agents()

        logger.info("✅ ResearchManager initialized")

