    async def _exposed_service_search(self, request: TaskRequest) -> Dict[str, Any]:
        """Exposed service hunting (S3, databases, GraphQL, CT logs)."""
        if not self._exposed_service_hunter:
            return {'source': 'exposed_services', 'results': []}

        try:
            # Extract target from query (simple heuristic)
            target = request.query.split()[-1] if ' ' in request.query else request.query
            results = await self._exposed_service_hunter.hunt(target)
            return {
                'source': 'exposed_services',
                'results': results,
                'count': sum(len(v) for v in results.values() if isinstance(v, list))
            }
        except Exception as e:
            logger.warning(f"Exposed service search failed: {e}")
            return {'source': 'exposed_services', 'results': [], 'error': str(e)}

    async def _inference_search(self, request: TaskRequest) -> Dict[str, Any]:
        """Inference engine for reasoning and evidence chaining."""
        if not self._inference_engine:
            return {'source': 'inference', 'results': []}

        try:
            # Multi-hop inference between query entities
            entities = request.query.split(' AND ')
            if len(entities) >= 2 and self._multi_hop_reasoner:
                paths = await self._multi_hop_reasoner.find_paths(
                    start=entities[0].strip(),
                    end=entities[1].strip(),
                    max_hops=5
                )
                return {
                    'source': 'inference',
                    'paths': [p.to_dict() if hasattr(p, 'to_dict') else str(p) for p in paths],
                    'count': len(paths)
                }
            return {'source': 'inference', 'message': 'Inference engine ready', 'entities': entities}
        except Exception as e:
            logger.warning(f"Inference search failed: {e}")
            return {'source': 'inference', 'results': [], 'error': str(e)}

    async def _relationship_search(self, request: TaskRequest) -> Dict[str, Any]:
        """Relationship discovery for social network analysis."""
        if not self._relationship_discovery:
            return {'source': 'relationships', 'results': []}

        try:
            # Build graph from query entities
            entities = request.query.split(',')
            for entity in entities:
                self._relationship_discovery.add_entity(entity.strip())

            communities = self._relationship_discovery.detect_communities()
            return {
                'source': 'relationships',
                'communities': [c.to_dict() if hasattr(c, 'to_dict') else str(c) for c in communities],
                'entity_count': len(entities)
            }
        except Exception as e:
            logger.warning(f"Relationship search failed: {e}")
            return {'source': 'relationships', 'results': [], 'error': str(e)}

    async def _temporal_archaeology_search(self, request: TaskRequest) -> Dict[str, Any]:
        """Temporal archaeology for deleted content recovery."""
        if not self._temporal_archaeologist:
            return {'source': 'temporal_archaeology', 'results': []}

        try:
            # Try to recover content from URL in query
            url = None
            words = request.query.split()
            for word in words:
                if word.startswith('http'):
                    url = word
                    break

            if url:
                recovered = await self._temporal_archaeologist.recover_deleted_content(url)
                return {
                    'source': 'temporal_archaeology',
                    'recovered': [r.to_dict() if hasattr(r, 'to_dict') else str(r) for r in recovered],
                    'count': len(recovered)
                }
            return {'source': 'temporal_archaeology', 'message': 'No URL found in query'}
        except Exception as e:
            logger.warning(f"Temporal archaeology search failed: {e}")
            return {'source': 'temporal_archaeology', 'results': [], 'error': str(e)}

