    async def _hypothesis_search(self, request: TaskRequest) -> Dict[str, Any]:
        """Hypothesis engine for automated hypothesis generation and testing."""
        if not self._hypothesis_engine:
            return {'source': 'hypothesis', 'results': []}

        try:
            # Generate hypotheses from query as observation
            from dataclasses import dataclass
            @dataclass
            class MockObservation:
                content: str
                source: str = "query"

            observation = MockObservation(content=request.query)
            hypotheses = self._hypothesis_engine.generate_hypotheses([observation])

            return {
                'source': 'hypothesis',
                'hypotheses': [h.to_dict() if hasattr(h, 'to_dict') else str(h) for h in hypotheses],
                'count': len(hypotheses)
            }
        except Exception as e:
            logger.warning(f"Hypothesis search failed: {e}")
