    async def _identity_stitching_search(self, request: TaskRequest) -> Dict[str, Any]:
        """Identity stitching for cross-platform identity linking."""
        if not self._identity_stitching:
            return {'source': 'identity_stitching', 'results': []}

        try:
            # Add profile from query and find matches
            profile_id = f"query_profile_{hash(request.query) % 10000}"
            self._identity_stitching.add_profile({
                'id': profile_id,
                'primary_name': request.query,
                'usernames': [{'platform': 'query', 'username': request.query.replace(' ', '_')}]
            })

            matches = self._identity_stitching.find_matches(profile_id)
            stitched = self._identity_stitching.stitch_identities()

            return {
                'source': 'identity_stitching',
                'matches': [m.to_dict() if hasattr(m, 'to_dict') else str(m) for m in matches],
                'stitched_identities': [s.to_dict() if hasattr(s, 'to_dict') else str(s) for s in stitched],
                'count': len(stitched)
            }
        except Exception as e:
            logger.warning(f"Identity stitching search failed: {e}")
            return {'source': 'identity_stitching', 'results': [], 'error': str(e)}

