    async def _blockchain_search(self, request: TaskRequest) -> Dict[str, Any]:
        """Blockchain forensics for transaction analysis."""
        if not self._blockchain_forensics:
            return {'source': 'blockchain', 'results': []}

        try:
            # Extract address from query
            eth_pattern = r'0x[a-fA-F0-9]{40}'
            btc_pattern = r'[13][a-km-zA-HJ-NP-Z1-9]{25,34}'

            eth_match = re.search(eth_pattern, request.query)
            btc_match = re.search(btc_pattern, request.query)

            if eth_match:
                address = eth_match.group(0)
                analysis = await self._blockchain_forensics.analyze_wallet(address, 'ethereum')
                return {
                    'source': 'blockchain',
                    'address': address,
                    'chain': 'ethereum',
                    'analysis': analysis.to_dict() if hasattr(analysis, 'to_dict') else str(analysis)
                }
            elif btc_match:
                address = btc_match.group(0)
                analysis = await self._blockchain_forensics.analyze_wallet(address, 'bitcoin')
                return {
                    'source': 'blockchain',
                    'address': address,
                    'chain': 'bitcoin',
                    'analysis': analysis.to_dict() if hasattr(analysis, 'to_dict') else str(analysis)
                }

            return {'source': 'blockchain', 'message': 'No valid blockchain address found in query'}
        except Exception as e:
            logger.warning(f"Blockchain search failed: {e}")
            return {'source': 'blockchain', 'results': [], 'error': str(e)}

