    async def execute_searxng_search(self, query: str) -> Dict[str, Any]:
        """Execute search via SearXNG meta-search engine."""
        # Initialize client if needed
        if not self._searxng_available:
            if self._searxng_client is None:
                try:
                    from .tools.searxng_client import SearxngClient
                    # Use configurable URL, fallback to localhost
                    url = getattr(self._orch.config, 'searxng_url', 'http://localhost:8080')
                    self._searxng_client = SearxngClient(base_url=url)
                    self._searxng_available = True
                except Exception as e:
                    logger.warning(f"SearXNG client initialization failed: {e}")
                    self._searxng_available = False
                    return {'findings': [], 'sources': []}

        if not self._searxng_available or not self._searxng_client:
            return {'findings': [], 'sources': []}

        try:
            results = await self._searxng_client.search(query, max_results=20)
            findings = []
            sources = []

            for r in results:
                source = ResearchSource(
                    url=r['url'],
                    title=r['title'],
                    content=r['content'],
                    source_type=SourceType.WEB,
                    confidence=0.7
                )
                sources.append(source)
                findings.append(ResearchFinding(
                    content=r['content'],
                    source=source,
                    confidence=0.7,
                    category='web_search'
                ))

            return {'findings': findings, 'sources': sources}
        except Exception as e:
            logger.warning(f"SearXNG search failed: {e}")
            return {'findings': [], 'sources': []}

