    async def deep_excavation(
        self,
        sources: List[ResearchSource],
        strategy: AutonomousStrategy
    ) -> Dict[str, Any]:
        """Deep excavation - následování odkazů a citací."""
        findings = []
        new_sources = []

        academic_sources = [s for s in sources if s.source_type == SourceType.ACADEMIC]

        for source in academic_sources[:2]:
            try:
                if hasattr(self._orch, 'research') and self._orch.research:
                    citations = await self._orch.research.follow_citations(source.title)
                    for citation in citations:
                        new_source = ResearchSource(
                            url=f"citation://{hash(citation) % 10000}",
                            title=str(citation),
                            content=f"Citation from {source.title}",
                            source_type=SourceType.ACADEMIC,
                            confidence=0.8
                        )
                        new_sources.append(new_source)
                        findings.append(ResearchFinding(
                            content=str(citation),
                            source=new_source,
                            confidence=0.8,
                            category='evidence'
                        ))
            except Exception as e:
                logger.debug(f"Citation following failed: {e}")

        return {'findings': findings, 'sources': new_sources}

    async def _maybe_trigger_deep_probe(
        self,
        reason: str,
        target_domains: Optional[List[str]] = None
    ) -> int:
        """
        Trigger deep_probe to generate seed URLs for frontier.

        Called when:
        - frontier_yield is low (stagnation detected)
        - frontier is nearly empty
        - contested/drift high-value URLs need history

        Args:
            reason: Why deep_probe was triggered
            target_domains: Optional list of domains to probe

        Returns:
            Number of seeds added
        """
        # Lazy load deep_probe
        if not DEEP_PROBE_AVAILABLE:
            _load_deep_probe()
        if not DEEP_PROBE_AVAILABLE or not DeepProbeScanner:
            return 0

        try:
            # Get domains to probe
            domains = target_domains
            if not domains:
                # Extract domains from frontier or visited URLs
                domains = list(set(
                    urlparse(u).netloc
                    for u in getattr(self._url_frontier, '_url_hashes', set())
                ))[:5]  # Max 5 domains

            if not domains:
                return 0

            # Use ShadowWalker for path prediction (not massive crawling)
            seeds = []
            wayback_used = 0
            predicted_paths = 0
            tech_seeds = 0

            for domain in domains[:3]:  # Max 3 domains
                base_url = f"https://{domain}"

                # Path prediction - limited to 30 paths per domain
                if ShadowWalkerAlgorithm:
                    walker = ShadowWalkerAlgorithm()
                    # Get known paths from frontier or empty
                    known_paths = []
                    predictions = walker.predict_next_paths(base_url, known_paths)
                    for url, conf in predictions[:30]:
                        if conf > 0.5:
                            seeds.append((url, conf, {'depth': 1, 'diversity': 0.5}))
                            predicted_paths += 1

                # WayBack - only for contested/drift/high-value
                if 'contested' in reason or 'drift' in reason or 'high_value' in reason:
                    if WaybackCDXClient and wayback_used < 1:  # Max 1 CDX call per run
                        async with WaybackCDXClient() as client:
                            snapshots = await client.query_snapshots(base_url, limit=20)
                            for snap in snapshots[:20]:  # Max 20 results
                                wayback_url = f"https://web.archive.org/web/{snap.get('timestamp', '')}/{base_url}"
                                seeds.append((wayback_url, 0.7, {'depth': 1, 'diversity': 0.6}))
                                wayback_used += 1
                                if wayback_used >= 20:
                                    break

                # Tech signature detection - limited to 10 endpoints per domain
                if TechStackSignature:
                    detector = TechStackSignature()
                    detected = detector.detect_stack(base_url)
                    if detected.get('framework'):
                        # Generate typical endpoints for detected CMS
                        framework = detected['framework']
                        typical_paths = {
                            'wordpress': ['/wp-json/', '/wp-admin/', '/feed/'],
                            'mediawiki': ['/api.php', '/Special:Random'],
                            'next': ['/api/', '/_next/data/'],
                        }.get(framework, [])[:3]

                        for path in typical_paths[:3]:  # Max 10 total
                            full_url = base_url + path
                            seeds.append((full_url, 0.8, {'depth': 1, 'diversity': 0.7}))
                            tech_seeds += 1
                            if tech_seeds >= 10:
                                break

            # Add seeds to frontier
            if seeds:
                added = self._url_frontier.add_seeds(seeds)
                logger.info(
                    f"[DEEP PROBE] seeds_generated={len(seeds)} domains={len(domains)} "
                    f"reason={reason} added={added}"
                )
                logger.info(
                    f"[DEEP PROBE] wayback_used={wayback_used} predicted_paths={predicted_paths} "
                    f"tech_seeds={tech_seeds}"
                )
                return added

        except Exception as e:
            logger.warning(f"[DEEP PROBE] Failed: {e}")

        return 0

    async def deep_frontier_crawl(
        self,
        seed_urls: List[str],
        max_depth: int = 2,
        max_urls: int = 20,
        use_cache: bool = True
    ) -> Dict[str, Any]:
        """
        Deep crawling using priority frontier - M1 8GB optimized.

        Args:
            seed_urls: Starting URLs
            max_depth: Maximum crawl depth
            max_urls: Maximum URLs to fetch
            use_cache: Use HTTP cache with revalidation

        Returns:
            Dict with findings and sources
        """
        findings = []
        sources = []
        fetched_count = 0

        # Sprint 2A: Windup check — seeds still allowed (initialization), but check remaining time
        remaining = self._lifecycle.remaining_time if hasattr(self, '_lifecycle') else float('inf')
        if remaining < 60:
            logger.info("[WINDUP] <60s remaining, skipping new seed expansion")
        elif hasattr(self, '_url_frontier') and self._url_frontier:
            for url in seed_urls[:10]:  # Max 10 seeds
                self._url_frontier.push(url, depth=0, novelty_score=1.0)

        logger.info(f"🕸️ Starting frontier crawl from {len(seed_urls)} seeds")

        # Process frontier
        while fetched_count < max_urls:
            entry = self._url_frontier.pop()
            if not entry:
                break

            # Skip if too deep
            if entry.depth > max_depth:
                continue

            # CRAWL-TRAP FIREWALL: Check for trap patterns before fetching
            is_trap, trap_reason, trap_score = self._is_crawl_trap(entry.url)
            if is_trap:
                # Update PatternStats for trap
                from urllib.parse import urlparse
                trap_domain = urlparse(entry.url).netloc
                self._pattern_stats.update(trap_domain, entry.url, 'trap', 0.0)
                self._trap_stats['skipped_traps'] += 1
                continue  # Skip this URL, already logged in _is_crawl_trap

            try:
                # Check cache first
                cached = self._http_cache.get(entry.url) if use_cache else None
                stale_while_revalidate = False
                scheduled_recrawl = False

                if cached:
                    # Check if cache is expired (stale)
                    import time as time_module
                    now = time_module.time()
                    cache_age_seconds = now - cached.fetched_at
                    cache_ttl = self._http_cache._ttl_seconds

                    if cache_age_seconds > cache_ttl:
                        # STALE-WHILE-REVALIDATE: Return cached preview immediately
                        # but schedule a low-priority recrawl
                        logger.info(f"[SWR] url={entry.url} age={cache_age_seconds:.0f}s ttl={cache_ttl}s")

                        result = {
                            'url': cached.url,
                            'title': cached.headers.get('title', ''),
                            'text_preview': cached.text_preview,
                            'text_hash': cached.text_hash,
                            'success': True,
                            'from_cache': True,
                            'stale_while_revalidate': True,
                            'cache_age_seconds': cache_age_seconds
                        }
                        stale_while_revalidate = True

                        # Schedule low-priority recrawl (not aggressive)
                        # Respect DomainLimiter and budget
                        if hasattr(self, '_recrawl_planner') and self._recrawl_planner:
                            # Check domain limiter before scheduling
                            parsed = cached.url if hasattr(cached, 'url') else entry.url
                            from urllib.parse import urlparse
                            domain = urlparse(parsed if parsed else entry.url).netloc.lower()

                            domain_limiter = getattr(self, '_domain_limiter', None)
                            can_fetch = True
                            if domain_limiter:
                                can_fetch = domain_limiter.can_fetch(domain)

                            if can_fetch:
                                self._recrawl_planner.schedule_recheck(
                                    url=entry.url,
                                    evidence_id=f"swr_{entry.url[:32]}",
                                    last_crawled_at=cached.fetched_at,
                                    content_hash=cached.text_hash,
                                    drift_detected=False,
                                    contested=False,
                                    high_value=False  # Low priority - just refresh
                                )
                                scheduled_recrawl = True
                                logger.info(f"[SWR] scheduled_recrawl=true priority=low url={entry.url}")

                        # Skip fresh fetch - use cached immediately
                        # But still fetch in background if budget allows
                        # For now, just use the cached version
                        if result.get('success'):
                            fetched_count += 1
                            content_hash = result.get('text_hash', '')
                            is_novel = self._url_frontier.mark_novel(content_hash)

                            if not is_novel:
                                logger.debug(f"Skipping duplicate content: {entry.url}")
                                continue

                            source = ResearchSource(
                                url=result['url'],
                                title=result.get('title', ''),
                                content=result.get('text_preview', ''),
                                source_type=SourceType.WEB,
                                confidence=0.6,  # Slightly reduced confidence for stale
                                metadata={
                                    'depth': entry.depth,
                                    'from_cache': True,
                                    'stale_while_revalidate': True,
                                    'scheduled_recrawl': scheduled_recrawl
                                }
                            )
                            sources.append(source)

                            # Add finding
                            if hasattr(self, '_orch') and self._orch:
                                try:
                                    from ..knowledge.entity_linker import Finding
                                    from ..knowledge.graph_builder import FindingType
                                    finding = Finding(
                                        entity_id=f"source_{content_hash[:16]}",
                                        entity_type="web_content",
                                        evidence_type=FindingType.CONTENT,
                                        content=result.get('text_preview', '')[:500],
                                        source_url=result['url'],
                                        metadata={'stale_while_revalidate': True}
                                    )
                                except Exception:
                                    pass

                            continue

                    # Cache is fresh - use revalidation
                    # Revalidate with If-None-Match / If-Modified-Since
                    reval_headers = self._http_cache.get_revalidation_headers(entry.url)

                    # Fetch with revalidation
                    async with self._orch._stealth_manager.session() as session:
                        response = await session.get(
                            entry.url,
                            headers=reval_headers,
                            max_bytes=262144
                        )

                        if response.status == 304:
                            # Not modified - use cache
                            logger.debug(f"Cache hit (304): {entry.url}")
                            result = {
                                'url': cached.url,
                                'title': '',
                                'text_preview': cached.text_preview,
                                'text_hash': cached.text_hash,
                                'success': True,
                                'from_cache': True
                            }
                        else:
                            # Relevance gating - skip low-relevance URLs
                            title_hint = getattr(entry, 'anchor_hint', '') or ""
                            anchor_hint = getattr(entry, 'anchor_hint', '') or ""
                            query_hint = ""  # No query in frontier crawl context
                            if not self._should_fetch_url(entry.url, title=title_hint, snippet=anchor_hint, query=query_hint):
                                logger.debug(f"Skipping low-relevance URL: {entry.url}")
                                continue
                            # Modified or error - fetch fresh
                            result = await self.deep_read(entry.url)
                            result['from_cache'] = False

                            # Update cache
                            if result.get('success'):
                                self._http_cache.set(entry.url, HttpCacheEntry(
                                    url=entry.url,
                                    status=response.status,
                                    headers=dict(response.headers),
                                    body_preview=result.get('text_preview', '')[:5000],
                                    text_preview=result.get('text_preview', ''),
                                    text_hash=result.get('text_hash', ''),
                                    fetched_at=time.time(),
                                    etag=response.headers.get('ETag'),
                                    last_modified=response.headers.get('Last-Modified')
                                ))
                else:
                    # Relevance gating - skip low-relevance URLs
                    title_hint = getattr(entry, 'anchor_hint', '') or ""
                    anchor_hint = getattr(entry, 'anchor_hint', '') or ""
                    query_hint = ""  # No query in frontier crawl context
                    if not self._should_fetch_url(entry.url, title=title_hint, snippet=anchor_hint, query=query_hint):
                        logger.debug(f"Skipping low-relevance URL: {entry.url}")
                        continue
                    # No cache - fetch fresh
                    result = await self.deep_read(entry.url)
                    result['from_cache'] = False

                if not result.get('success'):
                    continue

                fetched_count += 1

                # Check novelty
                content_hash = result.get('text_hash', '')
                is_novel = self._url_frontier.mark_novel(content_hash)

                if not is_novel:
                    logger.debug(f"Skipping duplicate content: {entry.url}")
                    continue

                # Create source
                source = ResearchSource(
                    url=result['url'],
                    title=result.get('title', ''),
                    content=result.get('text_preview', ''),
                    source_type=SourceType.WEB,
                    confidence=0.7,
                    metadata={
                        'depth': entry.depth,
                        'from_cache': result.get('from_cache', False)
                    }
                )
                sources.append(source)

                # Create finding
                finding = ResearchFinding(
                    content=result.get('text_preview', ''),
                    source=source,
                    confidence=0.7,
                    category='web_content'
                )
                findings.append(finding)

                # Add outlinks to frontier with DomainStats diversity penalty
                # PAGE-TYPE ROUTING: Adjust link extraction based on page_type
                if entry.depth < max_depth:
                    page_type = result.get('page_type', 'unknown')
                    high_value = result.get('metadata', {}).get('high_value', False)

                    # Link extraction limits based on page_type
                    if page_type == 'listing':
                        max_links = 20  # Listings have more links to extract
                        snapshot_priority = 0.3  # Lower priority for listing snapshots
                    elif page_type == 'article':
                        max_links = 10
                        snapshot_priority = 0.8  # Higher priority for article snapshots
                    elif page_type == 'profile':
                        max_links = 5  # Profiles have fewer outgoing links
                        snapshot_priority = 0.4
                    else:
                        max_links = 10
                        snapshot_priority = 0.5

                    for link in result.get('links_out', [])[:max_links]:
                        link_url = link['url']

                        # CRAWL-TRAP FIREWALL: Check outlinks too
                        is_trap, trap_reason, trap_score = self._is_crawl_trap(link_url)
                        if is_trap:
                            continue  # Skip trap URLs in outlinks

                        parsed = urlparse(link_url)
                        link_domain = parsed.netloc.lower()
                        domain_hash = hashlib.sha256(link_domain.encode()).hexdigest()[:8]

                        # LINK SCORING: Combine link score with diversity
                        link_score = link.get('score', 0.5)  # Default base score

                        # Diversity score: higher for new domains
                        diversity_score = 0.8 if self._url_frontier.is_novel(domain_hash) else 0.3

                        # DomainStats penalty: lower score for low-yield domains
                        yield_penalty = self._domain_stats.get_yield_penalty(link_domain)
                        adjusted_diversity = diversity_score * (1 - yield_penalty)

                        # Combine link_score with diversity (weighted average)
                        final_score = (adjusted_diversity * 0.7) + (link_score * 0.3)

                        # Recency boost: prefer recently seen but not too recent
                        recency_score = 0.5

                        # Anchor hint for frontier (max 200 chars)
                        anchor_text = link.get('anchor_text', '')[:120]
                        context_snippet = link.get('context_snippet', '')[:80]
                        anchor_hint = f"{anchor_text} | {context_snippet}"[:200] if anchor_text or context_snippet else ""

                        # Snapshot priority based on page_type
                        self._url_frontier.push(
                            link_url,
                            depth=entry.depth + 1,
                            novelty_score=final_score,
                            diversity_score=adjusted_diversity,
                            recency_score=recency_score,
                            snapshot_priority=snapshot_priority,  # Pass priority to frontier
                            anchor_hint=anchor_hint,  # Store anchor hint for context
                            referrer_domain=domain  # Store referrer for source tracking
                        )

                logger.debug(f"Crawled [{fetched_count}/{max_urls}]: {entry.url}")

            except Exception as e:
                logger.debug(f"Frontier crawl failed for {entry.url}: {e}")
                continue

            # Early stop check - if frontier is empty
            if len(self._url_frontier) == 0:
                # Trigger deep_probe for more seeds
                await self._maybe_trigger_deep_probe(reason="empty_frontier")
                if len(self._url_frontier) == 0:
                    logger.info("Frontier empty, stopping crawl")
                    break

            # Check for low yield - trigger deep_probe periodically
            if fetched_count > 0 and fetched_count % 10 == 0:
                stats = self._url_frontier.get_stats()
                if stats.get('novel_hashes', 0) / fetched_count < 0.3:
                    # Low novelty ratio - stagnating
                    await self._maybe_trigger_deep_probe(reason="low_yield")

        stats = self._url_frontier.get_stats()
        logger.info(f"🕸️ Frontier crawl complete: {fetched_count} URLs, "
                   f"frontier={stats['frontier_size']}, novel={stats['novel_hashes']}, "
                   f"skipped_traps={self._trap_stats['skipped_traps']}")

        return {
            'findings': findings,
            'sources': sources,
            'stats': {
                'fetched': fetched_count,
                'frontier_size': stats['frontier_size'],
                'novel_hashes': stats['novel_hashes'],
                'skipped_traps': self._trap_stats['skipped_traps'],
                'trap_score': self._trap_stats['trap_score']
            }
        }

    async def analyze_temporal_context(
        self,
        findings: List[ResearchFinding],
        query: str
    ) -> Dict[str, Any]:
        """Analyzuje temporální kontext nálezů."""
        if not self._temporal_analyzer:
            return {'range': 'unknown', 'timeline': []}

        try:
            timestamps = []
            for f in findings:
                if f.source.timestamp:
                    timestamps.append(f.source.timestamp)

            if not timestamps:
                return {'range': 'no_data', 'timeline': []}

            timeline = await self._temporal_analyzer.analyze(
                query=query,
                timestamps=timestamps
            )

            return {
                'range': f"{min(timestamps)} to {max(timestamps)}",
                'timeline': timeline,
                'oldest': min(timestamps),
                'newest': max(timestamps)
            }

        except Exception as e:
            logger.warning(f"Temporal analysis failed: {e}")
            return {'range': 'error', 'timeline': []}

    async def detect_steganography(self, sources: List) -> List[Dict]:
        """Detekuje steganografické vzory."""
        if not self._stego_detector:
            return []

        findings = []

        for source in sources[:5]:
            try:
                content = source if isinstance(source, str) else getattr(source, 'content', '')
                result = await self._stego_detector.analyze(content)
                if result.get('has_steganography'):
                    findings.append({
                        'source_url': getattr(source, 'url', 'unknown'),
                        'type': result.get('type', 'unknown'),
                        'confidence': result.get('confidence', 0)
                    })
            except Exception as e:
                logger.debug(f"Steganography detection failed: {e}")

        return findings

    async def generate_insights(self, findings: List[ResearchFinding], query: str) -> List[str]:
        """Generuje insighty z nálezů."""
        if not self._insight_engine:
            return []

        try:
            insights = await self._insight_engine.generate(
                findings=[f.content for f in findings[:20]],
                query=query
            )
            return insights
        except Exception as e:
            logger.warning(f"Insight generation failed: {e}")
            return []

    async def deep_read(self, url: str, fetch_snapshot: bool = False,
                        evidence_id: Optional[str] = None,
                        high_value: bool = False,
                        value_estimate_override: Optional[Dict[str, Any]] = None,
                        context: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
        """
        Deep read a URL with HEAD → Preview → Snapshot decision flow - M1 8GB optimized.

        Flow (v7.0 - HEAD/Preview/Snapshot Decision Flow):
        1. Normalize URL (drop tracking params)
        2. Check DomainStats for yield/cooldown
        3. Check robots.txt
        4. HEAD request - get Content-Length and Content-Type
           - If Content-Length > 5MB and not high-value: skip full snapshot
           - Check Content-Type for non-HTML early routing
        5. Preview GET (max 256KB) - lightweight content extraction
           - Extract: title, text_preview (first 5K chars), links (max 50), feeds
           - Compute: simhash for deduplication
        6. Full snapshot decision (store max 5MB, gzip):
        """
        # Offline mode guard - block network calls
        if self._offline_mode:
            raise RuntimeError(
                f"[REPLAY] Offline mode active - network calls blocked. "
                f"Use research() with offline_replay=True for disk-only analysis."
            )

        # Flow (v7.0 - HEAD/Preview/Snapshot Decision Flow):
        # 1. Normalize URL (drop tracking params)
        # 2. Check DomainStats for yield/cooldown
        # 3. Check robots.txt
        # 4. HEAD request - get Content-Length and Content-Type
        #    - If Content-Length > 5MB and not high-value: skip full snapshot
        #    - Check Content-Type for non-HTML early routing
        # 5. Preview GET (max 256KB) - lightweight content extraction
        #    - Extract: title, text_preview (first 5K chars), links (max 50), feeds
        #    - Compute: simhash for deduplication
        # 6. Full snapshot decision (store max 5MB, gzip):
        #    - Store ONLY if: URL is contested/drift/high_value OR
        #                    Content-Type is non-HTML with metadata gating OR
        #                    Content-Length < 5MB and good domain health
        #    - Otherwise: store only preview
        # 7. Non-HTML content: metadata extraction with top-K patterns
        # 8. SimHash prefilter for near-duplicate detection
        # 9. DomainLimiter integration: adjust fetch strategy based on domain health

        # Hard limits:
        # - max_bytes: 256KB (preview), 5MB (snapshot)
        # - max_links: 50
        # - text_preview: 5k chars

        from urllib.parse import urlparse, urljoin, parse_qs, urlencode, urlunparse
        import hashlib
        import gzip
        import aiohttp

        start_time = time.time()

        # Lazy init components
        _load_supreme_components()
        if not hasattr(self._orch, '_rust_miner'):
            self._orch._rust_miner = RustMiner() if RustMiner else None
        if not hasattr(self._orch, '_stealth_manager'):
            from .stealth.stealth_manager import StealthManager
            self._orch._stealth_manager = StealthManager()
        if not hasattr(self._orch, '_robots_parser'):
            from ..utils.robots_parser import RobotsParser
            self._orch._robots_parser = RobotsParser()

        try:
            # 1. Normalize URL - remove tracking params
            parsed = urlparse(url)
            domain = parsed.netloc.lower()
            tracking_params = {'utm_source', 'utm_medium', 'utm_campaign', 'utm_term',
                             'utm_content', 'fbclid', 'gclid', 'ref', 'source'}
            query_params = parse_qs(parsed.query)
            filtered_params = {k: v for k, v in query_params.items()
                             if k.lower() not in tracking_params}
            new_query = urlencode(filtered_params, doseq=True)
            normalized_url = urlunparse((
                parsed.scheme, parsed.netloc, parsed.path,
                parsed.params, new_query, ''  # Drop fragment
            ))

            # Security: Analyze URL for Unicode attacks (bidi, homoglyphs, confusables)
            url_unicode_flags = {}
            if self._orch._security_mgr and self._orch._security_mgr.unicode_analyzer:
                try:
                    url_unicode_flags = self._orch._security_mgr.analyze_unicode(normalized_url, context='url')
                    # Penalize suspicious URLs
                    if url_unicode_flags.get('has_bidi') or url_unicode_flags.get('has_homoglyph') or url_unicode_flags.get('suspicious_mixed_script'):
                        logger.warning(f"[SECURITY] Suspicious URL detected: {normalized_url[:60]}... flags={url_unicode_flags}")
                        # Log security event (sanitized)
                        url_hash = hashlib.sha256(normalized_url.encode()).hexdigest()[:16]
                        logger.info(f"[SECURITY EVENT] url_hash={url_hash} unicode_flags_hash={url_unicode_flags.get('findings_hash', '')}")
                except Exception as e:
                    logger.warning(f"URL unicode analysis failed: {e}")

            base_url = f"{parsed.scheme}://{parsed.netloc}"

            # 2. Check DomainStats (yield-based cooldown)
            domain_stats = self._domain_stats.get_stats(domain)
            if domain_stats.yield_score < 0.1:
                logger.info(f"[DOMAIN STATS] Skipping low-yield domain {domain} (score: {domain_stats.yield_score:.2f})")
                return {
                    'url': normalized_url,
                    'success': False,
                    'domain_cooldown': True,
                    'error': f'Domain {domain} in cooldown (low yield)'
                }

            # Domain health check for fetch strategy adjustment
            # Poor health (many errors) = prefer preview only
            # Good health (high yield) = allow full snapshots
            domain_health_poor = domain_stats.http_errors > 5 and (
                domain_stats.http_errors / max(1, domain_stats.requests) > 0.3
            )
            domain_health_good = domain_stats.yield_score > 0.5 and domain_stats.http_errors < 3

            # 3. Check robots.txt
            async with self._orch._robots_parser as robots:
                robots_doc = await robots.fetch_robots(base_url)
                if robots_doc and not robots.can_fetch(parsed.path, robots_doc=robots_doc):
                    logger.info(f"🚫 Blocked by robots.txt: {normalized_url}")
                    latency_ms = (time.time() - start_time) * 1000
                    domain_stats.record_request(latency_ms, is_new=False, blocked_by_robots=True)
                    self._domain_stats.save_stats()
                    # Update PatternStats for blocked
                    self._pattern_stats.update(domain, normalized_url, 'blocked', 0.0)
                    return {
                        'url': normalized_url,
                        'success': False,
                        'blocked_by_robots': True,
                        'error': 'Blocked by robots.txt'
                    }

            async with self._orch._stealth_manager.session() as session:
                # Budget check: network call
                allowed, reason = self._budget_manager.check_network_allowed()
                if not allowed:
                    logger.info(f"[BUDGET] action=network_fetch allowed=False reason={reason}")
                    return {
                        'url': normalized_url,
                        'success': False,
                        'error': f'Budget exceeded: {reason}'
                    }

                # Record network call
                self._budget_manager.record_network_call()
                logger.info(f"[BUDGET] action=network_fetch allowed=True calls={self._budget_manager._network_calls}")

                # Circuit Breaker: Check if network calls are allowed
                if self._orch._security_mgr and self._orch._security_mgr.is_net_breaker_open():
                    logger.warning(f"[CIRCUIT BREAKER] Network calls blocked - breaker open for {normalized_url[:40]}")
                    return {
                        'url': normalized_url,
                        'success': False,
                        'circuit_breaker_open': True,
                        'error': 'Circuit breaker open - network calls temporarily blocked'
                    }

                # 4. HEAD request - get metadata before full fetch
                head_status, head_headers, head_final_url = await session.head(normalized_url)

                if head_status < 200 or head_status >= 400:
                    latency_ms = (time.time() - start_time) * 1000
                    domain_stats.record_request(latency_ms, is_new=False, is_error=True)
                    self._domain_stats.save_stats()
                    return {
                        'url': normalized_url,
                        'success': False,
                        'status_code': head_status,
                        'error': f'HEAD request failed: HTTP {head_status}'
                    }

                # Parse HEAD response headers
                content_length_str = head_headers.get('Content-Length', '')
                content_type_head = head_headers.get('Content-Type', 'text/html').lower()
                is_html_head = 'text/html' in content_type_head

                # Parse Content-Length if available
                content_length = None
                try:
                    if content_length_str:
                        content_length = int(content_length_str)
                except (ValueError, TypeError):
                    pass

                # Early decision: skip full snapshot if too large and not high-value
                skip_full_snapshot = False
                if content_length and content_length > 5 * 1024 * 1024:  # > 5MB
                    if not high_value and not fetch_snapshot:
                        skip_full_snapshot = True
                        logger.info(f"[DEEP READ] Content-Length {content_length} > 5MB, skipping full snapshot for {normalized_url}")

                # Non-HTML content early routing
                is_non_html = not is_html_head

                # 5. Preview GET (max 256KB) - always fetch preview first
                preview_max_bytes = 256 * 1024  # 256KB preview limit
                preview_response = await session.get(normalized_url, max_bytes=preview_max_bytes)

                head_latency_ms = (time.time() - start_time) * 1000

                if not preview_response.success:
                    domain_stats.record_request(head_latency_ms, is_new=False, is_error=True)
                    self._domain_stats.save_stats()
                    return {
                        'url': normalized_url,
                        'success': False,
                        'status_code': preview_response.status,
                        'error': f'Preview fetch failed: HTTP {preview_response.status}'
                    }

                # Use Content-Type from preview (more reliable than HEAD)
                content_type = preview_response.content_type or content_type_head
                is_html = 'text/html' in content_type

                # 6. Preview extraction
                text_preview = ""
                title = ""
                links_out = []
                discovered_feeds = []
                simhash_fingerprint = 0

                # Initialize canonical/structured data variables (used in both HTML and non-HTML paths)
                canonical_url = None
                json_ld_objects = []
                opengraph_meta = {}

                if is_html:
                    # HTML: RustMiner extraction from preview
                    miner = self._orch._rust_miner
                    preview_html = preview_response.text_preview(max_chars=50000)

                    if not miner:
                        # Fallback: use content_extractor for text extraction (no raw HTML)
                        from .tools.content_extractor import extract_main_text_from_html, extract_content_bounded
                        text_preview = extract_main_text_from_html(preview_html, max_chars=5000)
                        # Extract title/links as fallback
                        extracted = extract_content_bounded(url=normalized_url, html=preview_html, max_text_chars=20000)
                        if not title:
                            title = extracted.title
                        if not links_out and extracted.links:
                            links_out = [{"url": u, "score": 0.5, "anchor_text": "", "context_snippet": ""} for u in extracted.links[:50]]
                    else:
                        mined = miner.mine_html(preview_html, url=normalized_url)
                        text_preview = mined.content[:5000] if len(mined.content) > 5000 else mined.content
                        title = mined.title

                        # Links extraction (max 50)
                        links_out = miner.extract_links(
                            preview_html,
                            base_url=normalized_url,
                            max_links=50
                        )

                        # RSS/Atom Feed Discovery
                        try:
                            feed_result = self._feed_discoverer.discover_feeds(
                                preview_html[:50000],
                                base_url=normalized_url
                            )
                            if feed_result.feed_urls:
                                logger.info(f"[RSS DISCOVERY] Found {len(feed_result.feed_urls)} feeds via {feed_result.discovery_method}")
                                discovered_feeds = feed_result.feed_urls
                        except Exception as e:
                            logger.debug(f"[RSS DISCOVERY] Failed: {e}")

                        # CANONICAL URL + STRUCTURED DATA HARVEST
                        canonical_url = None
                        og_url = None
                        json_ld_objects = []
                        opengraph_meta = {}

                        try:
                            import json

                            # Extract <link rel="canonical">
                            canonical_match = re.search(r'<link[^>]+rel=["\']canonical["\'][^>]+href=["\']([^"\']+)["\']', preview_html, re.I)
                            if not canonical_match:
                                canonical_match = re.search(r'<link[^>]+href=["\']([^"\']+)["\'][^>]+rel=["\']canonical["\']', preview_html, re.I)
                            if canonical_match:
                                canonical_url = canonical_match.group(1)

                            # Extract og:url
                            og_url_match = re.search(r'<meta[^>]+property=["\']og:url["\'][^>]+content=["\']([^"\']+)["\']', preview_html, re.I)
                            if not og_url_match:
                                og_url_match = re.search(r'<meta[^>]+content=["\']([^"\']+)["\'][^>]+property=["\']og:url["\']', preview_html, re.I)
                            if og_url_match:
                                og_url = og_url_match.group(1)

                            # Determine canonical URL (prefer canonical, then og:url)
                            if canonical_url or og_url:
                                canonical_url = canonical_url or og_url
                                # Normalize canonical URL using existing logic
                                canonical_parsed = urlparse(canonical_url)
                                tracking_params = {'utm_source', 'utm_medium', 'utm_campaign', 'utm_term',
                                                 'utm_content', 'fbclid', 'gclid', 'ref', 'source'}
                                canon_query = parse_qs(canonical_parsed.query)
                                filtered_params = {k: v for k, v in canon_query.items()
                                                 if k.lower() not in tracking_params}
                                new_query = urlencode(filtered_params, doseq=True)
                                canonical_url = urlunparse((
                                    canonical_parsed.scheme, canonical_parsed.netloc, canonical_parsed.path,
                                    canonical_parsed.params, new_query, ''
                                ))

                                if canonical_url != normalized_url:
                                    self._trap_stats['canonical_rewrites'] += 1
                                    logger.info(f"[CANONICAL] Rewrote {normalized_url[:50]}... -> {canonical_url[:50]}")
                                else:
                                    self._trap_stats['canonical_hits'] += 1

                            # Extract JSON-LD (hard limit: 5KB per object, max 3 objects)
                            json_ld_pattern = r'<script[^>]+type=["\']application/ld\+json["\'][^>]*>(.*?)</script>'
                            for i, match in enumerate(re.finditer(json_ld_pattern, preview_html, re.I | re.S)):
                                if i >= 3:  # Max 3 JSON-LD objects
                                    break
                                json_text = match.group(1).strip()[:5000]  # Hard limit 5KB
                                try:
                                    json_obj = json.loads(json_text)
                                    # Store only essential fields (no fulltext)
                                    if isinstance(json_obj, dict):
                                        json_ld_objects.append({
                                            '@type': json_obj.get('@type'),
                                            'headline': json_obj.get('headline', '')[:200],
                                            'datePublished': json_obj.get('datePublished'),
                                            'dateModified': json_obj.get('dateModified'),
                                            'author': json_obj.get('author', {}).get('name', '') if isinstance(json_obj.get('author'), dict) else str(json_obj.get('author', '')),
                                            'sameAs': json_obj.get('sameAs'),
                                            'url': json_obj.get('url'),
                                        })
                                    elif isinstance(json_obj, list):
                                        for item in json_obj[:2]:
                                            if isinstance(item, dict):
                                                json_ld_objects.append({
                                                    '@type': item.get('@type'),
                                                    'headline': item.get('headline', '')[:200],
                                                    'datePublished': item.get('datePublished'),
                                                })
                                except json.JSONDecodeError:
                                    pass

                            # Extract OpenGraph/Twitter meta
                            og_props = ['title', 'description', 'image', 'site_name', 'type', 'locale']
                            twitter_props = ['card', 'title', 'description', 'image']
                            for prop in og_props:
                                match = re.search(r'<meta[^>]+property=["\']og:' + prop + r'["\'][^>]+content=["\']([^"\']+)["\']', preview_html, re.I)
                                if not match:
                                    match = re.search(r'<meta[^>]+content=["\']([^"\']+)["\'][^>]+property=["\']og:' + prop + r'["\']', preview_html, re.I)
                                if match:
                                    opengraph_meta[f'og:{prop}'] = match.group(1)[:300]  # Limit length
                            for prop in twitter_props:
                                match = re.search(r'<meta[^>]+name=["\']twitter:' + prop + r'["\'][^>]+content=["\']([^"\']+)["\']', preview_html, re.I)
                                if not match:
                                    match = re.search(r'<meta[^>]+content=["\']([^"\']+)["\'][^>]+name=["\']twitter:' + prop + r'["\']', preview_html, re.I)
                                if match:
                                    opengraph_meta[f'twitter:{prop}'] = match.group(1)[:300]

                            if json_ld_objects or opengraph_meta:
                                logger.debug(f"[CANONICAL] Extracted {len(json_ld_objects)} JSON-LD, {len(opengraph_meta)} OG meta")

                        except Exception as e:
                            logger.debug(f"[CANONICAL] Structured data extraction failed: {e}")

                        # Sprint 33: Send JSON-LD to GraphCoordinator
                        if json_ld_objects and self._graph_coordinator:
                            try:
                                await self._graph_coordinator.add_entities_from_jsonld(json_ld_objects)
                            except Exception as e:
                                logger.warning(f"Failed to add JSON-LD entities to graph: {e}")

                # PAGE-TYPE ROUTING: Detect page type from heuristics
                page_type = "unknown"
                page_type_signals = []

                if is_html:
                    # Heuristic 1: JSON-LD @type -> article, product, organization, etc.
                    for jld in json_ld_objects:
                        jld_type = jld.get('@type', '')
                        if jld_type:
                            page_type_signals.append(f'json_ld:{jld_type}')
                            if jld_type.lower() in ('article', 'blogpost', 'newsarticle', 'blogposting',
                                                    'webpage', 'techarticle', 'scholarlyarticle'):
                                page_type = "article"
                                break
                            elif jld_type.lower() in ('product', 'book', 'movie', 'recipe', 'event',
                                                       'course', 'videoobject', 'audiobject'):
                                page_type = "doc"  # Structured entity page
                                break

                    # Heuristic 2: OpenGraph type
                    if page_type == "unknown":
                        og_type = opengraph_meta.get('og:type', '')
                        if og_type:
                            page_type_signals.append(f'og:{og_type}')
                            if og_type.lower() in ('article', 'book', 'profile', 'product',
                                                   'video', 'music', 'website'):
                                if og_type.lower() == 'article':
                                    page_type = "article"
                                elif og_type.lower() == 'profile':
                                    page_type = "profile"
                                else:
                                    page_type = "doc"

                    # Heuristic 3: Link count vs text length -> listing vs article
                    if page_type == "unknown":
                        text_len = len(text_preview)
                        link_count = len(links_out)
                        if link_count > 0 and text_len > 0:
                            link_density = link_count / (text_len / 1000)  # links per 1K chars
                            if link_density > 5 and text_len < 5000:
                                page_type = "listing"
                                page_type_signals.append(f'high_link_density:{link_density:.1f}')
                            elif link_density < 1 and text_len > 2000:
                                page_type = "article"
                                page_type_signals.append(f'low_link_density:{link_density:.1f}')

                    # Heuristic 4: Profile patterns (author, user, member)
                    if page_type == "unknown":
                        profile_patterns = (r'/profile/', r'/user/', r'/member/', r'/author/',
                                          r'/people/', r'@', r'/u/')
                        if any(re.search(p, normalized_url, re.I) for p in profile_patterns):
                            page_type = "profile"
                            page_type_signals.append('url_pattern:profile')

                    # Heuristic 5: Listing patterns
                    if page_type == "unknown":
                        listing_patterns = (r'/search', r'/products', r'/items', r'/list',
                                          r'/category', r'/tag', r'/page/\d+', r'\?page=')
                        if any(re.search(p, normalized_url, re.I) for p in listing_patterns):
                            page_type = "listing"
                            page_type_signals.append('url_pattern:listing')

                else:
                    # Non-HTML: treat as doc
                    page_type = "doc"
                    page_type_signals.append(f'non_html:{content_type}')

                logger.info(f"[PAGE TYPE] url={normalized_url[:50]}... type={page_type} signals={','.join(page_type_signals[:3])}")

                # API ENDPOINT INFERENCE: If low text and embedded JSON, try API endpoints
                api_previews = []
                low_text = len(text_preview) < 500
                embedded_json = None

                # Try to get embedded JSON from metadata extractor
                if hasattr(self, '_metadata_extractor') and low_text:
                    try:
                        # Re-extract embedded JSON from body bytes
                        if full_body_bytes:
                            embedded_json_str = full_body_bytes.decode('utf-8', errors='ignore')
                            # Look for __NEXT_DATA__ or similar
                            next_data_match = re.search(r'<script[^>]*id="__NEXT_DATA__"[^>]*>([^<]+)</script>', embedded_json_str)
                            if next_data_match:
                                embedded_json = json.loads(next_data_match.group(1))
                            else:
                                # Try window.__NUXT__ or similar
                                nuxt_match = re.search(r'window\.__NUXT__=([^;]+);', embedded_json_str)
                                if nuxt_match:
                                    embedded_json = json.loads(nuxt_match.group(1))

                        # Run API inference if we have embedded JSON
                        if embedded_json:
                            api_previews = await self.infer_api_endpoints(
                                normalized_url,
                                embedded_json,
                                max_candidates=6,
                                max_fetches=2
                            )
                            logger.info(f"[API INFER] url={normalized_url[:40]}... candidates={len(api_previews)}")
                    except Exception as e:
                        logger.debug(f"[API INFER] failed: {e}")

                # Store API preview digests if we got any
                api_digests = []
                if api_previews:
                    for api in api_previews:
                        if api.get('digest'):
                            api_digests.append(api['digest'])
                    logger.info(f"[API FETCH] url={normalized_url[:40]}... previews={len(api_digests)}")

                # Compute SimHash from preview for deduplication
                text_preview_lower = text_preview.lower()[:2000]
                simhash_fingerprint = self._simhash.compute(text_preview_lower)

                # Check near-duplicate before full snapshot
                is_duplicate = False
                dup_evidence_id = None
                for existing_id, existing_hash in self._simhash_fingerprints.items():
                    if self._simhash.is_near_duplicate(simhash_fingerprint, existing_hash, threshold=5):
                        is_duplicate = True
                        dup_evidence_id = existing_id
                        break

                if is_duplicate:
                    logger.info(f"[SIMHASH] Near-duplicate detected for {normalized_url} (dup of {dup_evidence_id})")
                    domain_stats.record_request(head_latency_ms, is_new=False, is_dedup=True)
                    self._domain_stats.save_stats()
                    return {
                        'url': normalized_url,
                        'success': True,
                        'is_near_duplicate': True,
                        'duplicate_of': dup_evidence_id,
                        'simhash': simhash_fingerprint,
                        'text_preview': text_preview,
                        'text_hash': hashlib.sha256(text_preview.encode()).hexdigest()[:16],
                        'title': title,
                        'content_type': content_type,
                        'fetched_at': preview_response.fetched_at,
                        'links_out': links_out,
                        'metadata': {
                            'final_url': preview_response.final_url,
                            'snapshot_stored': False,
                            'discovered_feeds': discovered_feeds if is_html else [],
                            'domain_yield_score': domain_stats.yield_score,
                            'preview_only': True,
                            # Canonical URL for dedup
                            'canonical_url': canonical_url if is_html else None,
                            'url_normalized': canonical_url if is_html and canonical_url else normalized_url,
                            # Structured data (if HTML)
                            'json_ld': json_ld_objects if is_html and json_ld_objects else None,
                            'opengraph': opengraph_meta if is_html and opengraph_meta else None,
                            'page_type': page_type if is_html else 'doc',
                            'page_type_signals': page_type_signals if is_html else [],
                        }
                    }

                # Sprint 29: Progressive document parsing - estimate document value
                # Sprint 29: Use override if provided (for testing)
                if value_estimate_override is not None:
                    value_estimate = value_estimate_override
                else:
                    value_estimate = {"final_score": 0.5}
                    context_query = context.get('query', '') if context else ''

                    if DOCUMENT_INTELLIGENCE_AVAILABLE and DocumentIntelligenceEngine:
                        try:
                            doc_intel = DocumentIntelligenceEngine()
                            value_estimate = doc_intel.probe(
                                normalized_url,
                                preview_response.body_bytes,
                                query=context_query
                            )
                            logger.debug(f"[PROGRESSIVE] value_estimate={value_estimate.get('final_score', 0.5):.2f} for {normalized_url[:40]}")
                        except Exception as e:
                            logger.debug(f"[PROGRESSIVE] probe failed, using default: {e}")

                # 7. Full snapshot decision
                snapshot_entry = None
                extracted_metadata = None
                full_body_bytes = preview_response.body_bytes
                fetch_reason = None

                # Sprint 29: Use blended value score for decision
                final_score = value_estimate.get('final_score', 0.5)

                # Decide whether to fetch full snapshot
                should_fetch_full = False

                if fetch_snapshot or high_value:
                    should_fetch_full = True
                    fetch_reason = "explicitly requested"
                elif final_score > 0.7:
                    # Sprint 29: High value estimate triggers deep parse
                    should_fetch_full = True
                    fetch_reason = f"value_estimate={final_score:.2f}"
                elif is_non_html:
                    should_fetch_full = True
                    fetch_reason = "non-HTML content"
                elif not skip_full_snapshot and domain_health_good:
                    should_fetch_full = True
                    fetch_reason = "good domain health"
                elif content_length and content_length <= 5 * 1024 * 1024 and not domain_health_poor:
                    should_fetch_full = True
                    fetch_reason = "small content size"

                # DomainLimiter integration: poor health = prefer preview only
                if domain_health_poor and not high_value:
                    should_fetch_full = False
                    logger.info(f"[DOMAIN LIMITER] Skipping full snapshot for {domain} due to poor health")

                if should_fetch_full:
                    # Fetch full content (up to 5MB)
                    if not skip_full_snapshot:
                        try:
                            full_max_bytes = 5 * 1024 * 1024  # 5MB limit
                            if content_length is None or content_length > preview_max_bytes:
                                # Need to fetch more than preview
                                full_response = await session.get(normalized_url, max_bytes=full_max_bytes)
                                if full_response.success:
                                    full_body_bytes = full_response.body_bytes
                                    logger.debug(f"[DEEP READ] Fetched full content: {len(full_body_bytes)} bytes")
                        except Exception as e:
                            logger.warning(f"[DEEP READ] Full fetch failed, using preview: {e}")

                    # Generate evidence_id if not provided
                    if evidence_id is None:
                        evidence_id = hashlib.sha256(normalized_url.encode()).hexdigest()[:32]

                    # Store snapshot (gzip for storage efficiency)
                    try:
                        # Budget check: snapshot writes
                        allowed, reason = self._budget_manager.check_snapshot_allowed()
                        if not allowed:
                            logger.info(f"[BUDGET] action=full_snapshot allowed=False reason={reason} fallback=preview_only")
                            snapshot_entry = None
                        else:
                            # Compress for storage (M1 8GB: reduce disk I/O)
                            compressed_body = gzip.compress(full_body_bytes, compresslevel=6)
                            snapshot_entry = await self._snapshot_storage.store_snapshot(
                                evidence_id=evidence_id,
                                url=normalized_url,
                                content_bytes=compressed_body,
                                content_type=content_type,
                                metadata={
                                    'fetched_at': preview_response.fetched_at,
                                    'latency_ms': head_latency_ms,
                                    'content_length': len(full_body_bytes),
                                    'compressed': True,
                                    'fetch_reason': fetch_reason
                                }
                            )
                            self._budget_manager.record_snapshot_write()
                            logger.info(f"[BUDGET] action=full_snapshot allowed=True writes={self._budget_manager._snapshot_writes}")
                            logger.info(f"[DEEP READ] Snapshot stored for {normalized_url} ({len(full_body_bytes)} bytes, reason: {fetch_reason})")

                        # Create EvidencePacket if snapshot stored OR contested/drift/high_value
                        if snapshot_entry or contested or drift or high_value:
                            try:
                                # Build evidence packet
                                from .knowledge.atomic_storage import EvidencePacket

                                # Compute text_hash early (needed for EvidencePacket)
                                text_hash = hashlib.sha256(text_preview.encode()).hexdigest()[:16] if text_preview else ""

                                # Headers digest (selected headers only, not full)
                                headers_for_digest = {}
                                if preview_response.headers:
                                    for h in ['content-type', 'content-length', 'server', 'date', 'cache-control']:
                                        if h.lower() in preview_response.headers:
                                            headers_for_digest[h] = preview_response.headers[h.lower()]
                                headers_digest = hashlib.sha256(
                                    json.dumps(headers_for_digest, sort_keys=True).encode()
                                ).hexdigest()[:16]

                                # Metadata digests (json-ld, opengraph - not full objects)
                                metadata_digests = {}
                                if extracted_metadata:
                                    if extracted_metadata.json_ld:
                                        metadata_digests['json_ld_hash'] = hashlib.sha256(
                                            json.dumps(extracted_metadata.json_ld, sort_keys=True).encode()
                                        ).hexdigest()[:16]
                                    if extracted_metadata.opengraph:
                                        metadata_digests['opengraph_hash'] = hashlib.sha256(
                                            json.dumps(extracted_metadata.opengraph, sort_keys=True).encode()
                                        ).hexdigest()[:16]

                                # Add API preview digests
                                if api_digests:
                                    metadata_digests['api_previews_hash'] = hashlib.sha256(
                                        '|'.join(api_digests).encode()
                                    ).hexdigest()[:16]

                                # SECURITY PIPELINE: Analyze text for evidence
                                security_analysis = {}
                                if self._orch._security_mgr:
                                    try:
                                        # 1. Sanitize title and preview for logs
                                        if title:
                                            sanitized_title = self._orch._security_mgr.sanitize_for_logs(title)
                                            # Replace title with sanitized version for packet
                                            title = sanitized_title

                                        # 2. Analyze unicode in title and preview
                                        if title:
                                            title_unicode = self._orch._security_mgr.analyze_unicode(title, context='title')
                                            security_analysis['title_unicode_hash'] = title_unicode.get('findings_hash', '')

                                        if text_preview:
                                            preview_unicode = self._orch._security_mgr.analyze_unicode(text_preview[:2000], context='preview')
                                            security_analysis['preview_unicode_hash'] = preview_unicode.get('findings_hash', '')

                                        # 3. Analyze text payload for encodings and hash IoCs
                                        if text_preview:
                                            text_analysis = self._orch._security_mgr.analyze_text_payload(text_preview[:6000])
                                            security_analysis['encoding_chain_summary'] = text_analysis.get('encoding_chain_summary', '')
                                            security_analysis['hash_types'] = text_analysis.get('hash_types', [])
                                            security_analysis['hash_count'] = text_analysis.get('hash_count', 0)

                                        # 4. Record PII sanitization status
                                        security_analysis['pii_sanitized'] = True  # Applied

                                        # Add to metadata digests (only hashes/summaries)
                                        if security_analysis.get('title_unicode_hash'):
                                            metadata_digests['unicode_title_hash'] = security_analysis['title_unicode_hash']
                                        if security_analysis.get('preview_unicode_hash'):
                                            metadata_digests['unicode_preview_hash'] = security_analysis['preview_unicode_hash']
                                        if security_analysis.get('encoding_chain_summary'):
                                            metadata_digests['encoding_chain_summary_hash'] = hashlib.sha256(
                                                security_analysis['encoding_chain_summary'].encode()
                                            ).hexdigest()[:16]

                                        # Log security event to Decision Ledger (hashed only)
                                        logger.info(f"[SECURITY EVENT] kind=security_text_analysis evidence_id={evidence_id[:12]} hash_types={security_analysis.get('hash_types', [])}")

                                    except Exception as e:
                                        logger.warning(f"Security analysis failed: {e}")

                                # LANGUAGE DETECTION: Add lang metadata for dedup binning
                                lang_detection = {}
                                if text_preview:
                                    try:
                                        from .utils.language import FastLangDetector
                                        lang_detector = FastLangDetector()
                                        lang_detection = lang_detector.detect(text_preview)
                                        # Add to metadata digests
                                        if lang_detection.get('lang'):
                                            metadata_digests['lang_code'] = lang_detection['lang']
                                        if lang_detection.get('conf_bucket'):
                                            metadata_digests['lang_conf_bucket'] = lang_detection['conf_bucket']
                                        if lang_detection.get('lang_hash'):
                                            metadata_digests['lang_hash'] = lang_detection['lang_hash']
                                    except Exception as e:
                                        logger.debug(f"Language detection failed: {e}")

                                # Flags
                                flags = {
                                    'stale': False,
                                    'swr': False,  # stale-while-revalidate
                                    'blocked': False,
                                }

                                # Snapshot ref (pointer, not full content)
                                snapshot_ref = {}
                                if snapshot_entry:
                                    is_encrypted = getattr(self._snapshot_storage, '_encrypt_at_rest', False)
                                    snapshot_ref = {
                                        'blob_hash': snapshot_entry.content_hash,
                                        'path': snapshot_entry.snapshot_path,
                                        'size': snapshot_entry.size_bytes,
                                        'encrypted': is_encrypted,
                                    }

                                # Create and store packet
                                packet = EvidencePacket(
                                    evidence_id=evidence_id,
                                    url=normalized_url,
                                    final_url=preview_response.final_url if preview_response else normalized_url,
                                    domain=domain,
                                    fetched_at=preview_response.fetched_at if preview_response else time.time(),
                                    status=preview_response.status if preview_response else 0,
                                    headers_digest=headers_digest,
                                    snapshot_ref=snapshot_ref,
                                    content_hash=text_hash,
                                    simhash=str(simhash_fingerprint) if simhash_fingerprint else None,
                                    page_type=content_type,
                                    metadata_digests=metadata_digests,
                                    flags=flags,
                                    graph_refs={'node_ids': [], 'edge_ids': []},
                                )

                                # Extract claims from preview text
                                if text_preview:
                                    # Sanitize the full preview text (max 50k chars) – no trim yet
                                    if self._orch and self._orch._security_mgr:
                                        sanitized_full = self._orch._security_mgr.sanitize_for_logs(text_preview)
                                    else:
                                        sanitized_full = fallback_sanitize(text_preview)

                                    # Now trim to 3000 chars for claim extraction
                                    claims = Claim.create_from_text(
                                        sanitized_full[:3000],
                                        evidence_id,
                                        hermes_available=False
                                    )
                                    packet.add_claims(claims)

                                    # Add to cluster index
                                    clusters_updated = 0
                                    for claim in claims:
                                        self._claim_index.add_evidence_to_cluster(
                                            claim_id=claim.claim_id,
                                            subject=claim.subject,
                                            predicate=claim.predicate,
                                            object_variant=claim.object,
                                            evidence_id=evidence_id,
                                            domain=domain,
                                            polarity=claim.polarity
                                        )
                                        clusters_updated += 1

                                    logger.info(f"[CLAIM] extracted={len(claims)} packet={evidence_id[:12]} clusters_updated={clusters_updated}")

                                # Store packet on disk
                                packet_stored = self._evidence_packet_storage.store_packet(evidence_id, packet)
                                logger.info(f"[EVIDENCE PACKET] Created for {evidence_id}: stored={packet_stored}")

                                # Log evidence_packet event with trimmed payload
                                if packet_stored:
                                    packet_path = str(self._evidence_packet_storage._get_packet_path(evidence_id))
                                    summary = {
                                        'url': normalized_url,
                                        'domain': domain,
                                        'status': preview_response.status if preview_response else 0,
                                        'page_type': content_type,
                                        'snapshot_stored': snapshot_entry is not None,
                                    }
                                    self._evidence_log.create_evidence_packet_event(
                                        evidence_id=evidence_id,
                                        packet_path=packet_path,
                                        summary=summary,
                                        confidence=0.9 if high_value else 0.7,
                                    )
                                    logger.info(f"[EVIDENCE LOG] evidence_packet event logged for {evidence_id}")

                            except Exception as e:
                                logger.warning(f"[EVIDENCE PACKET] Failed to create: {e}")
                    except Exception as e:
                        logger.warning(f"[DEEP READ] Snapshot storage failed: {e}")

                    # Non-HTML metadata extraction (top-K gating)
                    if is_non_html and snapshot_entry:
                        try:
                            extracted_metadata = await self._metadata_extractor.extract(
                                full_body_bytes,
                                content_type
                            )
                            # Update title if extracted
                            if extracted_metadata.title:
                                title = extracted_metadata.title
                        except Exception as e:
                            logger.debug(f"[METADATA] Extraction failed: {e}")

                # Store SimHash fingerprint
                if evidence_id:
                    self._simhash_fingerprints[evidence_id] = simhash_fingerprint

                # 8. Calculate content hash
                text_hash = hashlib.sha256(text_preview.encode()).hexdigest()[:16]

                # Update DomainStats (success)
                is_new_content = text_hash not in self._processed_hashes
                total_latency_ms = (time.time() - start_time) * 1000
                domain_stats.record_request(total_latency_ms, is_new=is_new_content)
                self._domain_stats.save_stats()

                # Update PatternStats (new_doc or dedup based on is_new_content)
                result_type = 'new_doc' if is_new_content else 'dedup'
                pattern_score = domain_stats.yield_score  # Use domain yield as proxy
                self._pattern_stats.update(domain, normalized_url, result_type, pattern_score)

                result = {
                    'url': normalized_url,
                    'title': title,
                    'text_preview': text_preview,
                    'text_hash': text_hash,
                    'simhash': simhash_fingerprint,
                    'content_type': content_type,
                    'fetched_at': preview_response.fetched_at,
                    'links_out': links_out,
                    'links_count': len(links_out),
                    'status_code': preview_response.status,
                    'truncated': preview_response.truncated,
                    'success': True,
                    'is_near_duplicate': False,
                    'domain': domain,
                    'metadata': {
                        'final_url': preview_response.final_url,
                        'content_length': len(full_body_bytes),
                        'blocked_by_robots': False,
                        'latency_ms': total_latency_ms,
                        'snapshot_stored': snapshot_entry is not None,
                        'snapshot_path': snapshot_entry.snapshot_path if snapshot_entry else None,
                        'extracted_metadata': extracted_metadata.__dict__ if extracted_metadata else None,
                        'discovered_feeds': discovered_feeds,
                        'domain_yield_score': domain_stats.yield_score,
                        'domain_health': 'poor' if domain_health_poor else ('good' if domain_health_good else 'neutral'),
                        'preview_only': snapshot_entry is None,
                        'fetch_reason': fetch_reason if snapshot_entry else None,
                        # Canonical URL for dedup
                        'canonical_url': canonical_url if canonical_url else None,
                        'url_normalized': canonical_url if canonical_url else normalized_url,
                        # Structured data harvest
                        'json_ld': json_ld_objects if json_ld_objects else None,
                        'opengraph': opengraph_meta if opengraph_meta else None,
                        'page_type': page_type,
                        'page_type_signals': page_type_signals,
                        # API endpoint inference results
                        'api_previews': api_previews if api_previews else None,
                        # Sprint 29: Progressive document parsing
                        'value_estimate': value_estimate,
                    }
                }

                # Sprint 39: Deep web hints extraction - add API candidates and Next.js detection to frontier
                if HINTS_AVAILABLE and preview_html:
                    try:
                        hints_extractor = DeepWebHintsExtractor()
                        hints = hints_extractor.extract(
                            url=normalized_url,
                            html_preview=preview_html[:50000]  # bounded to 50KB
                        )

                        # Add API candidates to frontier with novelty boost
                        if hints.api_candidates and hasattr(self, '_url_frontier'):
                            for api_url in hints.api_candidates[:5]:  # max 5 per page
                                self._url_frontier.push(api_url, novelty_score=0.85)

                        # Detect Next.js and add /_next/data/ endpoint
                        if hints.js_markers.get('__NEXT_DATA__') or hints.js_markers.get('next_data'):
                            try:
                                from urllib.parse import urlparse, urlunparse
                                parsed = urlparse(normalized_url)
                                path = parsed.path.rstrip('/') or '/index'
                                next_url = urlunparse((
                                    parsed.scheme,
                                    parsed.netloc,
                                    f"/_next/data/build-id{path}.json",
                                    '', '', ''
                                ))
                                if hasattr(self, '_url_frontier'):
                                    self._url_frontier.push(next_url, novelty_score=0.95)
                            except Exception:
                                pass

                        # Store hints in result metadata
                        result['metadata']['deep_web_hints'] = hints.to_dict()

                        # Flag auth-required pages
                        if any(f.get('type') == 'password' for form in hints.forms for f in form.get('fields', [])):
                            result['metadata']['requires_auth'] = True
                    except Exception as e:
                        logger.debug(f"[HINTS] Extraction skipped: {e}")

                # ----- Sprint 47: Async fingerprinting activation -----
                # CT Log scanning
                await self._ensure_ct_log_scanner()
                if self._ct_log_scanner and domain:
                    try:
                        subdomains = await self._ct_log_scanner.scan_domain(domain)
                        if subdomains:
                            result['metadata']['ct_subdomains'] = subdomains[:20]  # bounded
                    except Exception as e:
                        logger.warning(f"[CT] Scan failed for {domain}: {e}")

                # Favicon hashing
                await self._ensure_favicon_hasher()
                if self._favicon_hasher:
                    try:
                        favicon_url = self._guess_favicon_url(normalized_url)
                        if favicon_url:
                            favicon_bytes = await self._fetch_favicon(favicon_url)
                            if favicon_bytes:
                                favicon_hash = self._favicon_hasher.hash_favicon(favicon_bytes)
                                if favicon_hash:
                                    result['metadata']['favicon_hash'] = favicon_hash
                    except Exception as e:
                        logger.warning(f"[FAVICON] Hashing failed for {normalized_url}: {e}")

                # JS bundle extraction (external .js files)
                if hints and hints.bundle_urls:
                    await self._ensure_js_bundle_extractor()
                    if self._js_bundle_extractor:
                        for bundle_url in hints.bundle_urls[:3]:  # bounded: max 3 bundles per page
                            try:
                                bundle_content = await self._fetch_bundle(bundle_url)
                                if bundle_content:
                                    endpoints = self._js_bundle_extractor.extract_from_js(bundle_content, bundle_url)
                                    if endpoints:
                                        result['metadata'].setdefault('js_bundle_endpoints', []).extend(endpoints[:20])  # bounded
                            except Exception as e:
                                logger.warning(f"[JS] Bundle fetch failed for {bundle_url}: {e}")

                # ----- Sprint 47: Tor escalation decision (sync) -----
                if domain_stats:
                    if self._should_escalate_to_tor(result['metadata'], domain_stats.yield_score, normalized_url):
                        await self._ensure_tor_manager()
                        if self._tor_manager:
                            try:
                                circuit = await self._tor_manager.get_circuit_for_domain(domain)
                                if circuit:
                                    result['metadata']['tor_circuit'] = circuit
                                    logger.info(f"[TOR] Escalated {domain} to Tor circuit {circuit}")
                            except Exception as e:
                                logger.warning(f"[TOR] Escalation failed for {domain}: {e}")

                # ----- Sprint 49: JS Source Maps & Open Storage -----
                await self._run_js_source_map_extraction(hints, result['metadata'])
                await self._run_open_storage_scan(domain, result['metadata'])

                # ----- Sprint 50: GraphRAG Fingerprint Consumption -----
                gc = getattr(self._orch, '_graph_coordinator', None)
                if gc:
                    try:
                        await gc.consume_fingerprint_metadata(normalized_url, result['metadata'])
                    except Exception as e:
                        logger.warning(f"[GRAPH] Fingerprint consumption failed: {e}")

                # ----- Sprint 50: Frontier Priority Boost -----
                fingerprint_boost = self._compute_fingerprint_boost(result['metadata'])
                if fingerprint_boost > 0:
                    for subdomain in result['metadata'].get('ct_subdomains', [])[:5]:  # max 5
                        subdomain_url = f"https://{subdomain}"
                        # Add to frontier with boost - use existing frontier API
                        if hasattr(self, '_frontier') and self._frontier:
                            try:
                                await self._frontier.add(subdomain_url, priority_boost=fingerprint_boost)
                            except Exception:
                                pass  # Frontier add is best-effort

                # ----- Sprint 51: JARM Fingerprint -----
                await self._run_jarm_fingerprint(domain, result['metadata'])

                # ----- Sprint 52: Document Metadata Extraction -----
                if full_body_bytes:
                    await self._run_doc_meta_extraction(normalized_url, full_body_bytes, result['metadata'])

                # Safe logging - all variables may not be defined if early exception occurred
                try:
                    yield_val = domain_stats.yield_score if domain_stats else 0.0
                    logger.info(f"[DEEP READ] {normalized_url} | Domain: {domain} | "
                               f"Type: {content_type} | Snap: {snapshot_entry is not None} | "
                               f"SimHash: {simhash_fingerprint:x} | Yield: {yield_val:.2f} | "
                               f"Health: {'poor' if domain_health_poor else 'good' if domain_health_good else 'neutral'}")
                except Exception:
                    pass  # Skip logging if variables not defined

                logger.debug(f"[DEEP READ] Returning result for {normalized_url}")
                return result

        except Exception as e:
            logger.error(f"Deep read failed: {e}")

            # Check if this is a transient error (eligible for stale cache fallback)
            is_transient = False
            stale_reason = str(e)
            if isinstance(e, aiohttp.ClientResponseError):
                if e.status in {408, 500, 502, 503, 504, 429}:
                    is_transient = True
                    stale_reason = f"HTTP_{e.status}"
            elif isinstance(e, (asyncio.TimeoutError, aiohttp.ClientError)):
                is_transient = True
                stale_reason = type(e).__name__

            # Try stale cache fallback for transient errors
            if is_transient and hasattr(self, '_http_cache') and self._http_cache:
                try:
                    stale_result = self._http_cache.get_stale(normalized_url)
                    if stale_result and stale_result.content:
                        logger.info(f"[CACHE STALE] url={normalized_url} reason={stale_reason} "
                                   f"stale_count={stale_result.stale_count}")

                        # Track stale usage
                        self._http_cache._track_stale_usage(normalized_url)

                        # Return stale content with reduced confidence
                        return {
                            'url': normalized_url,
                            'title': stale_result.metadata.get('title', 'Unknown'),
                            'text_preview': stale_result.content[:5000],
                            'text_hash': stale_result.metadata.get('text_hash', ''),
                            'simhash': 0,
                            'content_type': stale_result.metadata.get('content_type', 'text/html'),
                            'fetched_at': stale_result.metadata.get('fetched_at', time.time()),
                            'links_out': [],
                            'links_count': 0,
                            'status_code': stale_result.metadata.get('status', 200),
                            'truncated': True,
                            'success': True,
                            'is_near_duplicate': False,
                            'domain': domain,
                            'from_stale_cache': True,
                            'stale_reason': stale_reason,
                            'stale_count': stale_result.stale_count,
                            'confidence': 0.5,  # Reduced confidence for stale content
                            'metadata': {
                                'final_url': stale_result.metadata.get('final_url', normalized_url),
                                'content_length': len(stale_result.content),
                                'blocked_by_robots': False,
                                'latency_ms': (time.time() - start_time) * 1000,
                                'snapshot_stored': False,
                                'stale': True,
                                'stale_reason': stale_reason,
                                'domain_yield_score': domain_stats.yield_score if domain_stats else 0.0,
                                'domain_health': 'poor',  # Domain is unhealthy if we're using stale
                                'preview_only': True,
                            }
                        }
                except Exception as stale_error:
                    logger.debug(f"Stale cache fallback failed: {stale_error}")

            # Update DomainStats with error
            try:
                latency_ms = (time.time() - start_time) * 1000
                domain_stats = self._domain_stats.get_stats(domain)
                domain_stats.record_request(latency_ms, is_new=False, is_error=True)
                self._domain_stats.save_stats()
            except Exception:
                pass  # Domain stats update failure
            return {'url': url, 'error': str(e), 'success': False}


    def generate_query_variants(
        self,
        query: str,
        depth: DiscoveryDepth,
        analysis: Dict[str, Any]
    ) -> List[str]:
        """Generuje varianty dotazů."""
        variants = [query]

        expanded = self._expander.expand(query)
        variants.extend(expanded)

        modifiers = []
        if depth.value >= DiscoveryDepth.DEEP.value:
            modifiers.extend(['research', 'paper', 'analysis', 'study'])
        if depth.value >= DiscoveryDepth.EXTREME.value:
            modifiers.extend(['archive', 'database', 'registry', 'leaked'])
        if depth.value >= DiscoveryDepth.EXHAUSTIVE.value:
            modifiers.extend(['classified', 'hidden', 'secret', 'steganography'])

        if modifiers:
            for mod in modifiers[:3]:
                variants.append(f"{query} {mod}")

        seen = set()
        unique = []
        for v in variants:
            v_lower = v.lower()
            if v_lower not in seen:
                seen.add(v_lower)
                unique.append(v)

        limits = {
            DiscoveryDepth.SURFACE: 3,
            DiscoveryDepth.DEEP: 8,
            DiscoveryDepth.EXTREME: 15,
            DiscoveryDepth.EXHAUSTIVE: 25
        }

        return unique[:limits.get(depth, 8)]

    async def execute_parallel_search(
        self,
        queries: List[str],
        strategy: AutonomousStrategy,
        depth: DiscoveryDepth,
        max_results: int = 20
    ) -> List[Dict[str, Any]]:
        """
        Provede paralelní vyhledávání napříč všemi zdroji - M1 8GB optimized.

        Používá asyncio.as_completed pro průběžné zpracování a early-stop.

        Args:
            queries: Seznam dotazů
            strategy: Vyhledávací strategie
            depth: Hloubka prohledávání
            max_results: Max počet výsledků (M1 8GB: default 20)

        Returns:
            Seznam výsledků s findings a sources
        """
        all_results = []
        tasks = []
        completed_count = 0
        novelty_degradation = 0  # Počet po sobě jdoucích nízké-novelty výsledků

        # Kontrola RAM před startem
        self._maybe_gc()

        # Vytvoř tasky pro všechny zdroje
        for source_type in strategy.selected_sources:
            task = self._search_source_with_resilience(
                source_type, queries, strategy, depth
            )
            tasks.append((source_type, asyncio.create_task(task)))

        # Zpracovávej výsledky jakmile jsou hotové (as_completed)
        pending = [task for _, task in tasks]
        source_map = {id(task): source_type for source_type, task in tasks}

        for coro in asyncio.as_completed(pending, timeout=30):
            try:
                result = await coro
                completed_count += 1

                # Měř novelty (nové findings/sources ratio)
                pre_findings = len(self._findings_heap)
                pre_sources = len(self._sources_heap)

                # Zpracuj výsledek přes _search_source_with_resilience
                if result and isinstance(result, dict):
                    # Přidej findings do top-K heapu
                    for finding in result.get('findings', [])[:10]:  # Max 10 per source
                        score = getattr(finding, 'confidence', 0.5)
                        self._add_finding_with_limit(finding, score)

                    # Přidej sources do top-K heapu
                    for source in result.get('sources', [])[:5]:  # Max 5 per source
                        score = getattr(source, 'reliability', 0.5)
                        self._add_source_with_limit(source, score)

                    # Ulož zkrácený výsledek
                    source_type_str = result.get('source_type', 'unknown')
                    all_results.append({
                        'source_type': source_type_str,
                        'findings_count': len(result.get('findings', [])),
                        'sources_count': len(result.get('sources', [])),
                        'preview': result.get('findings', [])[:3] if result.get('findings') else []
                    })

                    # Sprint 34: Update bandit reward
                    if self._source_bandit is not None:
                        try:
                            # Map SourceType to bandit source string
                            source_map = {
                                'SURFACE_WEB': 'web',
                                'ACADEMIC': 'academic',
                                'ARCHIVE': 'archive',
                                'OSINT': 'osint',
                                'DARK_WEB': 'darkweb',
                                'HIDDEN_DB': 'blockchain',
                            }
                            bandit_key = source_map.get(source_type_str, source_type_str.lower() if isinstance(source_type_str, str) else 'web')

                            # Reward = poměr užitečných findings / celkem (0..1)
                            findings = result.get('findings', [])
                            total = len(findings)
                            useful = len([f for f in findings if getattr(f, 'confidence', 0) > 0.7])
                            if total > 0:
                                reward = useful / total
                                self._source_bandit.update(bandit_key, reward)
                                logger.debug(f"[BANDIT] Updated {bandit_key} with reward={reward:.2f}")
                        except Exception as e:
                            logger.warning(f"[BANDIT] Update failed: {e}")

                # Vypočti novelty tohoto výsledku
                post_findings = len(self._findings_heap)
                post_sources = len(self._sources_heap)

                new_findings = post_findings - pre_findings
                new_sources = post_sources - pre_sources

                if new_findings == 0 and new_sources == 0:
                    novelty_degradation += 1
                else:
                    novelty_degradation = 0

                # Early stop podmínky
                if len(all_results) >= max_results:
                    logger.info(f"🛑 Early stop: reached max_results ({max_results})")
                    break

                if novelty_degradation >= 3:
                    logger.info(f"🛑 Early stop: novelty degraded ({novelty_degradation} consecutive low-novelty)")
                    break

                # RAM check každých 5 výsledků
                if completed_count % 5 == 0:
                    self._maybe_gc()

            except asyncio.TimeoutError:
                logger.warning("⏱️ Search task timed out")
            except Exception as e:
                logger.warning(f"Source failed: {e}")

        # Zruš zbylé tasky
        for task in pending:
            if not task.done():
                task.cancel()
                try:
                    await task
                except asyncio.CancelledError:
                    pass

        logger.info(f"✅ Parallel search: {len(all_results)} results, "
                   f"findings_heap: {len(self._findings_heap)}, "
                   f"sources_heap: {len(self._sources_heap)}")

        return all_results

    async def _search_source_with_resilience(
        self,
        source_type: SourceType,
        queries: List[str],
        strategy: AutonomousStrategy,
        depth: DiscoveryDepth
    ) -> Dict[str, Any]:
        """
        Vyhledávání s resilience patternem - M1 8GB optimized.

        Používá top-K heaps místo listů a respektuje hard limity.
        """
        local_findings: List[Tuple[float, Any]] = []  # (score, finding)
        local_sources: List[Tuple[float, Any]] = []   # (score, source)
        processed_urls: Set[str] = set()

        try:
            if source_type == SourceType.SURFACE_WEB:
                for query in queries[:3]:  # Max 3 queries per source
                    result = await self._resilience.execute_with_resilience(
                        'surface_web',
                        self.execute_surface_search,
                        None,
                        query
                    )
                    if result:
                        for finding in result.get('findings', [])[:self.MAX_FINDINGS_IN_RAM]:
                            score = getattr(finding, 'confidence', 0.5)
                            local_findings.append((-score, finding))  # Negativní pro max-heap
                        for source in result.get('sources', [])[:self.MAX_SOURCES_IN_RAM]:
                            url = getattr(source, 'url', '')
                            if url not in processed_urls:
                                processed_urls.add(url)
                                score = getattr(source, 'reliability', 0.5)
                                local_sources.append((-score, source))

            elif source_type == SourceType.ACADEMIC:
                for query in queries[:2]:  # Max 2 queries
                    result = await self._resilience.execute_with_resilience(
                        'academic',
                        self.execute_academic_search,
                        None,
                        query
                    )
                    if result:
                        for finding in result.get('findings', [])[:self.MAX_FINDINGS_IN_RAM]:
                            score = getattr(finding, 'confidence', 0.5)
                            local_findings.append((-score, finding))
                        for source in result.get('sources', [])[:self.MAX_SOURCES_IN_RAM]:
                            score = getattr(source, 'reliability', 0.5)
                            local_sources.append((-score, source))

            elif source_type == SourceType.ARCHIVE and self._archive_discovery:
                for query in queries[:2]:
                    result = await self._resilience.execute_with_resilience(
                        'archive',
                        self.execute_archive_search,
                        None,
                        query
                    )
                    if result:
                        for finding in result.get('findings', [])[:self.MAX_FINDINGS_IN_RAM]:
                            score = getattr(finding, 'confidence', 0.5)
                            local_findings.append((-score, finding))
                        for source in result.get('sources', [])[:self.MAX_SOURCES_IN_RAM]:
                            score = getattr(source, 'reliability', 0.5)
                            local_sources.append((-score, source))

            elif source_type == SourceType.OSINT:
                for query in queries[:2]:
                    result = await self._resilience.execute_with_resilience(
                        'osint',
                        self.execute_osint_search,
                        None,
                        query
                    )
                    if result:
                        for finding in result.get('findings', [])[:self.MAX_FINDINGS_IN_RAM]:
                            score = getattr(finding, 'confidence', 0.5)
                            local_findings.append((-score, finding))
                        for source in result.get('sources', [])[:self.MAX_SOURCES_IN_RAM]:
                            score = getattr(source, 'reliability', 0.5)
                            local_sources.append((-score, source))

            elif source_type == SourceType.DARK_WEB and self._dark_web:
                for query in queries[:1]:
                    if strategy.privacy_level != PrivacyLevel.STANDARD:
                        privacy = self._orch._security_mgr.privacy if self._orch._security_mgr else None
                        if privacy and hasattr(privacy, 'execute'):
                            result = await privacy.execute(
                                query=query,
                                research_func=self.execute_dark_web_search
                            )
                            if result and 'data' in result:
                                for finding in result['data'].get('findings', [])[:self.MAX_FINDINGS_IN_RAM]:
                                    score = getattr(finding, 'confidence', 0.5)
                                    local_findings.append((-score, finding))
                                for source in result['data'].get('sources', [])[:self.MAX_SOURCES_IN_RAM]:
                                    score = getattr(source, 'reliability', 0.5)
                                    local_sources.append((-score, source))
                        else:
                            result = await self.execute_dark_web_search(query)
                            if result:
                                for finding in result.get('findings', [])[:self.MAX_FINDINGS_IN_RAM]:
                                    score = getattr(finding, 'confidence', 0.5)
                                    local_findings.append((-score, finding))
                                for source in result.get('sources', [])[:self.MAX_SOURCES_IN_RAM]:
                                    score = getattr(source, 'reliability', 0.5)
                                    local_sources.append((-score, source))

        except Exception as e:
            logger.error(f"Error searching {source_type.value}: {e}")

        # Konverze heapů na seřazené listy (nejvyšší score první)
        local_findings.sort()
        local_sources.sort()

        findings_list = [f[1] for f in local_findings[:self.MAX_FINDINGS_IN_RAM]]

        # Aplikuj reranking na findings pokud máme query
        if queries and findings_list:
            query_for_rerank = queries[0] if queries else ""
            findings_list = await self._rerank_findings(query_for_rerank, findings_list)

        # Sestav result dict pro enrich
        result = {
            'source_type': source_type.value,
            'findings': findings_list,
            'sources': [s[1] for s in local_sources[:self.MAX_SOURCES_IN_RAM]]
        }

        # Aplikuj reputation a temporal enrichment
        query_for_enrich = queries[0] if queries else ""
        result = await self._enrich_result(query_for_enrich, result)

        return result

    # =====================================================================
    # RERANKER METHODS
    # =====================================================================

    async def _rerank_findings(self, query: str, findings: List) -> List:
        """
        Rerank findings using LightweightReranker.
        Pracuje se slice findings[:MAX_RERANK_DOCS] a vrací tento nový list.
        Mění pouze confidence na existujících objektech v slice.
        """
        if not findings:
            return findings

        # Práce se slice – původní findings zůstává nedotčený
        findings_slice = findings[:MAX_RERANK_DOCS]

        docs = []
        for idx, f in enumerate(findings_slice):
            content = f.content if hasattr(f, 'content') else str(f)
            # Sanitizace – vždy
            if self._orch and self._orch._security_mgr:
                content = self._orch._security_mgr.sanitize_for_logs(content)
            else:
                content = fallback_sanitize(content)
            docs.append({
                'idx': idx,
                'content': content,
                'original_score': f.confidence if hasattr(f, 'confidence') else 0.5,
            })

        if self._reranker is None:
            self._reranker = LightweightReranker()

        try:
            reranked_docs = await self._reranker.rerank(query, docs)
        except Exception:
            # Při jakékoli chybě rerankeru vrátíme findings_slice beze změny
            return findings_slice

        for item in reranked_docs:
            # idx může být string (document_id) nebo int
            idx = item.get('idx')
            if idx is None:
                continue
            # Konverze na int pro indexování
            try:
                idx_int = int(idx) if isinstance(idx, str) else idx
            except (ValueError, TypeError):
                continue
            if idx_int < len(findings_slice):  # bezpečnostní kontrola
                if 'reranked_score' in item:
                    findings_slice[idx_int].confidence = item['reranked_score']
                else:
                    findings_slice[idx_int].confidence = item.get('original_score', 0.5)

        return findings_slice

    async def _maybe_rerank_result(self, query: str, result: object) -> object:
        """Pokud result je dict a obsahuje 'findings', aplikuje rerank a findings nahradí."""
        if result and isinstance(result, dict) and result.get("findings"):
            result["findings"] = await self._rerank_findings(query, result["findings"])
        return result

    # =====================================================================
    # REPUTATION & TEMPORAL ENRICHMENT METHODS
    # =====================================================================

    def _apply_reputation(self, findings: List) -> List:
        """
        Multiply confidence by domain reputation.
        Mutates only the 'confidence' attribute of each finding.
        Fail-safe: if any error occurs, skip that finding and continue.
        """
        for f in findings:
            try:
                if hasattr(f, 'url') and f.url:
                    domain = urlparse(f.url).netloc
                    score = get_reputation_score(domain)
                    f.confidence = f.confidence * score
            except Exception:
                # Skip this finding, keep original confidence
                pass
        return findings

    async def _maybe_archive_fallback(self, url: str) -> Optional[Dict]:
        """If drift detected and we have budget, attempt archive retrieval."""
        if should_trigger_archive_fallback():
            increment_archive_fallback()
            # TODO: actual archive fetch (future)
            logger.debug(f"Archive fallback triggered for {url}")
            return {"archive_attempted": True}
        return None

    def _should_fetch_url(self, url: str, title: str = "", snippet: str = "", query: str = "") -> bool:
        """
        Relevance gating before deep_read.
        Returns True if URL should be fetched, False otherwise.
        """
        # Hard cap: if we've already evaluated too many URLs, just allow all.
        if self._gating_eval_count >= self.MAX_GATING_EVALS_PER_RUN:
            return True

        self._gating_eval_count += 1

        # High‑value signals always pass
        if is_high_value_url(url):
            return True

        # Adaptive threshold based on elapsed time (explore vs exploit)
        base_threshold = self.GATING_THRESHOLD
        if hasattr(self, '_run_started_at') and self._run_started_at is not None:
            elapsed = time.time() - self._run_started_at
            if elapsed < EXPLORE_SECONDS:
                base_threshold *= 0.7   # exploration phase
            else:
                base_threshold *= 1.3   # exploitation phase

        # Simple keyword overlap heuristic
        if query:
            query_words = set(query.lower().split())
            if not query_words:
                return True
            text = f"{title} {snippet}".lower()
            word_overlap = len(query_words & set(text.split()))
            score = word_overlap / len(query_words)
            if score >= base_threshold:
                return True
            else:
                return False

        # No query – can't judge, allow by default
        return True

    async def _enrich_result(self, query: str, result: Dict) -> Dict:
        """
        Central seam for post‑processing a result dictionary.
        Modifies result in‑place (findings confidence, adds metadata).
        All exceptions are caught and logged; never breaks the workflow.
        """
        if not result:
            return result

        try:
            if result.get("findings"):
                result["findings"] = self._apply_reputation(result["findings"])
        except Exception as e:
            logger.warning(f"Reputation application failed: {e}")

        if result.get("sources"):
            for src in result["sources"]:
                url = getattr(src, 'url', None)
                if not url:
                    continue
                try:
                    content_hash = getattr(src, 'content_hash', None) or getattr(src, 'text_hash', '')
                    title = getattr(src, 'title', '')
                    if content_hash and title:
                        drift_info = detect_drift(url, content_hash, title)
                        if drift_info:
                            if hasattr(self, '_orch') and hasattr(self._orch, '_evidence_log'):
                                try:
                                    self._orch._evidence_log.create_decision_event(
                                        kind="drift",
                                        summary={"url": url, "changes": list(drift_info['changes'].keys())},
                                        reasons=["content_changed"],
                                        refs={},
                                        confidence=0.8
                                    )
                                except Exception as e:
                                    logger.warning(f"Failed to log drift event: {e}")
                            if should_trigger_archive_fallback():
                                await self._maybe_archive_fallback(url)
                        record_previous_version(url, content_hash, title)
                except Exception as e:
                    logger.warning(f"Temporal processing failed for {url}: {e}")

        # Contradiction detection (low-noise lite) – add inside _enrich_result after processing sources
        if hasattr(self, '_claim_index') and self._claim_index:
            # Check recent clusters (simplified: just last 5)
            try:
                for claim_id in list(self._claim_index._ram_cache.keys())[-5:]:
                    cluster = self._claim_index.get_cluster(claim_id)
                    if not cluster:
                        continue
                    if cluster.predicate not in CONTRADICTION_WHITELIST:
                        continue
                    if len(cluster.domains) < 2:
                        continue

                    # Low-noise lite: normalize and check for differing objects
                    norm_objs = [normalize_text(obj) for obj in cluster.object_variants]
                    if len(set(norm_objs)) > 1:
                        if hasattr(self, '_orch') and hasattr(self._orch, '_evidence_log'):
                            try:
                                self._orch._evidence_log.create_decision_event(
                                    kind="contradiction",
                                    summary={
                                        "subject": cluster.subject,
                                        "predicate": cluster.predicate,
                                        "variants": cluster.object_variants,
                                        "domains": list(cluster.domains)
                                    },
                                    reasons=["low_noise_lite"],
                                    refs={},
                                    confidence=0.9
                                )
                                # Increment contradiction counter in meta
                                if "_meta" not in result:
                                    result["_meta"] = {}
                                result["_meta"]["contradictions"] = result["_meta"].get("contradictions", 0) + 1
                            except Exception as e:
                                logger.warning(f"Failed to log contradiction: {e}")
            except Exception as e:
                logger.warning(f"Contradiction detection failed: {e}")

        return result

    # =====================================================================
    # GRAPH STACK METHODS (M1 8GB Optimized)
    # =====================================================================

    async def _ensure_knowledge_layer(self) -> bool:
        """Lazy initialize knowledge layer and graph RAG."""
        if self._knowledge_layer is not None:
            return True

        try:
            from hledac.universal.knowledge.persistent_layer import PersistentKnowledgeLayer
            from hledac.universal.knowledge.graph_rag import GraphRAGOrchestrator
            from hledac.universal.knowledge.graph_builder import KnowledgeGraphBuilder
            from hledac.universal.knowledge.entity_linker import EntityLinker

            # Sprint 28: Reuse the same PersistentKnowledgeLayer instance from _MemoryManager
            # This ensures unified graph storage across the orchestrator
            memory_graph = self._orch._memory.knowledge_graph if hasattr(self._orch, '_memory') and self._orch._memory else None
            if memory_graph is not None and isinstance(memory_graph, PersistentKnowledgeLayer):
                # Use the shared instance from _MemoryManager
                self._knowledge_layer = memory_graph
                logger.info("[GRAPH] Using shared PersistentKnowledgeLayer from _MemoryManager")
            else:
                # Fallback: create new instance (for backwards compatibility or if not initialized yet)
                self._knowledge_layer = PersistentKnowledgeLayer(
                    db_path=self._orch.config.storage.knowledge_graph_path
                    if hasattr(self._orch.config, 'storage') and hasattr(self._orch.config.storage, 'knowledge_graph_path')
                    else None,
                    enable_cache=False  # Disable cache for M1 8GB
                )
                self._knowledge_layer.initialize()
                logger.info("[GRAPH] Created new PersistentKnowledgeLayer instance")

            # Initialize GraphRAG
            self._graph_rag = GraphRAGOrchestrator(self._knowledge_layer)

            # Initialize graph builder
            self._graph_builder = KnowledgeGraphBuilder()

            # Initialize entity linker
            self._entity_linker = EntityLinker()

            logger.info("[GRAPH] Knowledge layer and GraphRAG initialized")
            return True

        except Exception as e:
            logger.warning(f"[GRAPH] Failed to initialize knowledge layer: {e}")
            return False

    async def _graph_ingest_documents(
        self,
        documents: List[Dict[str, Any]]
    ) -> Dict[str, int]:
        """
        Ingest documents into knowledge graph with deduplication.

        Deterministic doc_id generation using content hash ensures
        duplicate documents are not stored multiple times.

        Args:
            documents: List of documents with 'content', 'url', 'title', etc.

        Returns:
            Dict with nodes_added, edges_added, docs_total, docs_new, docs_dedup counts
        """
        if not await self._ensure_knowledge_layer():
            return {'nodes_added': 0, 'edges_added': 0, 'docs_total': 0, 'docs_new': 0, 'docs_dedup': 0}

        from hledac.universal.knowledge.persistent_layer import NodeType, EdgeType

        nodes_added = 0
        edges_added = 0
        docs_total = len(documents)
        docs_new = 0
        docs_dedup = 0

        # Track edge hashes for runtime deduplication within this batch
        edge_hashes: Set[str] = set()

        try:
            for doc in documents:
                content = doc.get('content', '')
                url = doc.get('url', '')
                title = doc.get('title', '')

                if not content:
                    continue

                # Normalize URL for consistent storage
                normalized_url = normalize_url(url)

                # Generate deterministic doc_id from content hash
                doc_text_for_id = content.strip()
                doc_id = hashlib.sha256(doc_text_for_id.encode('utf-8')).hexdigest()[:32]

                # Check if document already exists using has_node (O(1) lookup)
                if self._knowledge_layer.has_node(doc_id):
                    # Document already exists - touch metadata instead of creating new
                    docs_dedup += 1

                    # Get existing metadata for merge
                    existing_node = self._knowledge_layer._backend.get_node(doc_id)
                    existing_metadata = existing_node.metadata or {} if existing_node else {}
                    existing_urls = existing_metadata.get('urls', [existing_metadata.get('url', '')])
                    if normalized_url and normalized_url not in existing_urls:
                        existing_urls.append(normalized_url)

                    # Update title if current one is better
                    existing_title = existing_metadata.get('title', '')
                    final_title = title if len(title) > len(existing_title) else existing_title

                    # Generate evidence_id for this touch
                    fetched_at_bucket = str(int(time.time() / 3600))
                    evidence_input = f"{normalized_url}|{doc_id}|{fetched_at_bucket}"
                    evidence_id = hashlib.sha256(evidence_input.encode('utf-8')).hexdigest()[:32]

                    # Content hash for ring
                    content_hash = hashlib.sha256(content.encode()).hexdigest()[:16]

                    # Touch node with temporal metadata update
                    self._knowledge_layer.touch_node(
                        doc_id,
                        {
                            'urls': existing_urls,
                            'url': existing_urls[0] if existing_urls else '',
                            'title': final_title,
                            'normalized_url': normalized_url,  # For url_ring
                            'evidence_id': evidence_id,  # For evidence_ring
                            'content_hash': content_hash,  # For content_hash_ring
                            'fetched_at': datetime.utcnow().isoformat()
                        }
                    )

                    logger.debug(f"[GRAPH INGEST] Dedup: doc_id={doc_id[:16]}..., url={normalized_url[:60]}, touched temporal metadata")
                    continue

                # New document - add to knowledge graph
                docs_new += 1

                # Generate deterministic evidence_id for this document
                fetched_at = datetime.utcnow()
                fetched_at_iso = fetched_at.isoformat()
                fetched_at_bucket = str(int(time.time() / 3600))  # Hour bucket
                evidence_input = f"{normalized_url}|{doc_id}|{fetched_at_bucket}" if normalized_url else doc_id
                evidence_id = hashlib.sha256(evidence_input.encode('utf-8')).hexdigest()[:32]

                # Content hash for ring
                content_hash = hashlib.sha256(content.encode()).hexdigest()[:16]

                # Add document as knowledge node with temporal metadata
                node_id = self._knowledge_layer.add_knowledge(
                    content=content[:5000],  # Limit content for M1 8GB
                    node_type=NodeType.DOCUMENT,
                    metadata={
                        'url': normalized_url,
                        'urls': [normalized_url] if normalized_url else [],
                        'title': title,
                        'content_hash': content_hash,
                        'fetched_at': fetched_at_iso,
                        'first_seen': fetched_at_iso,
                        'last_seen': fetched_at_iso,
                        'seen_count': 1,
                        'ingest_count': 1,
                        'evidence_id': evidence_id,
                        'evidence_ring': [evidence_id],  # Initialize ring with first evidence
                        'url_ring': [normalized_url] if normalized_url else [],
                        'content_hash_ring': [content_hash]
                    },
                    node_id=doc_id
                )
                nodes_added += 1

                # Extract facts and add edges with deduplication
                if self._graph_builder:
                    facts = self._graph_builder.extract_facts(content)
                    for fact in facts[:10]:  # Limit facts per document
                        # Generate deterministic fact_id
                        fact_content = f"{fact['source']} {fact['relation']} {fact['target']}"
                        fact_id = hashlib.sha256(fact_content.encode('utf-8')).hexdigest()[:32]

                        fact_node_id = self._knowledge_layer.add_knowledge(
                            content=fact_content,
                            node_type=NodeType.FACT,
                            metadata={'source_doc': normalized_url, 'source_doc_id': doc_id},
                            node_id=fact_id
                        )

                        # Check if this is a new fact node
                        if fact_node_id:
                            nodes_added += 1

                        # Create deterministic edge_id for deduplication (includes evidence_id)
                        edge_evidence_input = f"{doc_id}|MENTIONS|{fact_id}|{evidence_id}"
                        edge_hash = hashlib.sha256(edge_evidence_input.encode('utf-8')).hexdigest()[:32]

                        if edge_hash not in edge_hashes:
                            edge_hashes.add(edge_hash)

                            # Add edge with evidence_id in metadata for traceability
                            self._knowledge_layer.add_relation(
                                source_id=doc_id,
                                target_id=fact_id,
                                edge_type=EdgeType.MENTIONS,  # Standardized relation type
                                metadata={'evidence_id': evidence_id}
                            )
                            edges_added += 1
                            logger.debug(f"[EDGE DEDUP] New edge: {edge_hash[:16]}... evidence_id={evidence_id[:16]}...")

            logger.info(f"[GRAPH INGEST] docs_total={docs_total}, docs_new={docs_new}, "
                       f"docs_dedup={docs_dedup}, touched_existing={docs_dedup}, nodes_added={nodes_added}, edges_added={edges_added}")

        except Exception as e:
            logger.error(f"[GRAPH] Document ingestion failed: {e}")
            traceback.print_exc()

        return {
            'nodes_added': nodes_added,
            'edges_added': edges_added,
            'docs_total': docs_total,
            'docs_new': docs_new,
            'docs_dedup': docs_dedup
        }

    async def _graph_enrich_entities(
        self,
        texts: List[str],
        max_entities: int = 25,
        max_link_calls: int = 10
    ) -> Dict[str, Any]:
        """
        Extract entities from texts and link to knowledge graph.

        Deterministic entity ID generation using type:surface hash ensures
        entity deduplication. Supports canonical QID merging.

        Args:
            texts: List of texts to extract entities from
            max_entities: Maximum entities to process (M1 8GB constraint)
            max_link_calls: Maximum entity linking calls

        Returns:
            Dict with entities extracted, linked, merged counts
        """
        if not await self._ensure_knowledge_layer():
            return {'entities_extracted': 0, 'entities_linked': 0, 'entities_merged': 0}

        entities_extracted = 0
        entities_linked = 0
        entities_merged = 0

        # Track processed entity keys for deduplication
        processed_entities: Set[str] = set()

        try:
            from hledac.universal.knowledge.persistent_layer import NodeType, EdgeType

            # Collect all text
            all_text = ' '.join(texts)[:50000]  # Limit text for M1 8GB

            # Extract entities using entity linker
            if self._entity_linker:
                linked_entities = await self._entity_linker.link_entities(
                    text=all_text,
                    context=""
                )

                # Process top entities (budgeted)
                for entity in linked_entities[:max_entities]:
                    entities_extracted += 1

                    # Get entity type and label
                    entity_type = getattr(entity, 'entity_type', 'UNKNOWN')
                    entity_label = (entity.canonical_label if hasattr(entity, 'canonical_label') and entity.canonical_label
                                   else entity.entity_text)
                    wikidata_id = entity.wikidata_id if hasattr(entity, 'wikidata_id') else None

                    # Generate deterministic entity_id
                    normalized_surface = entity_label.lower().strip()
                    ent_key = f"{entity_type}:{normalized_surface}"
                    entity_id = hashlib.sha256(ent_key.encode('utf-8')).hexdigest()[:32]

                    # Check for duplicate in current batch
                    if ent_key in processed_entities:
                        logger.debug(f"[ENTITY LINK] Duplicate in batch: {ent_key}")
                        continue
                    processed_entities.add(ent_key)

                    # Check if entity already exists
                    existing_node = self._knowledge_layer._backend.get_node(entity_id)

                    if existing_node:
                        # Entity already exists - merge/ update metadata
                        existing_metadata = existing_node.metadata or {}
                        existing_wikidata = existing_metadata.get('wikidata_id')

                        # Update with Wikidata QID if available and not already set
                        if wikidata_id and not existing_wikidata:
                            updated_metadata = {
                                **existing_metadata,
                                'wikidata_id': wikidata_id,
                                'merged_at': time.time()
                            }
                            self._knowledge_layer.add_knowledge(
                                content=existing_node.content,
                                node_type=NodeType.ENTITY,
                                metadata=updated_metadata,
                                node_id=entity_id
                            )
                            logger.debug(f"[ENTITY LINK] Updated with QID: {entity_label} -> {wikidata_id}")

                        # If existing has QID and new has different QID, merge them
                        if existing_wikidata and wikidata_id and existing_wikidata != wikidata_id:
                            # Different QIDs for same entity - this is a conflict
                            logger.warning(f"[ENTITY LINK] QID conflict: {existing_wikidata} vs {wikidata_id}")

                        logger.debug(f"[ENTITY LINK] Entity exists: {entity_label}")
                        continue

                    # New entity - add to knowledge graph with deterministic ID
                    entity_node_id = self._knowledge_layer.add_knowledge(
                        content=entity_label,
                        node_type=NodeType.ENTITY,
                        metadata={
                            'original_text': entity.entity_text,
                            'entity_type': entity_type,
                            'wikidata_id': wikidata_id,
                            'description': entity.description if hasattr(entity, 'description') else '',
                            'extracted_at': time.time()
                        },
                        node_id=entity_id
                    )

                    # If canonical QID available, check for merge with other entities
                    if wikidata_id and entities_linked < max_link_calls:
                        canonical_id = f"wikidata:{wikidata_id}"

                        # Search for existing entities with same wikidata_id
                        for node in self._knowledge_layer._backend.iter_nodes():
                            if (node.node_type == NodeType.ENTITY and
                                node.metadata.get('wikidata_id') == wikidata_id and
                                node.id != entity_node_id):

                                # Merge: create canonical edge
                                self._knowledge_layer.add_relation(
                                    source_id=entity_node_id,
                                    target_id=node.id,
                                    edge_type=EdgeType.SIMILAR,
                                    metadata={'merge_reason': 'same_wikidata_id', 'canonical_id': canonical_id}
                                )
                                entities_merged += 1
                                logger.debug(f"[ENTITY LINK] Merged: {entity_label} -> {canonical_id}")
                                break

                        entities_linked += 1

                logger.info(f"[ENTITY LINK] extracted={entities_extracted}, "
                           f"linked={entities_linked}, merged={entities_merged}, "
                           f"unique={len(processed_entities)}")

        except Exception as e:
            logger.error(f"[GRAPH] Entity enrichment failed: {e}")
            traceback.print_exc()

        return {
            'entities_extracted': entities_extracted,
            'entities_linked': entities_linked,
            'entities_merged': entities_merged
        }

