    async def _fetch_favicon(self, url: str) -> Optional[bytes]:
        """Sprint 47: Fetch favicon bytes with timeout and size limit."""
        if not self.AIOHTTP_AVAILABLE:
            return None
        try:
            async with self._aiohttp.ClientSession() as session:
                async with session.get(url, timeout=self._aiohttp.ClientTimeout(total=5)) as resp:
                    if resp.status == 200:
                        content = await resp.read()
                        return content[:50000]  # max 50KB
        except Exception:
            return None
        return None

    async def _fetch_bundle(self, url: str) -> Optional[str]:
        """Sprint 47: Fetch JS bundle with timeout and size limit."""
        if not self.AIOHTTP_AVAILABLE:
            return None
        try:
            async with self._aiohttp.ClientSession() as session:
                async with session.get(url, timeout=self._aiohttp.ClientTimeout(total=10)) as resp:
                    if resp.status == 200:
                        content = await resp.text()
                        return content[:500000]  # max 500KB
        except Exception:
            return None
        return None

    def _guess_favicon_url(self, url: str) -> Optional[str]:
        """Sprint 47: Guess favicon URL from page URL."""
        from urllib.parse import urljoin
        return urljoin(url, "/favicon.ico")

