    def _should_escalate_to_tor(self, metadata: dict, domain_yield: float, url: str) -> bool:
        """
        Sprint 47: Decide whether to escalate to Tor for this domain, respecting per-URL limit.
        Sync method - only computes score and decides, no IO.
        """
        # Per-URL rate limit: max 3 Tor requests
        tor_count = self._tor_request_counts.get(url, 0)
        if tor_count >= 3:
            return False

        # Fingerprint score from available signals
        fingerprint_score = 0.0
        if metadata.get('ct_subdomains'):
            fingerprint_score += 0.3
        if metadata.get('favicon_hash'):
            fingerprint_score += 0.4
        if metadata.get('js_bundle_endpoints'):
            fingerprint_score += 0.3

        # Weighted score: (yield_score × 0.6) + (fingerprint_score × 0.4)
        score = (domain_yield * 0.6) + (min(fingerprint_score, 1.0) * 0.4)

        if score > 0.75:
            self._tor_request_counts[url] = tor_count + 1
            return True
        return False

