async def autonomous_research(
    query: str,
    depth: str = "deep",
    timeout: float = 600.0
) -> ComprehensiveResearchResult:
    """
    Convenience funkce pro rychlý autonomní výzkum.

    Args:
        query: Výzkumný dotaz
        depth: 'surface', 'deep', 'extreme', or 'exhaustive'
        timeout: Timeout v sekundách

    Returns:
        Kompletní výsledek výzkumu
    """
    depth_map = {
        'surface': DiscoveryDepth.SURFACE,
        'deep': DiscoveryDepth.DEEP,
        'extreme': DiscoveryDepth.EXTREME,
        'exhaustive': DiscoveryDepth.EXHAUSTIVE
    }

    depth_enum = depth_map.get(depth.lower(), DiscoveryDepth.DEEP)

    orchestrator = FullyAutonomousOrchestrator()

    try:
        await orchestrator.initialize()
        result = await orchestrator.research(query, depth_enum, timeout)
        return result
    finally:
        await orchestrator.cleanup()


async def deep_research(
    query: str,
    depth: str = "deep",
    timeout: float = 600.0
) -> ComprehensiveResearchResult:
    """
    Convenience function for deep autonomous research.

    Args:
        query: Research query
        depth: 'surface', 'deep', 'extreme', or 'exhaustive'
        timeout: Maximum execution time

    Returns:
        Comprehensive research result
    """
    depth_map = {
        'surface': DiscoveryDepth.SURFACE,
        'deep': DiscoveryDepth.DEEP,
        'extreme': DiscoveryDepth.EXTREME,
        'exhaustive': DiscoveryDepth.EXHAUSTIVE
    }

    depth_enum = depth_map.get(depth.lower(), DiscoveryDepth.DEEP)

    orchestrator = FullyAutonomousOrchestrator()

    try:
        await orchestrator.initialize()
        result = await orchestrator.research_autonomous(
            query=query,
            depth=depth_enum
        )
        return result
    finally:
        await orchestrator.cleanup()


